# Default retail profit margin (30 %)
DEFAULT_PROFIT_MARGIN = 30.0


def get_profit_margin() -> float:
    """Return the current retail profit margin (%) loaded from disk, fallback to default."""
    try:
        if os.path.exists(PROFIT_MARGIN_FILE):
            with open(PROFIT_MARGIN_FILE, 'r', encoding='utf-8') as f:
                data = json.load(f)
            val = float(data.get("margin_pct", DEFAULT_PROFIT_MARGIN))
            if 0 < val <= 500:
                return val
    except Exception as e:
        logger.error(f"get_profit_margin error: {e}")
    return DEFAULT_PROFIT_MARGIN


def set_profit_margin(margin_pct: float, set_by: str = "admin") -> bool:
    """Persist a new retail profit margin (%) to disk. Returns True on success."""
    tmp = PROFIT_MARGIN_FILE + ".tmp"
    try:
        data = {
            "margin_pct": round(float(margin_pct), 2),
            "set_by": str(set_by),
            "set_at": datetime.now(WAT).isoformat(),
        }
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)
        os.replace(tmp, PROFIT_MARGIN_FILE)
        return True
    except Exception as e:
        logger.error(f"set_profit_margin error: {e}")
        return False


# ── MARGIN RULE ENGINE ────────────────────────────────────────────────────────
class MarginRuleEngine:
    """
    Dynamic margin rule engine.

    Admins define rules like:
      • If USDNGN > 1700  → set margin to 40%
      • If COPPER > 5.0   → set margin to 35%
      • If USDNGN < 1400  → set margin to 25%

    Supported triggers (metric):
      USDNGN, GBPNGN, EURNGN, CNYNGN   — FX rates
      COPPER, STEEL, ALUMINUM, OIL_BRENT, OIL_WTI, GOLD, SILVER  — commodity prices

    Supported operators: gt (>), lt (<), gte (>=), lte (<=)

    Rules are evaluated every 5 min by BackgroundServices.
    The highest-priority triggered rule wins.
    If no rule fires, the base margin (last manually set) is used.

    Rule schema (stored in margin_rules.json):
    {
      "rules": [
        {
          "id": "r1",
          "metric": "USDNGN",
          "operator": "gt",
          "threshold": 1700,
          "margin_pct": 40.0,
          "priority": 1,
          "label": "NGN weak",
          "created_by": "7824293169",
          "created_at": "...",
          "active": true
        }, ...
      ],
      "auto_mode": true,         # false = rules defined but engine paused
      "last_evaluated": "...",
      "last_triggered_rule": null
    }
    """

    VALID_METRICS = {
        "USDNGN", "GBPNGN", "EURNGN", "CNYNGN",
        "COPPER", "STEEL", "ALUMINUM", "OIL_BRENT", "OIL_WTI",
        "GOLD", "SILVER", "NATURAL_GAS",
    }
    VALID_OPS = {"gt": ">", "lt": "<", "gte": ">=", "lte": "<="}
    _lock = threading.RLock()

    def _load(self) -> dict:
        try:
            if os.path.exists(MARGIN_RULES_FILE):
                with open(MARGIN_RULES_FILE, 'r', encoding='utf-8') as f:
                    return json.load(f)
        except Exception as e:
            logger.error(f"MarginRuleEngine load error: {e}")
        return {"rules": [], "auto_mode": True, "last_evaluated": None, "last_triggered_rule": None}

    def _save(self, data: dict):
        tmp = MARGIN_RULES_FILE + ".tmp"
        try:
            with open(tmp, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2, default=str)
            os.replace(tmp, MARGIN_RULES_FILE)
        except Exception as e:
            logger.error(f"MarginRuleEngine save error: {e}")

    def get_rules(self) -> list:
        return self._load().get("rules", [])

    def is_auto_mode(self) -> bool:
        return self._load().get("auto_mode", True)

    def set_auto_mode(self, enabled: bool):
        with self._lock:
            data = self._load()
            data["auto_mode"] = enabled
            self._save(data)

    def add_rule(self, metric: str, operator: str, threshold: float,
                 margin_pct: float, priority: int, label: str,
                 created_by: str) -> Tuple[bool, str]:
        metric   = metric.upper()
        operator = operator.lower()
        if metric not in self.VALID_METRICS:
            return False, f"Unknown metric `{metric}`.\nValid: {', '.join(sorted(self.VALID_METRICS))}"
        if operator not in self.VALID_OPS:
            return False, f"Unknown operator `{operator}`.\nValid: gt, lt, gte, lte"
        if not (1 <= margin_pct <= 500):
            return False, "❌ margin_pct must be between 1 and 500."
        if not (1 <= priority <= 100):
            return False, "❌ priority must be 1–100 (1 = highest)."
        with self._lock:
            data = self._load()
            rule_id = f"r{int(time.time())}"
            rule = {
                "id": rule_id,
                "metric": metric,
                "operator": operator,
                "threshold": round(float(threshold), 4),
                "margin_pct": round(float(margin_pct), 2),
                "priority": int(priority),
                "label": label[:60],
                "created_by": str(created_by),
                "created_at": datetime.now(WAT).isoformat(),
                "active": True,
            }
            data["rules"].append(rule)
            data["rules"].sort(key=lambda r: r["priority"])
            self._save(data)
        op_sym = self.VALID_OPS[operator]
        return True, (
            f"*Margin Rule Added*\n\n"
            f"ID: `{rule_id}`\n"
            f"Condition: `{metric} {op_sym} {threshold}`\n"
            f"→ Margin: *{margin_pct:.1f}%*\n"
            f"Priority: {priority} | Label: _{label}_\n\n"
            f"_Engine evaluates every 5 min. Use `/price listrules` to see all._"
        )

    def delete_rule(self, rule_id: str) -> Tuple[bool, str]:
        with self._lock:
            data = self._load()
            before = len(data["rules"])
            data["rules"] = [r for r in data["rules"] if r["id"] != rule_id]
            if len(data["rules"]) == before:
                return False, f"Rule `{rule_id}` not found."
            self._save(data)
        return True, f"Rule `{rule_id}` deleted."

    def clear_rules(self) -> str:
        with self._lock:
            data = self._load()
            n = len(data["rules"])
            data["rules"] = []
            data["last_triggered_rule"] = None
            self._save(data)
        return f"Cleared {n} rule(s). Engine will use base margin."

    def _fetch_live_value(self, metric: str) -> Optional[float]:
        """Fetch current value for a metric from market_engine."""
        try:
            if metric in ("USDNGN", "GBPNGN", "EURNGN", "CNYNGN"):
                base = metric[:3]
                result = market_engine.fetch_exchange_rate(base, "NGN")
                return result.get("rate") if result else None
            else:
                commodities = market_engine.fetch_commodity_prices()
                entry = commodities.get(metric, {})
                return entry.get("price") if entry else None
        except Exception as e:
            logger.error(f"MarginRuleEngine fetch {metric}: {e}")
            return None

    def _eval_op(self, value: float, operator: str, threshold: float) -> bool:
        return {
            "gt":  value >  threshold,
            "lt":  value <  threshold,
            "gte": value >= threshold,
            "lte": value <= threshold,
        }.get(operator, False)

    def evaluate(self) -> dict:
        """
        Evaluate all active rules against live market data.
        Returns a result dict:
          {
            "triggered": bool,
            "rule": rule_dict | None,
            "metric_value": float | None,
            "applied_margin": float,
            "base_margin": float,
            "snapshot": {metric: value, ...}
          }
        """
        data      = self._load()
        rules     = [r for r in data.get("rules", []) if r.get("active", True)]
        base      = get_profit_margin()
        snapshot  = {}

        # Pre-fetch unique metrics
        needed = set(r["metric"] for r in rules)
        for metric in needed:
            val = self._fetch_live_value(metric)
            if val is not None:
                snapshot[metric] = val

        # Evaluate in priority order (already sorted on add)
        for rule in sorted(rules, key=lambda r: r["priority"]):
            metric = rule["metric"]
            val    = snapshot.get(metric)
            if val is None:
                continue
            if self._eval_op(val, rule["operator"], rule["threshold"]):
                return {
                    "triggered":      True,
                    "rule":           rule,
                    "metric_value":   val,
                    "applied_margin": rule["margin_pct"],
                    "base_margin":    base,
                    "snapshot":       snapshot,
                }

        return {
            "triggered":      False,
            "rule":           None,
            "metric_value":   None,
            "applied_margin": base,
            "base_margin":    base,
            "snapshot":       snapshot,
        }

    def evaluate_and_apply(self) -> dict:
        """
        Evaluate rules, apply the winning margin, persist it, update last_evaluated.
        Returns the evaluate() result dict enriched with 'margin_changed'.
        """
        if not self.is_auto_mode():
            return {"triggered": False, "applied_margin": get_profit_margin(),
                    "base_margin": get_profit_margin(), "margin_changed": False,
                    "rule": None, "snapshot": {}}
        result = self.evaluate()
        old    = get_profit_margin()
        new    = result["applied_margin"]
        result["margin_changed"] = (round(new, 2) != round(old, 2))
        if result["margin_changed"]:
            set_profit_margin(new, set_by="rule_engine")
        # Update last_evaluated and last_triggered_rule
        with self._lock:
            data = self._load()
            data["last_evaluated"]     = datetime.now(WAT).isoformat()
            data["last_triggered_rule"] = result["rule"]["id"] if result["rule"] else None
            self._save(data)
        return result

    def format_rules_list(self, is_admin: bool = False) -> str:
        data  = self._load()
        rules = data.get("rules", [])
        mode  = "🟢 AUTO" if data.get("auto_mode", True) else "🔴 PAUSED"
        last  = data.get("last_evaluated", "never")[:16] if data.get("last_evaluated") else "never"
        last_rule = data.get("last_triggered_rule", "none")
        if not rules:
            msg = f"*📐 Margin Rule Engine — {mode}*\n\nNo rules defined.\n\n"
            if is_admin:
                msg += f"Add a rule:\n`/price addrule metric=USDNGN op=gt threshold=1700 margin=40 priority=1 label=NGN weak`\n\n"
            msg += f"_Last evaluated: {last}_"
            return msg
        lines = f"*📐 Margin Rule Engine — {mode}*\n_Last eval: {last} | Last fired: `{last_rule}`_\n\n"
        for r in sorted(rules, key=lambda x: x["priority"]):
            op_sym = self.VALID_OPS.get(r["operator"], r["operator"])
            status = "✅" if r.get("active", True) else "⏸"
            lines += (
                f"{status} `{r['id']}` P{r['priority']} · *{r['metric']} {op_sym} {r['threshold']}*"
                f" → *{r['margin_pct']:.1f}%*\n"
                f"   _{r.get('label','')}_\n\n"
            )
        lines += (
            "_Rules evaluated in priority order (1 = first). First triggered rule wins._\n"
            "_Use `/price delrule [id]` to remove · `/price autopause` to pause engine_"
        )
        return lines


# Global margin rule engine instance
margin_rule_engine = MarginRuleEngine()

# ── NIGERIA SHOP ──────────────────────────────────────────────────────────────
# Dedicated retail margin file so /shop margin is independent of /price margin.
SHOP_MARGIN_FILE = os.path.join(DATA_DIR, "shop_margin.json")
DEFAULT_SHOP_MARGIN = 20.0   # % added on top of Mercury base price

def get_shop_margin() -> float:
    """Return current /shop retail margin %, falling back to default."""
    try:
        if os.path.exists(SHOP_MARGIN_FILE):
            with open(SHOP_MARGIN_FILE, 'r', encoding='utf-8') as f:
                data = json.load(f)
            val = float(data.get("margin_pct", DEFAULT_SHOP_MARGIN))
            if 0 <= val <= 500:
                return val
    except Exception:
        pass
    return DEFAULT_SHOP_MARGIN

def set_shop_margin(margin_pct: float, set_by: str = "admin") -> bool:
    """Persist a new /shop retail margin % to disk. Returns True on success."""
    try:
        tmp = SHOP_MARGIN_FILE + ".tmp"
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump({"margin_pct": round(float(margin_pct), 2),
                       "set_by": set_by,
                       "set_at": datetime.now().isoformat()}, f)
        os.replace(tmp, SHOP_MARGIN_FILE)
        return True
    except Exception as e:
        logger.error(f"set_shop_margin error: {e}")
        return False

