# ── STOCK STATUS HELPERS ──────────────────────────────────────────────────────
# Admin sets stock via /shop setstockitem [SKU] [status]
# Statuses: in_stock | low_stock | out_of_stock | pre_order
STOCK_LABELS = {
    "in_stock":      ("", "In Stock"),
    "low_stock":     ("", "Low Stock"),
    "out_of_stock":  ("", "Out of Stock"),
    "pre_order":     ("", "Pre-Order"),
}

def _load_marketplace_ids() -> dict:
    try:
        if os.path.exists(MARKETPLACE_ID_FILE):
            with open(MARKETPLACE_ID_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception:
        pass
    return {}

def _save_marketplace_ids(data: dict):
    try:
        tmp = MARKETPLACE_ID_FILE + '.tmp'
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)
        os.replace(tmp, MARKETPLACE_ID_FILE)
    except Exception as e:
        logger.error(f'_save_marketplace_ids error: {e}')

def _get_or_create_marketplace_id(user_id: int, role: str = 'buyer') -> str:
    """Return a permanent iVolt public ID. Format: IVT-INS-XXXXXX / IVT-SAF-XXXXXX / IVT-BYR-XXXXXX / IVT-ADM-XXXXXX"""
    ids = _load_marketplace_ids()
    key = str(user_id)
    if key in ids:
        existing = ids[key]
        # Update role if needed (installer/safety take priority over buyer)
        priority = {'admin': 4, 'installer': 3, 'safety': 3, 'buyer': 1}
        if priority.get(role, 0) > priority.get(existing.get('role','buyer'), 0):
            prefix_map = {'installer': 'INS', 'safety': 'SAF', 'buyer': 'BYR', 'admin': 'ADM'}
            import hashlib
            prefix = prefix_map.get(role, 'BYR')
            suffix = hashlib.sha256(f"{user_id}-ivolt-{role}".encode()).hexdigest()[:6].upper()
            ids[key]['public_id'] = f"IVT-{prefix}-{suffix}"
            ids[key]['role'] = role
            _save_marketplace_ids(ids)
        return ids[key]['public_id']

    import hashlib
    prefix_map = {'installer': 'INS', 'safety': 'SAF', 'buyer': 'BYR', 'admin': 'ADM'}
    prefix = prefix_map.get(role, 'BYR')
    suffix = hashlib.sha256(f"{user_id}-ivolt-{role}".encode()).hexdigest()[:6].upper()
    public_id = f"IVT-{prefix}-{suffix}"
    ids[key] = {'user_id': user_id, 'public_id': public_id, 'role': role,
                'created_at': datetime.now(WAT).isoformat()}
    _save_marketplace_ids(ids)
    return public_id

def _resolve_public_id(public_id: str) -> dict:
    """Reverse lookup — find user record by public_id string."""
    ids = _load_marketplace_ids()
    for record in ids.values():
        if record.get('public_id') == public_id.upper():
            return record
    return {}

def _load_shop_stock() -> dict:
    """Load admin stock overrides {SKU: status_string}."""
    try:
        if os.path.exists(SHOP_STOCK_FILE):
            with open(SHOP_STOCK_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception:
        pass
    return {}

def _save_shop_stock(data: dict):
    try:
        tmp = SHOP_STOCK_FILE + '.tmp'
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)
        os.replace(tmp, SHOP_STOCK_FILE)
    except Exception as e:
        logger.error(f'_save_shop_stock error: {e}')

