# Works for both /shop (keyed by SKU) and /price (keyed by item name).
# Structure: { "SKU_OR_ITEM_NAME": { "photo_url": "...", "description": "...", "specs": "..." } }

def _load_item_meta() -> dict:
    try:
        if os.path.exists(ITEM_META_FILE):
            with open(ITEM_META_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception:
        pass
    return {}

def _save_item_meta(data: dict):
    try:
        tmp = ITEM_META_FILE + '.tmp'
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)
        os.replace(tmp, ITEM_META_FILE)
    except Exception as e:
        logger.error(f'_save_item_meta error: {e}')

def _apply_item_meta(key: str, item: dict) -> dict:
    """Return item dict with any admin meta overrides applied (non-destructive copy).
    Supports: photo_url, description, specs, weight_kg, name, stock_level, base_ngn

    Fix: uses explicit 'field in overrides' check instead of truthiness,
    so weight_kg=0, empty-string replacements, and all valid values are applied.
    """
    meta = _load_item_meta()
    if key not in meta:
        return item
    overrides = meta[key]
    result = dict(item)
    for field in ('photo_url', 'photo_url_bot4', 'description', 'specs', 'weight_kg', 'name', 'stock_level'):
        if field in overrides and overrides[field] is not None:
            result[field] = overrides[field]
    if 'base_ngn' in overrides and overrides['base_ngn'] is not None:
        result['base_ngn'] = overrides['base_ngn']
    return result

def get_item_stock(sku: str, catalogue_default: str = "in_stock") -> str:
    """Return effective stock status for a SKU (admin override > catalogue default)."""
    overrides = _load_shop_stock()
    return overrides.get(sku, catalogue_default)

def stock_badge(sku: str, catalogue_default: str = "in_stock") -> str:
    """Return a short display badge like '✅ In Stock' or '❌ Out of Stock'."""
    status = get_item_stock(sku, catalogue_default)
    icon, label = STOCK_LABELS.get(status, ("❓", status.replace('_', ' ').title()))
    return f"{icon} {label}"

def is_orderable(sku: str, catalogue_default: str = "in_stock") -> bool:
    """Returns False only for out_of_stock items (pre_order is still orderable)."""
    return get_item_stock(sku, catalogue_default) != "out_of_stock"

# ── BOT STATUS HELPERS ────────────────────────────────────────────────────────
# Admin sets bot status via /setstatus [online|away|offline] [optional message]
# Every command checks this and prepends a banner if away/offline.
BOT_STATUSES = {
    "online":  ("", "Online",  "Bot is fully operational."),
    "away":    ("", "Away",    "Slow responses — back soon."),
    "offline": ("", "Offline", "Bot is temporarily offline. Orders still accepted."),
}

def get_bot_status() -> dict:
    """Return {status, icon, label, message, set_at, set_by}."""
    try:
        if os.path.exists(BOT_STATUS_FILE):
            with open(BOT_STATUS_FILE, 'r', encoding='utf-8') as f:
                data = json.load(f)
            s = data.get('status', 'online')
            icon, label, default_msg = BOT_STATUSES.get(s, ("🟢", "Online", ""))
            return {
                'status':  s,
                'icon':    icon,
                'label':   label,
                'message': data.get('message') or default_msg,
                'set_at':  data.get('set_at', ''),
                'set_by':  data.get('set_by', 'system'),
            }
    except Exception:
        pass
    return {'status': 'online', 'icon': '🟢', 'label': 'Online',
            'message': '', 'set_at': '', 'set_by': 'system'}

def set_bot_status(status: str, message: str = '', set_by: str = 'admin') -> bool:
    if status not in BOT_STATUSES:
        return False
    try:
        tmp = BOT_STATUS_FILE + '.tmp'
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump({'status': status, 'message': message,
                       'set_at': datetime.now().isoformat(), 'set_by': set_by}, f)
        os.replace(tmp, BOT_STATUS_FILE)
        return True
    except Exception as e:
        logger.error(f'set_bot_status error: {e}')
        return False

def bot_status_banner() -> str:
    """Return a banner string to prepend to messages when not online, else ''."""
    bs = get_bot_status()
    if bs['status'] == 'online':
        return ''
    return (f"{bs['icon']} *Bot is {bs['label']}*\n"
            f"_{bs['message']}_\n\n")
# ── END STOCK / BOT-STATUS HELPERS ───────────────────────────────────────────

# ── NIGERIA LOGISTICS ZONES ───────────────────────────────────────────────────
# Delivery from Lagos (iVolt base). Fees are per-kg base rate + fixed handling.
# Zones defined by state proximity and road/transport infrastructure.
# Admin can override the per_kg_ngn rate via /shop setlogistics [zone] [rate].
# Formula: fee = max(min_fee, weight_kg * per_kg_ngn) + handling_ngn
#
# Zone tiers:
#   1 – Lagos + immediate environs          (same-day / next-day)
#   2 – South-West (Ogun, Oyo, Osun, etc.)  (1–2 days)
#   3 – South-South / South-East             (2–3 days)
#   4 – North-Central / FCT                  (2–3 days)
#   5 – North-East / North-West              (3–5 days)
