# ── LOGISTICS ENGINE CONSTANTS ────────────────────────────────────────────────
# Truck assumptions (12-tonne GVW rigid — common Lagos delivery truck):
_TRUCK_KM_PER_LITRE  = 4.5      # litres of diesel per km (laden)
_TRUCK_CAPACITY_KG   = 8_000    # usable cargo capacity (kg)
_LITRE_PER_BARREL    = 158.987  # barrels → litres conversion
_NIGERIA_DIESEL_MARKUP = 1.35   # Nigerian pump price premium over Brent-equivalent
                                  # (refining margin + distribution + subsidy gap)
_DRIVER_COST_PER_KM_NGN = 12.0  # driver wages + tolls + loading, fixed NGN/km
                                  # (admin can override via /shop setlogistics)
_FALLBACK_BRENT_USD  = 82.0     # USD/barrel if API unavailable
_FALLBACK_USDNGN     = 1_640.0  # NGN per USD if FX API unavailable

def _get_logistics_overrides() -> dict:
    """Load any admin overrides for logistics constants."""
    try:
        if os.path.exists(LOGISTICS_FILE):
            with open(LOGISTICS_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception:
        pass
    return {}

def _save_logistics_rates(zone_id: str, updates: Dict) -> bool:
    """Persist an admin override (zone handling/min_fee or engine constants)."""
    try:
        data = _get_logistics_overrides()
        data.setdefault(zone_id, {}).update(updates)
        tmp = LOGISTICS_FILE + ".tmp"
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)
        os.replace(tmp, LOGISTICS_FILE)
        return True
    except Exception as e:
        logger.error(f"_save_logistics_rates error: {e}")
        return False

def _get_logistics_rates() -> Dict[str, Dict]:
    """Return zone metadata merged with any admin overrides."""
    rates = {k: dict(v) for k, v in NIGERIA_LOGISTICS_ZONES.items()}
    overrides = _get_logistics_overrides()
    for zone_id, ov in overrides.items():
        if zone_id in rates:
            rates[zone_id].update(ov)
    return rates

def get_logistics_fee(state_or_city: str, weight_kg: float,
                      _commodities: dict = None, _fx_rate: float = None) -> Dict:
    """
    Calculate delivery fee to any Nigerian state — driven by live oil price,
    live USD/NGN FX rate, and exact road distance from Lagos.

    Formula:
      diesel_ngn_per_litre = (brent_usd / litres_per_barrel) * usd_ngn * markup
      fuel_cost_ngn        = distance_km * km_per_litre * diesel_ngn_per_litre
      labour_toll_ngn      = distance_km * driver_cost_per_km
      trip_cost_ngn        = fuel_cost_ngn + labour_toll_ngn
      per_kg_ngn           = trip_cost_ngn / truck_capacity_kg   (spread over cargo)
      raw_fee              = weight_kg * per_kg_ngn + handling_ngn
      fee_ngn              = max(min_fee, raw_fee)

    Returns None if location not recognised.
    """
    # ── Normalise location query ──────────────────────────────────────────────
    query = state_or_city.strip().lower()
    for suffix in (" state", " city", " lga", " town", " metropolis"):
        if query.endswith(suffix):
            query = query[: -len(suffix)].strip()

    # ── Match state route ─────────────────────────────────────────────────────
    matched_key  = None
    matched_route = None
    for key, route in NIGERIA_STATE_ROUTES.items():
        if query == key or query in key or key in query:
            matched_key   = key
            matched_route = route
            break

    if not matched_route:
        return None

    zone_id  = matched_route["zone"]
    distance = float(matched_route["distance_km"])
    rates    = _get_logistics_rates()
    zone     = rates.get(zone_id, NIGERIA_LOGISTICS_ZONES[zone_id])

    # ── Fetch live Brent oil price + USD/NGN ─────────────────────────────────
    brent_usd = _FALLBACK_BRENT_USD
    usd_ngn   = _fx_rate or _FALLBACK_USDNGN
    oil_source = "estimated"
    fx_source  = "estimated"

    try:
        if _commodities:
            brent_data = _commodities.get("OIL_BRENT") or _commodities.get("OIL_WTI")
            if brent_data and brent_data.get("price", 0) > 0:
                brent_usd  = float(brent_data["price"])
                oil_source = brent_data.get("data_quality", "live")
        else:
            # Lazy-import: market_engine may not be initialised at module level yet
            try:
                comms = market_engine.fetch_commodity_prices()
                bd    = comms.get("OIL_BRENT") or comms.get("OIL_WTI")
                if bd and bd.get("price", 0) > 0:
                    brent_usd  = float(bd["price"])
                    oil_source = bd.get("data_quality", "live")
            except Exception:
                pass

        if not _fx_rate:
            try:
                fx = market_engine.fetch_exchange_rate("USD", "NGN")
                if fx and fx.get("rate", 0) > 0:
                    usd_ngn   = float(fx["rate"])
                    fx_source = fx.get("source", "live")
            except Exception:
                pass
    except Exception as e:
        logger.warning(f"get_logistics_fee market fetch warning: {e}")

    # ── Admin engine-constant overrides ──────────────────────────────────────
    ov = _get_logistics_overrides()
    km_per_litre    = float(ov.get("_km_per_litre",    _TRUCK_KM_PER_LITRE))
    truck_cap_kg    = float(ov.get("_truck_capacity",   _TRUCK_CAPACITY_KG))
    diesel_markup   = float(ov.get("_diesel_markup",    _NIGERIA_DIESEL_MARKUP))
    driver_per_km   = float(ov.get("_driver_per_km",    _DRIVER_COST_PER_KM_NGN))

    # ── Compute dynamic per-km cost ───────────────────────────────────────────
    diesel_per_litre_ngn = (brent_usd / _LITRE_PER_BARREL) * usd_ngn * diesel_markup
    fuel_cost_ngn        = distance * (1.0 / km_per_litre) * diesel_per_litre_ngn
    labour_toll_ngn      = distance * driver_per_km
    trip_cost_ngn        = fuel_cost_ngn + labour_toll_ngn
    per_kg_ngn           = trip_cost_ngn / truck_cap_kg   # share per kg of cargo

    handling  = float(zone.get("handling_ngn", 3_000))
    min_fee   = float(zone.get("min_fee", 5_000))
    raw_fee   = weight_kg * per_kg_ngn + handling
    fee       = max(min_fee, raw_fee)

    return {
        "zone_id":              zone_id,
        "zone_label":           matched_route["label"],
        "fee_ngn":              round(fee),
        "per_kg_ngn":           round(per_kg_ngn, 2),
        "handling_ngn":         round(handling),
        "min_fee_ngn":          round(min_fee),
        "days":                 matched_route["days"],
        "matched_state":        matched_key,
        "weight_kg":            weight_kg,
        "distance_km":          distance,
        # Breakdown for transparency
        "brent_usd":            round(brent_usd, 2),
        "usd_ngn":              round(usd_ngn),
        "diesel_per_litre_ngn": round(diesel_per_litre_ngn, 2),
        "fuel_cost_ngn":        round(fuel_cost_ngn),
        "labour_toll_ngn":      round(labour_toll_ngn),
        "oil_source":           oil_source,
        "fx_source":            fx_source,
    }
# ── END NIGERIA LOGISTICS ─────────────────────────────────────────────────────

