# ── Regional Rates Persistence ────────────────────────────────────────────────
# REGIONAL_MULTIPLIERS is the compile-time default. At runtime, any admin edits
# are loaded from REGIONAL_RATES_FILE and merged in, so changes survive restarts.

def _load_regional_overrides() -> dict:
    """Load admin-edited regional rates from disk. Returns {} if none saved."""
    try:
        if os.path.exists(REGIONAL_RATES_FILE):
            with open(REGIONAL_RATES_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception as e:
        logger.error(f"regional rates load error: {e}")
    return {}

def _save_regional_overrides(data: dict):
    """Persist admin-edited regional rates atomically."""
    tmp = REGIONAL_RATES_FILE + ".tmp"
    try:
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, default=str)
        os.replace(tmp, REGIONAL_RATES_FILE)
    except Exception as e:
        logger.error(f"regional rates save error: {e}")

def get_regional_multipliers() -> dict:
    """Return REGIONAL_MULTIPLIERS merged with any admin overrides from disk."""
    import copy
    merged = copy.deepcopy(REGIONAL_MULTIPLIERS)
    overrides = _load_regional_overrides()
    for region, fields in overrides.items():
        if region in merged:
            merged[region].update(fields)
    return merged


