    def __init__(self, file_path: str = TRANSFORMER_OIL_FILE):
        self.file_path = file_path
        self._data = {}
        self._lock = threading.RLock()
        self._cache = {}
        self._last_update = 0
        self._ensure_file()
        self._load_data()

    def _ensure_file(self):
        """Ensure the oil database file exists"""
        if not os.path.exists(self.file_path):
            # Initialize with default data and timestamps
            initial_data = {}
            now = datetime.now(WAT).isoformat()
            for name, data in self.DEFAULT_OIL_DATA.items():
                initial_data[name] = {**data, "created_at": now, "updated_at": now}
            self._save_json(initial_data)
            logger.info(f"Created new transformer oil database at {self.file_path}")

    def _save_json(self, data: Dict):
        """Atomic JSON save with backup"""
        temp_file = f"{self.file_path}.tmp"
        try:
            with open(temp_file, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2, default=str)
            os.replace(temp_file, self.file_path)
        except Exception as e:
            logger.error(f"Error saving oil database: {e}")
            if os.path.exists(temp_file):
                os.remove(temp_file)

    def _load_json(self) -> Dict:
        """Load JSON with corruption handling"""
        try:
            if os.path.exists(self.file_path):
                with open(self.file_path, 'r', encoding='utf-8') as f:
                    return json.load(f)
        except json.JSONDecodeError as e:
            logger.error(f"Corrupted oil database JSON: {e}")
            backup = f"{self.file_path}.corrupted.{int(time.time())}"
            try:
                os.rename(self.file_path, backup)
            except:
                pass
        except Exception as e:
            logger.error(f"Error loading oil database: {e}")
        return {}

    def _load_data(self):
        """Load data from file with modification check"""
        try:
            mtime = os.path.getmtime(self.file_path)
            if mtime > self._last_update:
                self._data = self._load_json()
                self._last_update = mtime
                logger.debug("Oil database reloaded from disk")
        except Exception as e:
            logger.error(f"Error checking oil database: {e}")

    def _save_data(self):
        """Save data to file and update cache"""
        with self._lock:
            self._save_json(self._data)
            self._last_update = time.time()

    # ===== CRUD OPERATIONS =====

    def add_oil_type(self, name: str, data: Dict, created_by: str = "system") -> Tuple[bool, str]:
        """Add a new oil type to the database"""
        with self._lock:
            self._load_data()

            if name in self._data:
                return False, f"Oil type '{name}' already exists. Use update_oil_type() to modify."

            # Validate required fields
            required_fields = ["type", "base", "price_index", "fire_point", "flash_point", 
                             "pour_point", "biodegradable", "applications", "advantages", 
                             "disadvantages", "voltage_class", "environmental_rating", "price_per_liter_usd_base"]

            missing = [f for f in required_fields if f not in data]
            if missing:
                return False, f"Missing required fields: {', '.join(missing)}"

            now = datetime.now(WAT).isoformat()
            self._data[name] = {
                **data,
                "created_at": now,
                "updated_at": now,
                "created_by": created_by
            }
            self._save_data()
            logger.info(f"Added new oil type: {name} by {created_by}")
            return True, f"Oil type '{name}' added successfully"

    def update_oil_type(self, name: str, updates: Dict, updated_by: str = "system") -> Tuple[bool, str]:
        """Update an existing oil type"""
        with self._lock:
            self._load_data()

            if name not in self._data:
                return False, f"Oil type '{name}' not found"

            # Update fields while preserving original structure
            for key, value in updates.items():
                if key in ["created_at", "created_by"]:
                    continue  # Protect audit fields
                if key in self._data[name] or key in ["updated_at"]:
                    self._data[name][key] = value

            self._data[name]["updated_at"] = datetime.now(WAT).isoformat()
            self._save_data()
            logger.info(f"Updated oil type: {name} by {updated_by}")
            return True, f"Oil type '{name}' updated successfully"

    def delete_oil_type(self, name: str, deleted_by: str = "system") -> Tuple[bool, str]:
        """Delete an oil type from the database"""
        with self._lock:
            self._load_data()

            if name not in self._data:
                return False, f"Oil type '{name}' not found"

            # Create backup before deletion
            backup_data = self._data.pop(name)
            backup_data["deleted_at"] = datetime.now(WAT).isoformat()
            backup_data["deleted_by"] = deleted_by

            # Save to deletion log
            deletion_log_file = f"{self.file_path}.deletions.json"
            try:
                deletions = self._load_deletion_log(deletion_log_file)
                deletions[name] = backup_data
                with open(deletion_log_file, 'w', encoding='utf-8') as f:
                    json.dump(deletions, f, indent=2, default=str)
            except Exception as e:
                logger.warning(f"Could not save deletion log: {e}")

            self._save_data()
            logger.info(f"Deleted oil type: {name} by {deleted_by}")
            return True, f"Oil type '{name}' deleted successfully"

    def _load_deletion_log(self, path: str) -> Dict:
        """Load deletion log file"""
        try:
            if os.path.exists(path):
                with open(path, 'r', encoding='utf-8') as f:
                    return json.load(f)
        except:
            pass
        return {}

    def get_oil_type(self, name: str) -> Optional[Dict]:
        """Get a specific oil type by name"""
        self._load_data()
        return self._data.get(name)

    def get_all_oil_types(self) -> Dict[str, Dict]:
        """Get all oil types"""
        self._load_data()
        return self._data.copy()

    def search_oil_types(self, query: str = None, oil_type: str = None, 
                         biodegradable: bool = None, min_price_index: float = None,
                         max_price_index: float = None) -> Dict[str, Dict]:
        """Search oil types with filters"""
        self._load_data()
        results = {}

        for name, data in self._data.items():
            # Text search
            if query:
                query_lower = query.lower()
                searchable_text = f"{name} {data.get('type', '')} {data.get('base', '')} {' '.join(data.get('applications', []))}"
                if query_lower not in searchable_text.lower():
                    continue

            # Type filter
            if oil_type and data.get('type') != oil_type:
                continue

            # Biodegradable filter
            if biodegradable is not None and data.get('biodegradable') != biodegradable:
                continue

            # Price index filters
            price_idx = data.get('price_index', 0)
            if min_price_index is not None and price_idx < min_price_index:
                continue
            if max_price_index is not None and price_idx > max_price_index:
                continue

            results[name] = data

        return results

    def get_oil_types_by_category(self) -> Dict[str, List[str]]:
        """Get oil types grouped by category/type"""
        self._load_data()
        categories = defaultdict(list)
        for name, data in self._data.items():
            oil_type = data.get('type', 'Unknown')
            categories[oil_type].append(name)
        return dict(categories)

    def get_price_statistics(self) -> Dict:
        """Get price statistics across all oil types"""
        self._load_data()
        if not self._data:
            return {}

        price_indices = [d.get('price_index', 0) for d in self._data.values()]
        base_prices = [d.get('price_per_liter_usd_base', 0) for d in self._data.values()]

        return {
            "count": len(self._data),
            "price_index": {
                "min": min(price_indices),
                "max": max(price_indices),
                "average": sum(price_indices) / len(price_indices)
            },
            "base_price_usd": {
                "min": min(base_prices),
                "max": max(base_prices),
                "average": sum(base_prices) / len(base_prices)
            },
            "biodegradable_count": sum(1 for d in self._data.values() if d.get('biodegradable')),
            "non_biodegradable_count": sum(1 for d in self._data.values() if not d.get('biodegradable'))
        }

    # ===== REAL-TIME PRICE CALCULATIONS =====

    def calculate_oil_price(self, oil_name: str, liters: float = None, 
                           fx_rate: float = None, base_price: float = 2.50) -> Optional[Dict]:
        """Calculate real-time price for a specific oil type"""
        oil_data = self.get_oil_type(oil_name)
        if not oil_data:
            return None

        price_usd = base_price * oil_data['price_index']
        price_ngn = price_usd * (fx_rate or 1550)

        result = {
            'oil_name': oil_name,
            'price_per_liter_usd': round(price_usd, 2),
            'price_per_liter_ngn': round(price_ngn, 2),
            'price_index': oil_data['price_index'],
            'base_price_usd': base_price,
            'fx_rate': fx_rate,
            'properties': {
                'type': oil_data['type'],
                'base': oil_data['base'],
                'fire_point': oil_data['fire_point'],
                'flash_point': oil_data['flash_point'],
                'pour_point': oil_data['pour_point'],
                'biodegradable': oil_data['biodegradable'],
                'voltage_class': oil_data['voltage_class'],
                'environmental_rating': oil_data['environmental_rating']
            },
            'applications': oil_data.get('applications', []),
            'timestamp': datetime.now(WAT).isoformat()
        }

        if liters:
            result['liters'] = liters
            result['total_cost_ngn'] = round(price_ngn * liters, 2)
            result['total_cost_usd'] = round(price_usd * liters, 2)

        return result

    def calculate_all_oil_prices(self, liters: float = None, fx_rate: float = None, 
                                  base_price: float = 2.50) -> Dict[str, Dict]:
        """Calculate prices for all oil types"""
        self._load_data()
        results = {}
        for name in self._data:
            price_info = self.calculate_oil_price(name, liters, fx_rate, base_price)
            if price_info:
                results[name] = price_info
        return results

    def compare_oils(self, oil_names: List[str], liters: float = 1000, 
                     fx_rate: float = None) -> Dict:
        """Compare multiple oil types"""
        comparison = {
            "oils": {},
            "summary": {
                "cheapest": None,
                "most_expensive": None,
                "best_fire_safety": None,
                "most_eco_friendly": None
            },
            "timestamp": datetime.now(WAT).isoformat()
        }

        prices = []
        fire_points = []

        for name in oil_names:
            oil_data = self.get_oil_type(name)
            if not oil_data:
                continue

            price_info = self.calculate_oil_price(name, liters, fx_rate)
            comparison["oils"][name] = price_info
            prices.append((name, price_info['total_cost_ngn']))

            # Parse fire point for comparison
            fp_str = oil_data.get('fire_point', '0°C').replace('°C', '').replace('>', '').replace('<', '')
            try:
                fp_val = float(fp_str)
                fire_points.append((name, fp_val))
            except:
                pass

        if prices:
            prices.sort(key=lambda x: x[1])
            comparison["summary"]["cheapest"] = prices[0][0]
            comparison["summary"]["most_expensive"] = prices[-1][0]

        if fire_points:
            fire_points.sort(key=lambda x: x[1], reverse=True)
            comparison["summary"]["best_fire_safety"] = fire_points[0][0]

        # Most eco-friendly ( biodegradable + best rating)
        eco_scores = []
        for name in oil_names:
            oil_data = self.get_oil_type(name)
            if oil_data and oil_data.get('biodegradable'):
                rating = oil_data.get('environmental_rating', 'C')
                score = {'A+': 5, 'A': 4, 'B': 3, 'C': 2}.get(rating, 1)
                eco_scores.append((name, score))
        if eco_scores:
            eco_scores.sort(key=lambda x: x[1], reverse=True)
            comparison["summary"]["most_eco_friendly"] = eco_scores[0][0]

        return comparison

    def recommend_oil(self, application: str = None, fire_safety_priority: bool = False,
                      eco_priority: bool = False, budget_conscious: bool = False,
                      cold_climate: bool = False) -> Dict:
        """Get oil recommendations based on requirements"""
        self._load_data()
        scores = {}

        for name, data in self._data.items():
            score = 0
            reasons = []

            # Application match
            if application:
                apps = [a.lower() for a in data.get('applications', [])]
                if any(application.lower() in a for a in apps):
                    score += 10
                    reasons.append(f"Matches {application} application")

            # Fire safety priority
            if fire_safety_priority:
                fp_str = data.get('fire_point', '0°C').replace('°C', '').replace('>', '')
                try:
                    fp_val = float(fp_str)
                    if fp_val > 300:
                        score += 15
                        reasons.append("High fire point (K-class)")
                except:
                    pass

            # Eco priority
            if eco_priority:
                if data.get('biodegradable'):
                    score += 10
                    reasons.append("Biodegradable")
                rating = data.get('environmental_rating', 'C')
                if rating in ['A+', 'A']:
                    score += 5
                    reasons.append(f"Environmental rating {rating}")

            # Budget conscious
            if budget_conscious:
                if data.get('price_index', 1) <= 1.5:
                    score += 10
                    reasons.append("Cost-effective")

            # Cold climate
            if cold_climate:
                pp_str = data.get('pour_point', '0°C').replace('°C', '').replace('<', '')
                try:
                    pp_val = float(pp_str)
                    if pp_val < -30:
                        score += 10
                        reasons.append("Excellent low-temp performance")
                except:
                    pass

            if score > 0:
                scores[name] = {"score": score, "reasons": reasons, "data": data}

        # Sort by score
        sorted_scores = sorted(scores.items(), key=lambda x: x[1]["score"], reverse=True)

        return {
            "recommendations": sorted_scores[:3],
            "total_options": len(sorted_scores),
            "criteria": {
                "application": application,
                "fire_safety_priority": fire_safety_priority,
                "eco_priority": eco_priority,
                "budget_conscious": budget_conscious,
                "cold_climate": cold_climate
            }
        }

    # ── OIL PRICE OVERRIDES ──────────────────────────────────────────────────

    def get_all_overrides(self) -> dict:
        """Return all active admin oil price overrides."""
        try:
            if os.path.exists(OIL_OVERRIDES_FILE):
                with open(OIL_OVERRIDES_FILE, "r") as f:
                    return json.load(f)
        except Exception:
            pass
        return {}

    def set_oil_price_override(self, oil_name: str, price_usd: float,
                                set_by: str = "admin") -> Tuple[bool, str]:
        """Set an admin price override for an oil type. Returns (ok, message)."""
        if not self.get_oil_type(oil_name):
            all_names = ", ".join(list(self.get_all_oil_types().keys())[:5])
            return False, f"Oil type `{oil_name}` not found. Examples: {all_names}..."
        if price_usd <= 0:
            return False, "❌ Price must be greater than 0."
        overrides = self.get_all_overrides()
        overrides[oil_name] = {
            "override_usd": round(price_usd, 4),
            "set_by": set_by,
            "set_at": datetime.now(WAT).isoformat(),
        }
        try:
            with open(OIL_OVERRIDES_FILE, "w") as f:
                json.dump(overrides, f, indent=2)
            return True, f"*Price Override Set*\n\nOil: `{oil_name}`\nPrice: *${price_usd:.4f}/L*\nSet by: {set_by} at {datetime.now(WAT).strftime('%H:%M WAT')}"
        except Exception as e:
            logger.error(f"Failed to save oil override: {e}")
            return False, f"Failed to save override: {e}"

    def clear_oil_price_override(self, oil_name: str) -> Tuple[bool, str]:
        """Remove an admin price override for an oil type. Returns (ok, message)."""
        overrides = self.get_all_overrides()
        if oil_name not in overrides:
            return False, f"ℹ️ No override found for `{oil_name}`."
        del overrides[oil_name]
        try:
            with open(OIL_OVERRIDES_FILE, "w") as f:
                json.dump(overrides, f, indent=2)
            return True, f"Override cleared for `{oil_name}`. Restored live market pricing."
        except Exception as e:
            logger.error(f"Failed to clear oil override: {e}")
            return False, f"Failed to clear override: {e}"

    def export_to_json(self, output_path: str = None) -> str:
        """Export database to JSON file"""
        self._load_data()
        output_path = output_path or f"transformer_oil_export_{int(time.time())}.json"
        try:
            with open(output_path, 'w', encoding='utf-8') as f:
                json.dump(self._data, f, indent=2, default=str)
            return output_path
        except Exception as e:
            logger.error(f"Export failed: {e}")
            return None

    def import_from_json(self, input_path: str, merge: bool = False, 
                         imported_by: str = "system") -> Tuple[bool, str]:
        """Import oil types from JSON file"""
        try:
            with open(input_path, 'r', encoding='utf-8') as f:
                import_data = json.load(f)

            with self._lock:
                self._load_data()

                if not merge:
                    # Backup current data
                    backup_path = f"{self.file_path}.backup.{int(time.time())}"
                    self._save_json(self._data)
                    os.rename(self.file_path, backup_path)
                    self._data = {}

                added = 0
                updated = 0
                now = datetime.now(WAT).isoformat()

                for name, data in import_data.items():
                    if name in self._data:
                        # Update existing
                        for key, value in data.items():
                            if key not in ["created_at", "created_by"]:
                                self._data[name][key] = value
                        self._data[name]["updated_at"] = now
                        updated += 1
                    else:
                        # Add new
                        self._data[name] = {
                            **data,
                            "created_at": now,
                            "updated_at": now,
                            "created_by": f"import:{imported_by}"
                        }
                        added += 1

                self._save_data()
                logger.info(f"Import completed: {added} added, {updated} updated by {imported_by}")
                return True, f"Import successful: {added} added, {updated} updated"

        except Exception as e:
            logger.error(f"Import failed: {e}")
            return False, f"Import failed: {str(e)}"

    def reset_to_defaults(self, confirmed: bool = False) -> Tuple[bool, str]:
        """Reset database to default values"""
        if not confirmed:
            return False, "⚠️ Set confirmed=True to confirm reset"

        with self._lock:
            # Backup current data
            backup_path = f"{self.file_path}.backup.reset.{int(time.time())}"
            try:
                os.rename(self.file_path, backup_path)
            except:
                pass

            now = datetime.now(WAT).isoformat()
            self._data = {}
            for name, data in self.DEFAULT_OIL_DATA.items():
                self._data[name] = {**data, "created_at": now, "updated_at": now}

            self._save_data()
            logger.info("Oil database reset to defaults")
            return True, "✅ Database reset to default values"

