# --- 4. DATABASE MANAGER (Fixed) ---

class DatabaseManager:
    """Thread-safe database manager with caching"""

    def __init__(self):
        self._cache = {}
        self._lock = threading.Lock()
        self._ensure_files()

    def _ensure_files(self):
        """Ensure all database files exist"""
        files = [
            WARRANTY_FILE, USAGE_FILE, PREMIUM_FILE, CONFIG_FILE,
            PRICE_HISTORY_FILE, ALERTS_FILE, LAST_ID_FILE, STOCK_DATA_FILE,
            GLOBAL_MARKETS_FILE, RSS_CACHE_FILE, PROJECT_DB_FILE, 
            CYCLE_ANALYSIS_FILE, REALTIME_CACHE_FILE, ADMINS_FILE,
            USER_BANS_FILE, COMMAND_LOCKS_FILE, SCHEMATIC_CACHE_FILE
        ]
        for f in files:
            if not os.path.exists(f):
                self._save_json(f, {} if 'last_id' not in f else {'last_id': 0})

    def _save_json(self, filepath: str, data: Dict):
        """Atomic JSON save with backup"""
        temp_file = f"{filepath}.tmp"
        try:
            with open(temp_file, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2, default=str)
            os.replace(temp_file, filepath)
        except Exception as e:
            logger.error(f"Error saving {filepath}: {e}")
            if os.path.exists(temp_file):
                os.remove(temp_file)

    def _load_json(self, filepath: str) -> Dict:
        """Load JSON with corruption handling"""
        try:
            if os.path.exists(filepath):
                with open(filepath, 'r', encoding='utf-8') as f:
                    return json.load(f)
        except json.JSONDecodeError as e:
            logger.error(f"Corrupted JSON in {filepath}: {e}")
            backup = f"{filepath}.corrupted.{int(time.time())}"
            try:
                os.rename(filepath, backup)
            except:
                pass
        except Exception as e:
            logger.error(f"Error loading {filepath}: {e}")
        return {}

    def save(self, key: str, data: Dict):
        """Save data to file and update cache"""
        filepath = {
            'warranty': WARRANTY_FILE, 'usage': USAGE_FILE, 'premium': PREMIUM_FILE,
            'config': CONFIG_FILE, 'price_history': PRICE_HISTORY_FILE,
            'alerts': ALERTS_FILE, 'last_id': LAST_ID_FILE, 'stock_data': STOCK_DATA_FILE,
            'global_markets': GLOBAL_MARKETS_FILE, 'rss_cache': RSS_CACHE_FILE,
            'projects': PROJECT_DB_FILE, 'cycle_analysis': CYCLE_ANALYSIS_FILE,
            'realtime_cache': REALTIME_CACHE_FILE, 'admins': ADMINS_FILE,
            'user_bans': USER_BANS_FILE, 'command_locks': COMMAND_LOCKS_FILE,
            'schematic_cache': SCHEMATIC_CACHE_FILE,
            'all_users': ALL_USERS_FILE,
            'group_promo_state': GROUP_PROMO_FILE,
        }.get(key)

        if filepath:
            with self._lock:
                self._save_json(filepath, data)
                self._cache[key] = data

    def load(self, key: str) -> Dict:
        """Load data from cache or file"""
        if key in self._cache:
            return self._cache[key]

        filepath = {
            'warranty': WARRANTY_FILE, 'usage': USAGE_FILE, 'premium': PREMIUM_FILE,
            'config': CONFIG_FILE, 'price_history': PRICE_HISTORY_FILE,
            'alerts': ALERTS_FILE, 'last_id': LAST_ID_FILE, 'stock_data': STOCK_DATA_FILE,
            'global_markets': GLOBAL_MARKETS_FILE, 'rss_cache': RSS_CACHE_FILE,
            'projects': PROJECT_DB_FILE, 'cycle_analysis': CYCLE_ANALYSIS_FILE,
            'realtime_cache': REALTIME_CACHE_FILE, 'admins': ADMINS_FILE,
            'user_bans': USER_BANS_FILE, 'command_locks': COMMAND_LOCKS_FILE,
            'schematic_cache': SCHEMATIC_CACHE_FILE,
            'all_users': ALL_USERS_FILE,
            'group_promo_state': GROUP_PROMO_FILE,
        }.get(key)

        if filepath:
            data = self._load_json(filepath)
            self._cache[key] = data
            return data
        return {}

    def get_next_id(self) -> str:
        """Generate unique project ID"""
        data = self.load('last_id')
        last = data.get('last_id', 0)
        new_id = last + 1
        data['last_id'] = new_id
        self.save('last_id', data)
        return f"IVOLT-{datetime.now(WAT).year}-{new_id:05d}"

# Global database instance
db = DatabaseManager()

# --- FIREBASE REALTIME DATABASE MANAGER ---

class FirebaseManager:
    """
    Firebase Realtime Database manager.
    All bot data (premium users, warranty, usage, projects, alerts, plans)
    is stored in Firebase RTDB and synced locally as a fast-access cache.
    Firebase is the source of truth; local JSON files are fallback only.
    """

    BASE_URL: str = FIREBASE_URL.rstrip("/")
    SECRET:   str = FIREBASE_SECRET
    _cache:   Dict = {}
    _cache_ts: Dict = {}
    _CACHE_TTL: int = 30        # 30s local cache TTL for reads
    _lock = threading.RLock()

    # Firebase paths for each data type
    PATHS = {
        "premium":        "/premium_users",
        "warranty":       "/warranty",
        "usage":          "/user_usage",
        "alerts":         "/price_alerts",
        "projects":       "/projects",
        "premium_plans":  "/premium_plans",
        "config":         "/bot_config",
        "admins":         "/admins",
        "user_bans":      "/user_bans",
        "command_locks":  "/command_locks",
        "price_history":  "/price_history",
        "rss_cache":      "/rss_cache",
        "global_markets": "/global_markets",
        "stock_data":     "/stock_data",
        "last_id":        "/counters",
        "realtime_cache": "/realtime_cache",
        "cycle_analysis": "/cycle_analysis",
        "schematic_cache":"/schematic_cache",
        "api_keys":           "/api_keys",
        "enterprise_reports": "/enterprise_reports",
    }

    @classmethod
    def _url(cls, path: str) -> str:
        """Build Firebase REST URL. Handles root and sub-paths cleanly."""
        clean = path.rstrip("/") if path != "/" else ""
        return f"{cls.BASE_URL}{clean}.json?auth={cls.SECRET}"

    @classmethod
    def read(cls, path: str, default=None):
        """Read a value from Firebase RTDB. Returns default if missing or error."""
        # Check local cache first
        now = time.time()
        with cls._lock:
            if path in cls._cache and (now - cls._cache_ts.get(path, 0)) < cls._CACHE_TTL:
                return cls._cache[path]
        try:
            resp = requests.get(cls._url(path), timeout=8)
            if resp.status_code == 200:
                data = resp.json()
                with cls._lock:
                    cls._cache[path] = data
                    cls._cache_ts[path] = now
                return data if data is not None else default
            logger.warning(f"Firebase read {path} → HTTP {resp.status_code}")
        except Exception as e:
            logger.error(f"Firebase read error {path}: {e}")
        return default

    @classmethod
    def write(cls, path: str, data) -> bool:
        """Write (PUT) a value to Firebase RTDB. Returns True on success."""
        try:
            resp = requests.put(cls._url(path), json=data, timeout=10)
            if resp.status_code == 200:
                with cls._lock:
                    cls._cache[path] = data
                    cls._cache_ts[path] = time.time()
                return True
            logger.warning(f"Firebase write {path} → HTTP {resp.status_code}: {resp.text[:100]}")
        except Exception as e:
            logger.error(f"Firebase write error {path}: {e}")
        return False

    @classmethod
    def patch(cls, path: str, data: Dict) -> bool:
        """Patch (PATCH/merge) a value in Firebase RTDB. Returns True on success."""
        try:
            resp = requests.patch(cls._url(path), json=data, timeout=10)
            if resp.status_code == 200:
                with cls._lock:
                    existing = cls._cache.get(path, {}) or {}
                    if isinstance(existing, dict):
                        existing.update(data)
                    else:
                        existing = data
                    cls._cache[path] = existing
                    cls._cache_ts[path] = time.time()
                return True
            logger.warning(f"Firebase patch {path} → HTTP {resp.status_code}")
        except Exception as e:
            logger.error(f"Firebase patch error {path}: {e}")
        return False

    @classmethod
    def delete(cls, path: str) -> bool:
        """Delete a node from Firebase RTDB."""
        try:
            resp = requests.delete(cls._url(path), timeout=8)
            if resp.status_code == 200:
                with cls._lock:
                    cls._cache.pop(path, None)
                    cls._cache_ts.pop(path, None)
                return True
        except Exception as e:
            logger.error(f"Firebase delete error {path}: {e}")
        return False

    @classmethod
    def invalidate(cls, path: str):
        """Invalidate local cache for a path so next read hits Firebase."""
        with cls._lock:
            cls._cache.pop(path, None)
            cls._cache_ts.pop(path, None)

    # ── PREMIUM PLANS (source of truth in Firebase) ────────────────────────

    @classmethod
    def get_premium_plans(cls) -> Dict:
        """
        Fetch premium plans from Firebase.
        Falls back to local JSON cache, then PREMIUM_PLANS_DEFAULT.
        Always returns a valid dict — never crashes.
        """
        plans = cls.read(cls.PATHS["premium_plans"])
        if plans and isinstance(plans, dict) and len(plans) >= 1:
            return plans

        # Try local file fallback
        try:
            local_path = os.path.join(DATA_DIR, "premium_plans.json")
            if os.path.exists(local_path):
                with open(local_path, "r", encoding="utf-8") as f:
                    local = json.load(f)
                if local and isinstance(local, dict):
                    return local
        except Exception:
            pass

        # Seed Firebase with defaults on first run
        logger.info("Seeding Firebase premium_plans with defaults")
        cls.write(cls.PATHS["premium_plans"], PREMIUM_PLANS_DEFAULT)
        return dict(PREMIUM_PLANS_DEFAULT)

    @classmethod
    def set_plan(cls, plan_id: str, plan_data: Dict, set_by: str = "admin") -> bool:
        """Create or fully update a plan in Firebase."""
        plan_data["updated_at"] = datetime.now(WAT).isoformat()
        plan_data["updated_by"] = set_by
        ok = cls.patch(cls.PATHS["premium_plans"], {plan_id: plan_data})
        if ok:
            # Also persist locally
            try:
                local_path = os.path.join(DATA_DIR, "premium_plans.json")
                all_plans  = cls.get_premium_plans()
                all_plans[plan_id] = plan_data
                with open(local_path, "w", encoding="utf-8") as f:
                    json.dump(all_plans, f, indent=2, default=str)
            except Exception as e:
                logger.error(f"Local premium_plans save error: {e}")
        return ok

    @classmethod
    def delete_plan(cls, plan_id: str) -> bool:
        """Remove a plan from Firebase."""
        return cls.delete(f"{cls.PATHS['premium_plans']}/{plan_id}")

    # ── GENERIC DB BRIDGE (replaces local JSON for all data types) ─────────

    @classmethod
    def db_load(cls, key: str) -> Dict:
        """Load a data collection from Firebase, fall back to local file."""
        path = cls.PATHS.get(key)
        if path:
            data = cls.read(path)
            if data and isinstance(data, dict):
                return data
        # Fallback to local db
        return db.load(key)

    @classmethod
    def db_save(cls, key: str, data: Dict) -> bool:
        """Save data to both Firebase and local JSON."""
        # Always save locally first (fast, reliable)
        db.save(key, data)
        # Then sync to Firebase asynchronously
        path = cls.PATHS.get(key)
        if path:
            try:
                threading.Thread(
                    target=cls.write, args=(path, data), daemon=True
                ).start()
                return True
            except Exception as e:
                logger.error(f"Firebase async save error ({key}): {e}")
        return False

    @classmethod
    def health_check(cls) -> Dict:
        """
        Check Firebase RTDB connectivity via lightweight REST ping.
        Uses shallow=true on root — lightest call that confirms auth + connectivity.
        The .info/connected endpoint does NOT work reliably with REST + secret auth.
        """
        try:
            start = time.time()
            url   = f"{cls.BASE_URL}/.json?auth={cls.SECRET}&shallow=true&limitToFirst=1"
            resp  = requests.get(url, timeout=6)
            ms    = round((time.time() - start) * 1000, 1)

            if resp.status_code == 200:
                return {
                    "status":     "online",
                    "latency_ms": ms,
                    "http":       200,
                    "db":         cls.BASE_URL.split("//")[-1].split(".")[0],
                }
            elif resp.status_code == 401:
                return {"status": "auth_error",        "http": 401, "latency_ms": ms,
                        "error": "Invalid secret — check FIREBASE_SECRET"}
            elif resp.status_code == 403:
                return {"status": "permission_denied", "http": 403, "latency_ms": ms,
                        "error": "Rules blocked access — open Firebase security rules"}
            elif resp.status_code == 404:
                return {"status": "not_found",         "http": 404, "latency_ms": ms,
                        "error": "Database URL wrong — check FIREBASE_URL"}
            else:
                return {"status": "error", "http": resp.status_code,
                        "latency_ms": ms, "body": resp.text[:120]}

        except requests.exceptions.ConnectionError:
            return {"status": "offline",  "error": "Cannot reach Firebase — check internet"}
        except requests.exceptions.Timeout:
            return {"status": "timeout",  "error": "Firebase did not respond within 6s"}
        except Exception as e:
            return {"status": "offline",  "error": str(e)[:100]}

def _safe_rate(pair_result, fallbacks=None):
    """Safely extract rate from fetch_exchange_rate result — never raises."""
    if fallbacks is None:
        fallbacks = {"USD_NGN": 1640, "GBP_NGN": 2050, "EUR_NGN": 1750, "CNY_NGN": 225, "JPY_NGN": 10.5}
    if pair_result and isinstance(pair_result, dict) and pair_result.get('rate'):
        return float(pair_result['rate'])
    return 1640.0  # last-resort fallback

def get_premium_plans() -> Dict:
    """Always returns the current live premium plans from Firebase."""
    return FirebaseManager.get_premium_plans()

# --- 5. DYNAMIC ADMIN MANAGER (Fixed) ---

class DynamicAdminManager:
    """Hierarchical admin management system with audit logging"""

    PERMISSIONS = {
        "super_admin": ["broadcast", "manage_admins", "view_logs", "system_config", 
                       "user_management", "price_override", "maintenance_mode", 
                       "database_access", "ban_users", "view_stats", "lock_commands"],
        "admin": ["broadcast", "user_management", "view_logs", "price_override", "ban_users", "lock_commands"],
        "moderator": ["broadcast", "user_management", "view_stats"],
        "support": ["user_management", "view_logs"]
    }

    def __init__(self):
        self._lock = threading.RLock()
        self._admins_cache = {}
        self._last_load = 0
        self._ensure_admin_file()
        self._load_admins()

    def _ensure_admin_file(self):
        """Initialize admin file with default super admin"""
        if not os.path.exists(ADMINS_FILE):
            default = {
                str(ADMIN_ID): {
                    "role": "super_admin",
                    "added_by": "system",
                    "added_at": datetime.now(WAT).isoformat(),
                    "last_active": datetime.now(WAT).isoformat(),
                    "permissions": self.PERMISSIONS["super_admin"],
                    "name": "Primary Admin",
                    "is_active": True
                }
            }
            db._save_json(ADMINS_FILE, default)

    def _load_admins(self):
        """Load admins from file with modification check"""
        try:
            mtime = os.path.getmtime(ADMINS_FILE)
            if mtime > self._last_load:
                self._admins_cache = db._load_json(ADMINS_FILE)
                self._last_load = mtime
        except Exception as e:
            logger.error(f"Error loading admins: {e}")

    def _save_admins(self, data: Dict = None):
        """Save admins to file and update cache"""
        data = data or self._admins_cache
        db._save_json(ADMINS_FILE, data)
        self._admins_cache = data
        self._last_load = time.time()

    def _log_action(self, admin_id: int, action: str, target: str = None, details: str = None):
        """Log admin action to audit file"""
        log_entry = {
            "timestamp": datetime.now(WAT).isoformat(),
            "admin_id": admin_id,
            "action": action,
            "target": target,
            "details": details
        }
        try:
            with open(AUDIT_FILE, 'a', encoding='utf-8') as f:
                f.write(json.dumps(log_entry, default=str) + "\n")
        except Exception as e:
            logger.error(f"Audit log error: {e}")

    def is_admin(self, user_id: int) -> bool:
        """Check if user is active admin"""
        self._load_admins()
        user_key = str(user_id)
        return (user_key in self._admins_cache and 
                self._admins_cache[user_key].get("is_active", True))

    def has_permission(self, user_id: int, permission: str) -> bool:
        """Check if admin has specific permission"""
        self._load_admins()
        user_key = str(user_id)
        if user_key not in self._admins_cache:
            return False
        admin_data = self._admins_cache[user_key]
        if not admin_data.get("is_active", True):
            return False
        perms = admin_data.get("permissions", [])
        return permission in perms or "super_admin" in perms

    def get_admin_role(self, user_id: int) -> Optional[str]:
        """Get admin role for user"""
        self._load_admins()
        user_key = str(user_id)
        if user_key in self._admins_cache:
            return self._admins_cache[user_key].get("role")
        return None

    def add_admin(self, admin_id: int, new_admin_id: int, role: str = "admin", 
                  name: str = None) -> Tuple[bool, str]:
        """Add new admin with hierarchy check"""
        if not self.has_permission(admin_id, "manage_admins"):
            return False, "⛔ Permission denied."

        if role not in self.PERMISSIONS:
            return False, f"Invalid role. Valid: {', '.join(self.PERMISSIONS.keys())}"

        if role == "super_admin" and self.get_admin_role(admin_id) != "super_admin":
            return False, "⛔ Only super admins can create other super admins."

        user_key = str(new_admin_id)

        with self._lock:
            self._load_admins()
            if user_key in self._admins_cache and self._admins_cache[user_key].get("is_active", True):
                return False, "User is already an admin."

            self._admins_cache[user_key] = {
                "role": role,
                "added_by": admin_id,
                "added_at": datetime.now(WAT).isoformat(),
                "last_active": datetime.now(WAT).isoformat(),
                "permissions": self.PERMISSIONS[role].copy(),
                "name": name or f"Admin_{new_admin_id}",
                "is_active": True
            }
            self._save_admins()
            self._log_action(admin_id, "add_admin", str(new_admin_id), f"role={role}")

        return True, f"Added {name or new_admin_id} as {role}"

    def remove_admin(self, admin_id: int, target_admin_id: int) -> Tuple[bool, str]:
        """Remove admin with hierarchy check"""
        if not self.has_permission(admin_id, "manage_admins"):
            return False, "⛔ Permission denied."

        if admin_id == target_admin_id:
            return False, "⛔ Cannot remove yourself."

        target_key = str(target_admin_id)
        admin_key = str(admin_id)

        with self._lock:
            self._load_admins()
            if target_key not in self._admins_cache:
                return False, "User is not an admin."

            target_role = self._admins_cache[target_key].get("role")
            admin_role = self._admins_cache[admin_key].get("role")

            hierarchy = {"super_admin": 3, "admin": 2, "moderator": 1, "support": 0}
            if hierarchy.get(target_role, 0) >= hierarchy.get(admin_role, 0) and admin_role != "super_admin":
                return False, f"⛔ Cannot remove {target_role} as {admin_role}."

            self._admins_cache[target_key]["is_active"] = False
            self._admins_cache[target_key]["removed_by"] = admin_id
            self._admins_cache[target_key]["removed_at"] = datetime.now(WAT).isoformat()
            self._save_admins()
            self._log_action(admin_id, "remove_admin", str(target_admin_id))

        return True, f"Removed admin {target_admin_id}"

    def list_admins(self, requester_id: int) -> Tuple[bool, str]:
        """List all admins"""
        if not self.is_admin(requester_id):
            return False, "⛔ Admin access required."

        self._load_admins()
        response = "*👥 Admin Team*\n\n"
        active_admins = []
        inactive_admins = []

        for user_id, data in self._admins_cache.items():
            if data.get("is_active", True):
                active_admins.append((user_id, data))
            else:
                inactive_admins.append((user_id, data))

        if active_admins:
            response += "*Active Admins:*\n"
            for user_id, data in active_admins:
                role_emoji = {"super_admin": "👑", "admin": "⭐", "moderator": "🔧", "support": "💬"}.get(data["role"], "👤")
                last_active = data.get("last_active", "Unknown")[:10]
                response += f"{role_emoji} `{user_id}` - {data.get('name', 'Unknown')} ({data['role']})\n"
                response += f"   Last active: {last_active}\n\n"

        if inactive_admins and self.has_permission(requester_id, "manage_admins"):
            response += "*Inactive Admins:*\n"
            for user_id, data in inactive_admins:
                response += f"⚪ `{user_id}` - {data.get('name', 'Unknown')} (removed)\n"

        return True, response

    def update_activity(self, user_id: int):
        """Update last activity timestamp"""
        user_key = str(user_id)
        if user_key in self._admins_cache:
            self._admins_cache[user_key]["last_active"] = datetime.now(WAT).isoformat()
            if random.random() < 0.1:  # 10% chance to save
                self._save_admins()

    def get_audit_log(self, requester_id: int, limit: int = 50) -> Tuple[bool, str]:
        """Get recent audit log entries"""
        if not self.has_permission(requester_id, "view_logs"):
            return False, "⛔ Permission denied."

        try:
            if not os.path.exists(AUDIT_FILE):
                return True, "No audit logs yet."

            with open(AUDIT_FILE, 'r', encoding='utf-8') as f:
                lines = f.readlines()

            recent_logs = lines[-limit:] if len(lines) > limit else lines
            response = "*📋 Recent Admin Activity*\n\n"

            for line in recent_logs:
                try:
                    log = json.loads(line.strip())
                    response += f"`{log['timestamp'][:16]}`\n"
                    response += f"👤 `{log['admin_id']}` → {log['action']}\n"
                    if log.get('target'):
                        response += f"   Target: `{log['target']}`\n"
                    response += "\n"
                except:
                    continue

            return True, response

        except Exception as e:
            return False, f"Error reading logs: {e}"

# Global admin manager instance
admin_manager = DynamicAdminManager()

# --- 6. USER MANAGER (Fixed) ---

class UserManager:
    """User management with banning and statistics"""

    def __init__(self):
        self._lock = threading.Lock()

    def is_banned(self, user_id: int) -> Tuple[bool, Optional[str]]:
        """Check if user is banned"""
        bans = db.load('user_bans')
        user_key = str(user_id)
        if user_key in bans and bans[user_key].get('active', False):
            # Check if ban has expired
            if 'expires_at' in bans[user_key]:
                try:
                    exp = datetime.fromisoformat(bans[user_key]['expires_at'])
                    if datetime.now(WAT) > exp:
                        bans[user_key]['active'] = False
                        db.save('user_bans', bans)
                        return False, None
                except:
                    pass
            return True, bans[user_key].get('reason', 'No reason provided')
        return False, None

    def ban_user(self, admin_id: int, user_id: int, reason: str = None, 
                 duration_days: int = None) -> Tuple[bool, str]:
        """Ban a user with optional duration"""
        if not admin_manager.has_permission(admin_id, "ban_users"):
            return False, "⛔ Permission denied."

        user_key = str(user_id)
        bans = db.load('user_bans')

        with self._lock:
            bans[user_key] = {
                'banned_by': admin_id,
                'banned_at': datetime.now(WAT).isoformat(),
                'reason': reason or 'Violation of terms',
                'duration_days': duration_days,
                'active': True
            }
            if duration_days:
                bans[user_key]['expires_at'] = (datetime.now(WAT) + 
                    timedelta(days=duration_days)).isoformat()
            db.save('user_bans', bans)
            admin_manager._log_action(admin_id, "ban_user", str(user_id), reason)

        duration_text = f"for {duration_days} days" if duration_days else "permanently"
        return True, f"User {user_id} banned ({duration_text}). Reason: {reason}"

    def unban_user(self, admin_id: int, user_id: int) -> Tuple[bool, str]:
        """Unban a user"""
        if not admin_manager.has_permission(admin_id, "ban_users"):
            return False, "⛔ Permission denied."

        user_key = str(user_id)
        bans = db.load('user_bans')

        with self._lock:
            if user_key not in bans:
                return False, "User is not banned."
            bans[user_key]['active'] = False
            bans[user_key]['unbanned_by'] = admin_id
            bans[user_key]['unbanned_at'] = datetime.now(WAT).isoformat()
            db.save('user_bans', bans)
            admin_manager._log_action(admin_id, "unban_user", str(user_id))

        return True, f"User {user_id} unbanned."

    def get_user_stats(self, admin_id: int, user_id: int = None) -> Tuple[bool, str]:
        """Get user statistics"""
        if not admin_manager.has_permission(admin_id, "view_stats"):
            return False, "⛔ Permission denied."

        usage = db.load('usage')
        premium = db.load('premium')
        bans = db.load('user_bans')

        if user_id:
            # Single user stats
            user_key = str(user_id)
            p_data = premium.get(user_key, {})
            is_premium = False
            if isinstance(p_data, dict):
                exp_str = p_data.get('expiry')
                if exp_str:
                    try:
                        exp_date = datetime.strptime(exp_str, '%Y-%m-%d')
                        if datetime.now(WAT) <= WAT.localize(exp_date):
                            is_premium = True
                    except:
                        pass

            user_usage = {k: v for k, v in usage.items() if k.startswith(f"{user_id}_")}
            total_queries = sum(user_usage.values())
            is_banned, ban_reason = self.is_banned(user_id)

            response = f"""
*👤 User Statistics*
ID: `{user_id}`
Status: {'⭐ Premium' if is_premium else '🔹 Free'}
Banned: {'🚫 Yes - ' + ban_reason if is_banned else '✅ No'}
Total Queries: {total_queries}
            """
            return True, response
        else:
            # Global stats
            today = datetime.now(WAT).strftime("%Y-%m-%d")
            today_usage = sum(v for k, v in usage.items() if k.endswith(f"_{today}"))
            unique_users_today = len(set(k.split('_')[0] for k in usage.keys() if k.endswith(f"_{today}")))
            active_bans = sum(1 for b in bans.values() if b.get('active', False))
            total_premium = len(premium)

            response = f"""
*📊 Global Statistics*
Today: {unique_users_today} users, {today_usage} queries
Premium: {total_premium} users
Active Bans: {active_bans}
            """
            return True, response

    def list_banned_users(self, admin_id: int) -> Tuple[bool, str]:
        """List all banned users"""
        if not admin_manager.has_permission(admin_id, "ban_users"):
            return False, "⛔ Permission denied."

        bans = db.load('user_bans')
        active_bans = {k: v for k, v in bans.items() if v.get('active', False)}

        if not active_bans:
            return True, "No active bans."

        response = "*🚫 Banned Users*\n\n"
        for user_id, data in active_bans.items():
            expires = data.get('expires_at', 'Never')[:10] if data.get('expires_at') else 'Never'
            response += f"👤 `{user_id}` - {data.get('reason', 'N/A')}\n   Expires: {expires}\n\n"

        return True, response

# Global user manager instance
user_manager = UserManager()

# --- ENTERPRISE API KEY MANAGER ---

class EnterpriseAPIManager:
    """
    Manages API keys for Enterprise subscribers.
    Keys grant direct HTTP access to iVolt's Firebase price database.

    Firebase path: /api_keys/{user_id}/
      {
        "key":         "ivolt_xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx",
        "created_at":  "2026-03-23T09:00:00+01:00",
        "label":       "My App",
        "active":      true,
        "daily_limit": 500,
        "calls_today": 0,
        "last_reset":  "2026-03-23",
        "total_calls": 0,
        "issued_by":   admin_id
      }
    """

    API_KEY_PREFIX = "ivolt_"
    FIREBASE_PATH  = "/api_keys"
    DAILY_LIMIT    = 500   # requests per day per enterprise key

    @staticmethod
    def _generate_key() -> str:
        """Generate a cryptographically secure API key."""
        raw = hashlib.sha256(
            f"{time.time()}{random.getrandbits(128)}".encode()
        ).hexdigest()
        return f"ivolt_{raw[:32]}"

    @classmethod
    def _load_keys(cls) -> Dict:
        data = FirebaseManager.read(cls.FIREBASE_PATH, default={})
        return data if isinstance(data, dict) else {}

    @classmethod
    def _save_key(cls, user_id: int, key_data: Dict) -> bool:
        return FirebaseManager.write(
            f"{cls.FIREBASE_PATH}/{user_id}", key_data
        )

    @classmethod
    def is_enterprise(cls, user_id: int) -> bool:
        """Check whether a user has an active Enterprise premium plan."""
        premium = FirebaseManager.db_load('premium')
        entry = premium.get(str(user_id), {})
        if not isinstance(entry, dict):
            return False
        plan = entry.get('plan', '').lower()
        expiry = entry.get('expiry', '')
        try:
            exp_date = WAT.localize(datetime.strptime(expiry, "%Y-%m-%d"))
            return plan == 'enterprise' and datetime.now(WAT) <= exp_date
        except Exception:
            return False

    @classmethod
    def generate_key(cls, admin_id: int, user_id: int, label: str = "Default") -> Tuple[bool, str]:
        """Admin issues an API key to an enterprise user."""
        if not admin_manager.has_permission(admin_id, "activate_premium"):
            return False, "⛔ Permission denied."

        keys = cls._load_keys()
        user_key = str(user_id)

        if user_key in keys and keys[user_key].get('active'):
            existing = keys[user_key]['key']
            return False, (
                f"User `{user_id}` already has an active API key.\n\n"
                f"`{existing}`\n\n"
                f"Use `/api revoke {user_id}` to revoke it first."
            )

        new_key = cls._generate_key()
        key_data = {
            "key":         new_key,
            "user_id":     user_id,
            "label":       label,
            "created_at":  datetime.now(WAT).isoformat(),
            "active":      True,
            "daily_limit": cls.DAILY_LIMIT,
            "calls_today": 0,
            "last_reset":  datetime.now(WAT).strftime("%Y-%m-%d"),
            "total_calls": 0,
            "issued_by":   admin_id
        }

        if cls._save_key(user_id, key_data):
            admin_manager._log_action(admin_id, "api_key_issued", str(user_id), label)
            return True, (
                f"*API Key Issued*\n\n"
                f"👤 User: `{user_id}`\n"
                f"Label: {label}\n\n"
                f"🔑 *Key:*\n`{new_key}`\n\n"
                f"Daily limit: {cls.DAILY_LIMIT:,} requests\n\n"
                f"📖 *Usage:*\n"
                f"`GET {FIREBASE_URL}/shop_catalogue_flat.json?auth={new_key}`\n\n"
                f"_Share this key securely with the user._"
            )
        return False, "❌ Failed to save API key. Check Firebase connection."

    @classmethod
    def revoke_key(cls, admin_id: int, user_id: int) -> Tuple[bool, str]:
        """Admin revokes a user's API key."""
        if not admin_manager.has_permission(admin_id, "activate_premium"):
            return False, "⛔ Permission denied."

        keys = cls._load_keys()
        user_key = str(user_id)

        if user_key not in keys:
            return False, f"No API key found for user `{user_id}`."

        keys[user_key]['active'] = False
        keys[user_key]['revoked_at'] = datetime.now(WAT).isoformat()
        keys[user_key]['revoked_by'] = admin_id

        if cls._save_key(user_id, keys[user_key]):
            admin_manager._log_action(admin_id, "api_key_revoked", str(user_id))
            return True, f"API key revoked for user `{user_id}`."
        return False, "❌ Failed to revoke key. Check Firebase connection."

    @classmethod
    def get_key_info(cls, user_id: int) -> Tuple[bool, str]:
        """User checks their own API key status."""
        keys = cls._load_keys()
        user_key = str(user_id)

        if user_key not in keys:
            return False, (
                "🔑 *No API Key Found*\n\n"
                "You don't have an Enterprise API key yet.\n"
                "Contact the admin to get one issued.\n\n"
                f"Support: {SUPPORT_HANDLE}"
            )

        k = keys[user_key]
        active = k.get('active', False)
        status = "✅ Active" if active else "🚫 Revoked"

        # Reset daily counter if it's a new day
        today = datetime.now(WAT).strftime("%Y-%m-%d")
        calls_today = k.get('calls_today', 0)
        if k.get('last_reset') != today:
            calls_today = 0

        remaining = max(0, k.get('daily_limit', cls.DAILY_LIMIT) - calls_today)

        msg = (
            f"🔑 *Your Enterprise API Key*\n\n"
            f"Status: {status}\n"
            f"Label: {k.get('label', 'N/A')}\n"
            f"Created: {k.get('created_at', 'N/A')[:10]}\n\n"
            f"*Usage Today:* {calls_today} / {k.get('daily_limit', cls.DAILY_LIMIT):,}\n"
            f"📈 *Remaining:* {remaining:,} requests\n"
            f"*Total All-time:* {k.get('total_calls', 0):,}\n\n"
        )

        if active:
            key_val = k.get('key', '')
            msg += (
                f"🔐 *Your Key:*\n`{key_val}`\n\n"
                f"📖 *Endpoints:*\n"
                f"• Shop Catalogue (flat):\n`GET {FIREBASE_URL}/shop_catalogue_flat.json?auth={key_val}`\n\n"
                f"• Retail Prices per SKU:\n`GET {FIREBASE_URL}/shop_prices.json?auth={key_val}`\n\n"
                f"• Live FX Rates:\n`GET {FIREBASE_URL}/live_fx.json?auth={key_val}`\n\n"
                f"• Live Commodities:\n`GET {FIREBASE_URL}/live_commodities.json?auth={key_val}`\n\n"
                f"_Keep your key private. Contact {SUPPORT_HANDLE} to rotate it._"
            )
        return True, msg

    @classmethod
    def list_keys(cls, admin_id: int) -> Tuple[bool, str]:
        """Admin lists all issued API keys."""
        if not admin_manager.has_permission(admin_id, "view_stats"):
            return False, "⛔ Permission denied."

        keys = cls._load_keys()
        if not keys:
            return True, "No API keys issued yet."

        today = datetime.now(WAT).strftime("%Y-%m-%d")
        lines = ["*🔑 Enterprise API Keys*\n"]
        active_count = 0

        for uid, k in keys.items():
            active = k.get('active', False)
            if active:
                active_count += 1
            calls = k.get('calls_today', 0) if k.get('last_reset') == today else 0
            status_icon = "✅" if active else "🚫"
            lines.append(
                f"{status_icon} User `{uid}` — {k.get('label', 'N/A')}\n"
                f"   Calls today: {calls} | Total: {k.get('total_calls', 0):,}\n"
                f"   Issued: {k.get('created_at', '')[:10]}\n"
            )

        lines.append(f"\n_Active keys: {active_count} / {len(keys)}_")
        return True, "\n".join(lines)

    @classmethod
    def rotate_key(cls, admin_id: int, user_id: int) -> Tuple[bool, str]:
        """Admin rotates (regenerates) a user's API key."""
        if not admin_manager.has_permission(admin_id, "activate_premium"):
            return False, "⛔ Permission denied."

        keys = cls._load_keys()
        user_key = str(user_id)

        if user_key not in keys:
            return False, f"No API key found for user `{user_id}`."

        new_key = cls._generate_key()
        keys[user_key]['key'] = new_key
        keys[user_key]['rotated_at'] = datetime.now(WAT).isoformat()
        keys[user_key]['rotated_by'] = admin_id
        keys[user_key]['active'] = True

        if cls._save_key(user_id, keys[user_key]):
            admin_manager._log_action(admin_id, "api_key_rotated", str(user_id))
            return True, (
                f"🔄 *API Key Rotated*\n\n"
                f"👤 User: `{user_id}`\n\n"
                f"🔑 *New Key:*\n`{new_key}`\n\n"
                f"_Old key is now invalid. Share the new key with the user._"
            )
        return False, "❌ Failed to rotate key. Check Firebase connection."


# Global Enterprise API manager instance
enterprise_api_manager = EnterpriseAPIManager()


# --- CATALOGUE SYNC MANAGER ---

class CatalogueSyncManager:
    """
    Syncs NIGERIA_SHOP_CATALOGUE + live stock overrides + retail prices
    to Firebase RTDB so Enterprise API keys can query them directly.

    Firebase paths written:
      /shop_catalogue          — full catalogue with categories, SKUs, prices
      /shop_catalogue_flat     — flat list of all SKUs (easier for API consumers)
      /shop_catalogue_meta     — last_synced timestamp, item count, version
    """

    CATALOGUE_PATH  = "/shop_catalogue"
    FLAT_PATH       = "/shop_catalogue_flat"
    META_PATH       = "/shop_catalogue_meta"
    _last_sync: float = 0.0
    _SYNC_INTERVAL: int = 300   # minimum seconds between auto-syncs

    @classmethod
    def _apply_overrides(cls, catalogue: dict) -> dict:
        """
        Merge stock overrides + admin price overrides into a catalogue copy.
        Returns a new dict — does NOT mutate NIGERIA_SHOP_CATALOGUE.
        """
        import copy
        result = copy.deepcopy(catalogue)

        # Load stock overrides (set via /shopstock command)
        stock_overrides = db.load("shop_stock") or {}

        # Load admin retail price overrides (set via /shop setprice)
        try:
            from_firebase = FirebaseManager.read("/shop_price_overrides", default={}) or {}
        except Exception:
            from_firebase = {}

        for cat_name, items in result.items():
            for item in items:
                sku = item.get("sku", "")
                if sku in stock_overrides:
                    item["stock_level"] = stock_overrides[sku]
                if sku in from_firebase:
                    item["base_ngn"] = from_firebase[sku]

        return result

    @classmethod
    def _build_flat(cls, catalogue: dict) -> list:
        """Flatten catalogue into a list of items with category field added.
        Applies item_meta overrides (admin-set photo, name, specs, description)
        so the embed widget reflects all Bot4 edits immediately.
        """
        flat = []
        for cat_name, items in catalogue.items():
            for item in items:
                entry = dict(item)
                entry["category"] = cat_name
                # Apply any admin meta overrides (photo_url, name, specs, etc.)
                entry = _apply_item_meta(entry.get("sku", ""), entry)
                flat.append(entry)
        return flat

    @classmethod
    def _build_meta(cls, flat: list) -> dict:
        return {
            "last_synced":      datetime.now(WAT).isoformat(),
            "item_count":       len(flat),
            "category_count":   len(NIGERIA_SHOP_CATALOGUE),
            "version":          "1.0",
            "bot":              "iVolt Power Solutions",
            "note":             "Prices in NGN. stock_level: in_stock | low_stock | out_of_stock | pre_order"
        }

    @classmethod
    def sync(cls, force: bool = False) -> Tuple[bool, str]:
        """
        Push current catalogue to Firebase.
        Throttled to _SYNC_INTERVAL unless force=True.
        """
        now = time.time()
        if not force and (now - cls._last_sync) < cls._SYNC_INTERVAL:
            return True, "Sync skipped (throttle)"

        try:
            catalogue_with_overrides = cls._apply_overrides(NIGERIA_SHOP_CATALOGUE)
            flat = cls._build_flat(catalogue_with_overrides)
            meta = cls._build_meta(flat)

            ok1 = FirebaseManager.write(cls.CATALOGUE_PATH, catalogue_with_overrides)
            ok2 = FirebaseManager.write(cls.FLAT_PATH, flat)
            ok3 = FirebaseManager.write(cls.META_PATH, meta)

            if ok1 and ok2 and ok3:
                cls._last_sync = now
                logger.info(f"CatalogueSyncManager: synced {meta['item_count']} items to Firebase")
                return True, (
                    f"*Catalogue Synced to Firebase*\n\n"
                    f"Items: {meta['item_count']}\n"
                    f"Categories: {meta['category_count']}\n"
                    f"Time: {meta['last_synced'][:19]} WAT\n\n"
                    f"*API endpoints now live:*\n"
                    f"`GET {FIREBASE_URL}/shop_catalogue.json?auth=<key>`\n"
                    f"`GET {FIREBASE_URL}/shop_catalogue_flat.json?auth=<key>`\n"
                    f"`GET {FIREBASE_URL}/shop_catalogue_meta.json?auth=<key>`"
                )
            else:
                failed = [p for p, ok in [
                    (cls.CATALOGUE_PATH, ok1),
                    (cls.FLAT_PATH, ok2),
                    (cls.META_PATH, ok3)
                ] if not ok]
                return False, f"Partial sync failure on paths: {failed}"

        except Exception as e:
            logger.error(f"CatalogueSyncManager.sync error: {e}", exc_info=True)
            return False, f"Sync error: {e}"

    @classmethod
    def sync_silent(cls, force: bool = False):
        """Fire-and-forget sync — logs result but never raises."""
        try:
            ok, msg = cls.sync(force=force)
            if not ok:
                logger.warning(f"CatalogueSyncManager silent sync: {msg}")
        except Exception as e:
            logger.error(f"CatalogueSyncManager.sync_silent: {e}")


# Global catalogue sync manager instance
catalogue_sync = CatalogueSyncManager()


# --- 7. COMMAND LOCK MANAGER (Fixed) ---

class CommandLockManager:
    """Manage command locks with pattern matching and auto-expiry"""

    def __init__(self):
        self._lock = threading.RLock()
        self._locks_cache = {}
        self._last_load = 0
        self._ensure_locks_file()
        self._load_locks()

    def _ensure_locks_file(self):
        """Initialize locks file"""
        if not os.path.exists(COMMAND_LOCKS_FILE):
            db._save_json(COMMAND_LOCKS_FILE, {
                "locked_commands": {},
                "lock_history": [],
                "global_lock": False
            })

    def _load_locks(self):
        """Load locks from file"""
        try:
            mtime = os.path.getmtime(COMMAND_LOCKS_FILE)
            if mtime > self._last_load:
                self._locks_cache = db._load_json(COMMAND_LOCKS_FILE)
                self._last_load = mtime
        except Exception as e:
            logger.error(f"Error loading locks: {e}")

    def _save_locks(self, data: Dict = None):
        """Save locks to file"""
        data = data or self._locks_cache
        db._save_json(COMMAND_LOCKS_FILE, data)
        self._locks_cache = data
        self._last_load = time.time()

    def is_locked(self, command: str) -> Tuple[bool, Optional[str]]:
        """Check if command is locked with pattern matching"""
        self._load_locks()
        if self._locks_cache.get("global_lock", False):
            return True, "All commands temporarily locked by administrator"

        cmd = command.lower().lstrip('/')
        locked_cmds = self._locks_cache.get("locked_commands", {})

        # Exact match
        if cmd in locked_cmds and locked_cmds[cmd].get("active", False):
            return True, locked_cmds[cmd].get("reason", "Command locked")

        # Pattern matching
        for pattern, lock_data in locked_cmds.items():
            if not lock_data.get("active", False):
                continue
            if pattern.endswith('*') and cmd.startswith(pattern.rstrip('*')):
                return True, lock_data.get("reason", f"Pattern '{pattern}' locked")
            elif pattern.startswith('*') and cmd.endswith(pattern.lstrip('*')):
                return True, lock_data.get("reason", f"Pattern '{pattern}' locked")

        return False, None

    def lock_command(self, admin_id: int, command: str, reason: str = None,
                     duration_minutes: int = None) -> Tuple[bool, str]:
        """Lock a command"""
        if not admin_manager.has_permission(admin_id, "lock_commands"):
            return False, "⛔ Permission denied."

        cmd = command.lower().lstrip('/')

        with self._lock:
            self._load_locks()
            if "locked_commands" not in self._locks_cache:
                self._locks_cache["locked_commands"] = {}

            lock_data = {
                "active": True,
                "locked_by": admin_id,
                "locked_at": datetime.now(WAT).isoformat(),
                "reason": reason or "Command temporarily disabled",
            }

            if duration_minutes:
                unlock_time = datetime.now(WAT) + timedelta(minutes=duration_minutes)
                lock_data["auto_unlock_at"] = unlock_time.isoformat()

            self._locks_cache["locked_commands"][cmd] = lock_data

            if "lock_history" not in self._locks_cache:
                self._locks_cache["lock_history"] = []
            self._locks_cache["lock_history"].append({
                "action": "lock", "command": cmd, "admin_id": admin_id,
                "timestamp": datetime.now(WAT).isoformat(), "reason": reason
            })
            self._save_locks()
            admin_manager._log_action(admin_id, "lock_command", cmd, reason)

        duration_text = f" for {duration_minutes} minutes" if duration_minutes else ""
        return True, f"Command '/{cmd}' locked{duration_text}."

    def unlock_command(self, admin_id: int, command: str) -> Tuple[bool, str]:
        """Unlock a command"""
        if not admin_manager.has_permission(admin_id, "lock_commands"):
            return False, "⛔ Permission denied."

        cmd = command.lower().lstrip('/')

        with self._lock:
            self._load_locks()
            if cmd not in self._locks_cache.get("locked_commands", {}):
                return False, f"Command '/{cmd}' is not locked."

            self._locks_cache["locked_commands"][cmd]["active"] = False
            self._locks_cache["locked_commands"][cmd]["unlocked_by"] = admin_id
            self._locks_cache["locked_commands"][cmd]["unlocked_at"] = datetime.now(WAT).isoformat()
            self._save_locks()
            admin_manager._log_action(admin_id, "unlock_command", cmd)

        return True, f"🔓 Command '/{cmd}' unlocked."

    def global_lock(self, admin_id: int, reason: str = None) -> Tuple[bool, str]:
        """Enable global lock"""
        if not admin_manager.has_permission(admin_id, "lock_commands"):
            return False, "⛔ Permission denied."

        with self._lock:
            self._load_locks()
            self._locks_cache["global_lock"] = True
            self._locks_cache["global_lock_reason"] = reason or "System maintenance"
            self._locks_cache["global_lock_by"] = admin_id
            self._locks_cache["global_lock_at"] = datetime.now(WAT).isoformat()
            self._save_locks()
            admin_manager._log_action(admin_id, "global_lock", None, reason)

        return True, f"GLOBAL LOCK activated. Reason: {reason or 'Maintenance'}"

    def global_unlock(self, admin_id: int) -> Tuple[bool, str]:
        """Disable global lock"""
        if not admin_manager.has_permission(admin_id, "lock_commands"):
            return False, "⛔ Permission denied."

        with self._lock:
            self._load_locks()
            self._locks_cache["global_lock"] = False
            self._locks_cache["global_unlock_by"] = admin_id
            self._locks_cache["global_unlock_at"] = datetime.now(WAT).isoformat()
            self._save_locks()
            admin_manager._log_action(admin_id, "global_unlock")

        return True, "🔓 Global lock removed."

    def list_locked(self, admin_id: int) -> Tuple[bool, str]:
        """List all locked commands"""
        if not admin_manager.is_admin(admin_id):
            return False, "⛔ Admin access required."

        self._load_locks()
        response = "*🔒 Command Lock Status*\n\n"

        if self._locks_cache.get("global_lock", False):
            response += "🚨 *GLOBAL LOCK ACTIVE*\n"
            response += f"Reason: {self._locks_cache.get('global_lock_reason', 'N/A')}\n\n"

        locked_cmds = self._locks_cache.get("locked_commands", {})
        active_locks = {k: v for k, v in locked_cmds.items() if v.get("active", False)}

        if active_locks:
            response += "*Locked Commands:*\n"
            for cmd, data in active_locks.items():
                response += f"/{cmd} - {data.get('reason', 'No reason')}\n"
        else:
            response += "✅ No command locks active."

        return True, response

    def check_auto_unlocks(self):
        """Check and auto-expire locks"""
        self._load_locks()
        current_time = datetime.now(WAT)
        unlocked_any = False

        for cmd, data in self._locks_cache.get("locked_commands", {}).items():
            if not data.get("active", False):
                continue
            auto_unlock = data.get("auto_unlock_at")
            if auto_unlock:
                try:
                    unlock_time = datetime.fromisoformat(auto_unlock)
                    if current_time >= unlock_time:
                        data["active"] = False
                        data["auto_unlocked"] = True
                        unlocked_any = True
                except:
                    pass

        if unlocked_any:
            self._save_locks()

# Global command lock manager
command_lock_manager = CommandLockManager()

# --- 8. REAL-TIME MARKET ENGINE (Fixed) ---

class RealTimeMarketEngine:
    """Central engine for fetching and caching real-time market data with multi-source failover"""

    def __init__(self):
        self.cache = {}
        self.cache_ttl = 300  # 5 minutes default
        self.last_update = {}
        self.price_history = defaultdict(lambda: deque(maxlen=100))
        self.subscribers = []
        self._lock = threading.Lock()
        self._session = requests.Session()
        self._session.headers.update({
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        })

    def _get_cache_key(self, data_type: str, symbol: str) -> str:
        """Generate cache key"""
        return f"{data_type}:{symbol}"

    def _is_cache_valid(self, key: str, ttl: int = None) -> bool:
        """Check if cache entry is still valid"""
        if key not in self.last_update:
            return False
        ttl = ttl or self.cache_ttl
        return (time.time() - self.last_update[key]) < ttl

    def get_cached(self, data_type: str, symbol: str) -> Optional[Dict]:
        """Get cached data if valid"""
        key = self._get_cache_key(data_type, symbol)
        if self._is_cache_valid(key):
            return self.cache.get(key)
        return None

    def set_cached(self, data_type: str, symbol: str, data: Dict, ttl: int = None):
        """Cache data with timestamp"""
        key = self._get_cache_key(data_type, symbol)
        with self._lock:
            self.cache[key] = data
            self.last_update[key] = time.time()
            if 'price' in data:
                self.price_history[key].append({
                    'timestamp': datetime.now(WAT).isoformat(),
                    'price': data['price']
                })

    def fetch_yahoo_finance(self, symbol: str, region: str = "US") -> Optional[Dict]:
        """Fetch real-time data from Yahoo Finance with caching"""
        try:
            cached = self.get_cached("yahoo", symbol)
            if cached:
                return cached

            url = f"https://query1.finance.yahoo.com/v8/finance/chart/{symbol}"
            headers = {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
                'Accept': 'application/json',
                'Accept-Language': 'en-US,en;q=0.9',
                'Referer': 'https://finance.yahoo.com'
            }
            params = {
                'interval': '1d',
                'range': '1mo',
                'includeAdjustedClose': 'true'
            }

            response = self._session.get(url, headers=headers, params=params, timeout=15)

            if response.status_code == 404:
                logger.warning(f"Symbol {symbol} not found")
                return None
            elif response.status_code == 429:
                logger.warning(f"Rate limited for {symbol}")
                return self.cache.get(self._get_cache_key("yahoo", symbol))

            response.raise_for_status()
            data = response.json()

            if not data.get('chart') or not data['chart'].get('result'):
                return None

            result = data['chart']['result'][0]
            meta = result['meta']

            current_price = meta.get('regularMarketPrice', 0)
            previous_close = meta.get('previousClose', 0) or meta.get('chartPreviousClose', 0)

            if previous_close and previous_close > 0:
                change = current_price - previous_close
                change_pct = (change / previous_close) * 100
            else:
                change = 0
                change_pct = 0

            indicators = result.get('indicators', {}).get('quote', [{}])[0]
            closes = [c for c in indicators.get('close', []) if c]
            volumes = [v for v in indicators.get('volume', []) if v]

            processed_data = {
                'symbol': symbol,
                'price': current_price,
                'currency': meta.get('currency', 'USD'),
                'change': round(change, 2),
                'change_pct': round(change_pct, 2),
                'previous_close': previous_close,
                'open': meta.get('regularMarketOpen', 0),
                'high': meta.get('regularMarketDayHigh', 0),
                'low': meta.get('regularMarketDayLow', 0),
                'volume': meta.get('regularMarketVolume', 0),
                'fifty_two_week_high': meta.get('fiftyTwoWeekHigh', 0),
                'fifty_two_week_low': meta.get('fiftyTwoWeekLow', 0),
                'fifty_day_average': meta.get('fiftyDayAverage', 0),
                'two_hundred_day_average': meta.get('twoHundredDayAverage', 0),
                'market_state': meta.get('marketState', 'CLOSED'),
                'exchange': meta.get('exchangeName', 'Unknown'),
                'region': region,
                'timestamp': datetime.now(WAT).isoformat(),
                'price_history': closes[-30:] if closes else [],
                'volume_history': volumes[-30:] if volumes else [],
                'data_quality': 'real-time' if meta.get('marketState') == 'REGULAR' else 'delayed'
            }

            self.set_cached("yahoo", symbol, processed_data, ttl=60)
            return processed_data

        except Exception as e:
            logger.error(f"Error fetching {symbol}: {e}")
            return self._get_fallback_data(symbol)

    def _get_fallback_data(self, symbol: str) -> Optional[Dict]:
        """Get fallback data from cache or generate synthetic"""
        key = self._get_cache_key("yahoo", symbol)
        if key in self.cache:
            data = self.cache[key].copy()
            data['data_quality'] = 'cached'
            return data

        if symbol in ["HG=F", "CL=F", "ALI=F", "BZ=F", "GC=F", "SI=F", "NG=F"]:
            return self._generate_synthetic_commodity(symbol)
        return None

    def _generate_synthetic_commodity(self, symbol: str) -> Dict:
        """Generate synthetic commodity data when APIs fail"""
        base_prices = {
            "HG=F": 4.15, "CL=F": 75.50, "BZ=F": 78.50, "ALI=F": 2200.0,
            "GC=F": 2050.0, "SI=F": 23.50, "NG=F": 2.85, "LIT": 55.0
        }
        base = base_prices.get(symbol, 100.0)
        variation = random.uniform(-0.02, 0.02)
        price = base * (1 + variation)

        return {
            'symbol': symbol,
            'price': round(price, 2),
            'currency': 'USD',
            'change': round(price * variation, 2),
            'change_pct': round(variation * 100, 2),
            'data_quality': 'synthetic',
            'timestamp': datetime.now(WAT).isoformat()
        }

    def fetch_exchange_rate(self, base: str, quote: str = "NGN") -> Optional[Dict]:
        """Fetch exchange rate with multi-source failover"""
        cache_key = f"{base}_{quote}"
        cached = self.get_cached("forex", cache_key)
        if cached:
            return cached

        sources = [
            self._fetch_from_alpha_vantage,
            self._fetch_from_yahoo_forex,
            self._fetch_from_cbn_parallel
        ]

        for source_func in sources:
            try:
                result = source_func(base, quote)
                if result and result.get('rate', 0) > 0:
                    self.set_cached("forex", cache_key, result, ttl=300)
                    return result
            except Exception as e:
                logger.warning(f"Source {source_func.__name__} failed: {e}")
                continue

        return self._get_fallback_forex(base, quote)

    def _fetch_from_alpha_vantage(self, base: str, quote: str) -> Optional[Dict]:
        """Fetch from Alpha Vantage API"""
        if not ALPHA_VANTAGE_KEY or ALPHA_VANTAGE_KEY == "demo":
            return None
        url = f"https://www.alphavantage.co/query?function=CURRENCY_EXCHANGE_RATE&from_currency={base}&to_currency={quote}&apikey={ALPHA_VANTAGE_KEY}"
        response = self._session.get(url, timeout=10)
        data = response.json()
        if 'Realtime Currency Exchange Rate' in data:
            fx = data['Realtime Currency Exchange Rate']
            return {
                'base': base, 'quote': quote, 'rate': float(fx['5. Exchange Rate']),
                'source': 'Alpha Vantage', 'timestamp': fx['6. Last Refreshed'],
                'bid': float(fx.get('8. Bid Price', 0)),
                'ask': float(fx.get('9. Ask Price', 0))
            }
        return None

    def _fetch_from_yahoo_forex(self, base: str, quote: str) -> Optional[Dict]:
        """Fetch from Yahoo Finance forex"""
        symbol = f"{base}{quote}=X"
        data = self.fetch_yahoo_finance(symbol, "FX")
        if data and data['price'] > 0:
            return {
                'base': base, 'quote': quote, 'rate': data['price'],
                'change_pct': data['change_pct'], 'source': 'Yahoo Finance',
                'timestamp': data['timestamp'],
                'bid': data['price'] * 0.998, 'ask': data['price'] * 1.002
            }
        return None

    def _fetch_from_cbn_parallel(self, base: str, quote: str) -> Optional[Dict]:
        """Fetch from CBN/Parallel market rates"""
        if quote != "NGN":
            return None
        fallback_rates = {
            "USD": {"official": 1600, "parallel": 1640},
            "GBP": {"official": 2000, "parallel": 2050},
            "EUR": {"official": 1700, "parallel": 1750},
            "CNY": {"official": 220, "parallel": 225}
        }
        if base in fallback_rates:
            rates = fallback_rates[base]
            return {
                'base': base, 'quote': quote, 'rate': rates['parallel'],
                'official_rate': rates['official'],
                'spread_pct': ((rates['parallel'] - rates['official']) / rates['official']) * 100,
                'source': 'CBN/Parallel Market',
                'timestamp': datetime.now(WAT).isoformat(),
                'market_type': 'parallel'
            }
        return None

    def _get_fallback_forex(self, base: str, quote: str) -> Dict:
        """Hardcoded fallback rates"""
        hardcoded = {
            "USD_NGN": 1640.0, "GBP_NGN": 2050.0,
            "EUR_NGN": 1750.0, "CNY_NGN": 225.0, "JPY_NGN": 10.5
        }
        rate = hardcoded.get(f"{base}_{quote}", 1640.0)
        return {
            'base': base, 'quote': quote, 'rate': rate,
            'source': 'Fallback/Hardcoded',
            'timestamp': datetime.now(WAT).isoformat()
        }

    def fetch_commodity_prices(self) -> Dict[str, Dict]:
        """Fetch all commodity prices"""
        commodities = {}
        for name, config in SYMBOLS["COMMODITIES"].items():
            symbol = config["symbol"]
            data = self.fetch_yahoo_finance(symbol, "COMMODITY")
            if data:
                commodities[name] = {
                    'price': data['price'], 'change_pct': data['change_pct'],
                    'unit': config['unit'], 'source': config['source'],
                    'currency': data['currency'], 'weight': config.get('weight', 0.25),
                    'timestamp': data['timestamp'], 'data_quality': data.get('data_quality', 'real-time')
                }
            else:
                synthetic = self._generate_synthetic_commodity(symbol)
                commodities[name] = {
                    'price': synthetic['price'], 'change_pct': synthetic['change_pct'],
                    'unit': config['unit'], 'source': f"{config['source']} (Est.)",
                    'currency': 'USD', 'weight': config.get('weight', 0.25),
                    'timestamp': synthetic['timestamp'], 'data_quality': 'estimated'
                }
        return commodities

    def _load_equipment_overrides(self) -> dict:
        """Load admin-set equipment price overrides from disk."""
        try:
            if os.path.exists(EQUIPMENT_OVERRIDES_FILE):
                with open(EQUIPMENT_OVERRIDES_FILE, "r") as f:
                    return json.load(f)
        except Exception:
            pass
        return {}

    def _save_equipment_overrides(self, overrides: dict) -> None:
        """Persist admin-set equipment price overrides to disk."""
        try:
            with open(EQUIPMENT_OVERRIDES_FILE, "w") as f:
                json.dump(overrides, f, indent=2)
        except Exception as e:
            logger.error(f"Failed to save equipment overrides: {e}")

    def calculate_equipment_prices(self, region: str = "Nigeria", _commodities=None, _fx_data=None) -> Dict[str, Dict]:
        """Calculate real-time landed equipment prices with full VAT/duty/logistics breakdown.
        Always uses NGN rate. Pass _commodities/_fx_data to reuse already-fetched data."""
        try:
            fx_data     = _fx_data or self.fetch_exchange_rate("USD", "NGN")
            commodities = _commodities or self.fetch_commodity_prices()
            usd_rate    = fx_data['rate'] if fx_data else 1550.0
        except Exception as e:
            logger.error(f"calculate_equipment_prices FX/commodity fetch error: {e}")
            usd_rate    = 1550.0
            commodities = {}

        mult = get_regional_multipliers().get(region, get_regional_multipliers()["Nigeria"])

        # Individual tax/cost rates (for transparent display)
        insurance_rate    = mult.get('insurance', 1.005) - 1  # e.g. 0.01 = 1% (on CIF)
        import_duty_rate  = mult['import_duty'] - 1           # e.g. 0.15 = 15%
        vat_rate          = mult['vat'] - 1                   # e.g. 0.075 = 7.5%
        logistics_rate    = mult['logistics'] - 1             # e.g. 0.12 = 12%
        fx_risk_rate      = mult['fx_risk'] - 1               # e.g. 0.08 = 8%
        inflation_rate    = mult['inflation_adj'] - 1         # e.g. 0.25 = 25%
        local_content     = mult['local_content']             # e.g. 0.95 = -5% discount

        # Commodity-driven material adjustment
        copper_adj   = 1 + (commodities.get('COPPER',   {}).get('change_pct', 0) / 100) * 0.40
        steel_adj    = 1 + (commodities.get('STEEL',    {}).get('change_pct', 0) / 100) * 0.30
        aluminum_adj = 1 + (commodities.get('ALUMINUM', {}).get('change_pct', 0) / 100) * 0.20
        oil_adj      = 1 + (commodities.get('OIL_WTI',  {}).get('change_pct', 0) / 100) * 0.10
        mat_mult     = copper_adj * 0.35 + steel_adj * 0.25 + aluminum_adj * 0.20 + oil_adj * 0.20

        qualities = [c.get('data_quality', 'unknown') for c in commodities.values()]
        dq = 'real-time' if 'real-time' in qualities else 'delayed' if 'delayed' in qualities else 'estimated'

        overrides = {}
        try:
            overrides = self._load_equipment_overrides()
        except Exception:
            pass

        calculated_prices = {}
        for category, items in EQUIPMENT_DATABASE.items():
            calculated_prices[category] = {}
            for item_name, specs in items.items():
                try:
                    base_usd = specs['base_cost_usd']

                    # Admin override replaces the base; taxes still apply on top
                    if item_name in overrides and overrides[item_name].get('override_usd', 0) > 0:
                        cif_usd  = float(overrides[item_name]['override_usd'])
                        item_dq  = 'admin_override'
                        price_src = f"admin@{overrides[item_name].get('set_at','?')[:10]}"
                    else:
                        cif_usd  = base_usd * mat_mult
                        item_dq  = dq
                        price_src = 'commodity_derived'

                    # Convert CIF to NGN before applying taxes
                    cif_ngn          = cif_usd * usd_rate

                    # Step-by-step landed cost (CIF → Insurance → Duty → VAT → Logistics → FX → Inflation → Local discount)
                    insurance_ngn    = cif_ngn * insurance_rate        # 1% on CIF value
                    cif_insured_ngn  = cif_ngn + insurance_ngn
                    duty_ngn         = cif_insured_ngn * import_duty_rate
                    subtotal_duty    = cif_insured_ngn + duty_ngn
                    vat_ngn          = subtotal_duty * vat_rate
                    subtotal_vat     = subtotal_duty + vat_ngn
                    logistics_ngn    = subtotal_vat * logistics_rate
                    subtotal_log     = subtotal_vat + logistics_ngn
                    fx_risk_ngn      = subtotal_log * fx_risk_rate
                    subtotal_fx      = subtotal_log + fx_risk_ngn
                    inflation_ngn    = subtotal_fx * inflation_rate
                    subtotal_inf     = subtotal_fx + inflation_ngn
                    landed_ngn       = subtotal_inf * local_content   # local content gives small discount

                    # USD equivalent of final landed price
                    landed_usd       = landed_ngn / usd_rate

                    calculated_prices[category][item_name] = {
                        # Primary prices shown to user
                        'price_ngn':          round(landed_ngn, 2),
                        'price_usd':          round(landed_usd, 2),
                        # Itemised breakdown (NGN)
                        'breakdown': {
                            'cif_ngn':        round(cif_ngn, 2),
                            'insurance_ngn':  round(insurance_ngn, 2),
                            'duty_ngn':       round(duty_ngn, 2),
                            'vat_ngn':        round(vat_ngn, 2),
                            'logistics_ngn':  round(logistics_ngn, 2),
                            'fx_risk_ngn':    round(fx_risk_ngn, 2),
                            'inflation_ngn':  round(inflation_ngn, 2),
                            'subtotal_ex_vat':round(subtotal_duty, 2),
                        },
                        # Rates for display
                        'rates': {
                            'insurance_pct':    round(insurance_rate * 100, 2),
                            'import_duty_pct':  round(import_duty_rate * 100, 1),
                            'vat_pct':          round(vat_rate * 100, 1),
                            'logistics_pct':    round(logistics_rate * 100, 1),
                            'fx_risk_pct':      round(fx_risk_rate * 100, 1),
                            'inflation_pct':    round(inflation_rate * 100, 1),
                            'local_discount_pct': round((1 - local_content) * 100, 1),
                        },
                        'base_price_usd':     base_usd,
                        'cif_usd':            round(cif_usd, 2),
                        'data_quality':       item_dq,
                        'price_source':       price_src,
                        'proxy_ticker':       'N/A',
                        'material_adjustment': round((mat_mult - 1) * 100, 2),
                        'fx_rate':            usd_rate,
                        'stock_level':        specs.get('stock_level', 'Unknown'),
                        'warranty_months':    specs.get('warranty_months', 12),
                        'specifications': {
                            'power_rating':        specs.get('power_rating', 'N/A'),
                            'watts':               specs.get('watts', specs.get('watts_coverage', 0)),
                            'efficiency':          specs.get('efficiency', 0),
                            'lifespan_years':      specs.get('lifespan_years', 5),
                            'applications':        specs.get('applications', []),
                            'install_hours':       specs.get('install_hours', 2),
                            'commissioning_hours': specs.get('commissioning_hours', 1),
                            'phase':               specs.get('phase', 'Single'),
                            'technology':          specs.get('technology', 'Standard'),
                            'description':         specs.get('description', ''),
                            'protection_level':    specs.get('protection_level', ''),
                            'capacity':            specs.get('capacity', ''),
                            'response_time':       specs.get('response_time', ''),
                            'schematic_type':      specs.get('schematic_type', ''),
                        },
                        'last_updated': datetime.now(WAT).isoformat(),
                        'valid_until':  (datetime.now(WAT) + timedelta(hours=24)).isoformat(),
                    }
                except Exception as e:
                    logger.error(f"Price calc error for {item_name}: {e}")
                    calculated_prices[category][item_name] = {
                        'price_ngn': 0, 'price_usd': 0, 'cif_usd': 0,
                        'base_price_usd': specs.get('base_cost_usd', 0),
                        'data_quality': 'error', 'price_source': 'error', 'proxy_ticker': 'N/A',
                        'breakdown': {}, 'rates': {},
                        'stock_level': specs.get('stock_level', '?'), 'warranty_months': 12,
                        'specifications': {}, 'last_updated': datetime.now(WAT).isoformat(),
                        'valid_until': datetime.now(WAT).isoformat(),
                    }
        return calculated_prices

    def fetch_power_sector_stocks(self) -> Dict[str, Dict]:
        """Fetch power sector stock data"""
        stock_data = {}
        for region, stocks in SYMBOLS["POWER_SECTOR"].items():
            stock_data[region] = {}
            for symbol, info in stocks.items():
                data = self.fetch_yahoo_finance(symbol, region)
                if data:
                    stock_data[region][symbol] = {
                        **data, **info,
                        'analysis': self._analyze_stock_signal(data)
                    }
                time.sleep(0.1)  # Rate limiting
        return stock_data

    def _analyze_stock_signal(self, data: Dict) -> Dict:
        """Generate trading signal from stock data"""
        price = data['price']
        avg_50 = data.get('fifty_day_average', 0)
        avg_200 = data.get('two_hundred_day_average', 0)
        change_pct = data.get('change_pct', 0)

        signal = {
            'trend': 'Neutral', 'strength': 50, 'recommendation': 'Hold',
            'entry_point': None, 'exit_point': None, 'sector_impact': 'Neutral'
        }

        if avg_50 > 0 and avg_200 > 0:
            # Full MA crossover signal — primary path
            if price > avg_50 > avg_200:
                signal.update({
                    'trend': 'Strong Bullish', 'strength': 80, 'recommendation': 'Buy',
                    'sector_impact': 'Equipment prices rising - Procure now',
                    'entry_point': round(avg_50 * 0.98, 2),
                    'exit_point': round(avg_50 * 1.05, 2)
                })
            elif price < avg_50 < avg_200:
                signal.update({
                    'trend': 'Bearish', 'strength': 30, 'recommendation': 'Sell/Wait',
                    'sector_impact': 'Equipment prices may drop - Delay procurement'
                })
            elif price > avg_50:
                signal.update({
                    'trend': 'Short-term Bullish', 'strength': 65, 'recommendation': 'Accumulate',
                    'sector_impact': 'Moderate price increase expected'
                })
        else:
            # Fallback: MA data absent — derive live signal from change_pct alone
            if change_pct > 3:
                signal.update({
                    'trend': 'Bullish', 'strength': 60, 'recommendation': 'Buy',
                    'sector_impact': 'Equipment prices rising - Procure now'
                })
            elif change_pct > 1:
                signal.update({
                    'trend': 'Short-term Bullish', 'strength': 55, 'recommendation': 'Accumulate',
                    'sector_impact': 'Moderate price increase expected'
                })
            elif change_pct < -3:
                signal.update({
                    'trend': 'Bearish', 'strength': 35, 'recommendation': 'Sell/Wait',
                    'sector_impact': 'Equipment prices may drop - Delay procurement'
                })
            elif change_pct < -1:
                signal.update({
                    'trend': 'Short-term Bearish', 'strength': 42, 'recommendation': 'Hold',
                    'sector_impact': 'Minor price softening possible'
                })
            # -1 to +1: stays at default Neutral/Hold

        if abs(change_pct) > 5:
            signal['volatility_alert'] = 'High volatility detected'

        return signal

    def calculate_oil_prices(self, liters: float = None, region: str = "Nigeria"):
        """Calculate transformer oil prices using the dynamic oil manager"""
        fx_data = self.fetch_exchange_rate("USD", "NGN")
        fx_rate = fx_data['rate'] if fx_data else 1550

        # Use the dynamic oil manager for calculations
        return oil_manager.calculate_all_oil_prices(liters, fx_rate)

# Global market engine instance
market_engine = RealTimeMarketEngine()

# --- 9. TECHNICAL ANALYSIS ENGINE (Fixed) ---

class TechnicalAnalysis:
    """Technical analysis calculations for market data"""

    @staticmethod
    def calculate_ema(prices: List[float], period: int = 15) -> float:
        """Calculate Exponential Moving Average"""
        if len(prices) < period:
            return sum(prices) / len(prices) if prices else 0
        k = 2 / (period + 1)
        ema = sum(prices[:period]) / period
        for price in prices[period:]:
            ema = (price * k) + (ema * (1 - k))
        return ema

    @staticmethod
    def calculate_rsi(prices: List[float], period: int = 14) -> float:
        """Calculate Relative Strength Index"""
        if len(prices) < period + 1:
            return 50.0
        gains, losses = [], []
        for i in range(1, len(prices)):
            change = prices[i] - prices[i-1]
            gains.append(change if change > 0 else 0)
            losses.append(abs(change) if change < 0 else 0)
        avg_gain = sum(gains[-period:]) / period
        avg_loss = sum(losses[-period:]) / period
        if avg_loss == 0:
            return 100.0
        rs = avg_gain / avg_loss
        return 100 - (100 / (1 + rs))

    @staticmethod
    def calculate_macd(prices: List[float], fast: int = 12, slow: int = 26, signal: int = 9):
        """Calculate MACD indicator"""
        if len(prices) < slow:
            return 0.0, 0.0, 0.0
        ema_fast = TechnicalAnalysis.calculate_ema(prices, fast)
        ema_slow = TechnicalAnalysis.calculate_ema(prices, slow)
        macd_line = ema_fast - ema_slow
        signal_line = macd_line * (2 / (signal + 1))
        return macd_line, signal_line, macd_line - signal_line

    @staticmethod
    def calculate_bollinger_bands(prices: List[float], period: int = 20, std_dev: int = 2):
        """Calculate Bollinger Bands"""
        if len(prices) < period:
            return 0.0, 0.0, 0.0
        recent = prices[-period:]
        sma = sum(recent) / period
        variance = sum((p - sma) ** 2 for p in recent) / period
        std = variance ** 0.5
        return sma + (std_dev * std), sma, sma - (std_dev * std)

    @staticmethod
    def detect_market_cycle(prices: List[float], volumes: List[int] = None) -> Dict:
        """Detect current market cycle phase"""
        if len(prices) < 30:
            return {'cycle': 'Insufficient Data', 'confidence': 0}

        ema_15 = TechnicalAnalysis.calculate_ema(prices, 15)
        ema_30 = TechnicalAnalysis.calculate_ema(prices, 30)
        rsi = TechnicalAnalysis.calculate_rsi(prices)
        macd, signal, hist = TechnicalAnalysis.calculate_macd(prices)

        current_price = prices[-1]
        trend = "Uptrend" if current_price > ema_15 > ema_30 else "Downtrend" if current_price < ema_15 < ema_30 else "Neutral"
        rsi_phase = "Overbought" if rsi > 70 else "Oversold" if rsi < 30 else "Neutral"
        momentum = "Bullish" if macd > signal and hist > 0 else "Bearish" if macd < signal and hist < 0 else "Neutral"

        cycle = "Transition"
        if trend == "Uptrend" and rsi_phase == "Overbought":
            cycle = "Expansion (Late Stage)"
        elif trend == "Uptrend" and rsi_phase == "Neutral":
            cycle = "Expansion (Early/Mid)"
        elif trend == "Downtrend" and rsi_phase == "Oversold":
            cycle = "Accumulation"
        elif trend == "Downtrend":
            cycle = "Contraction"

        # Bollinger Band position (0=at lower, 0.5=mid, 1=at upper)
        upper_bb, mid_bb, lower_bb = TechnicalAnalysis.calculate_bollinger_bands(prices)
        bb_range = upper_bb - lower_bb if upper_bb != lower_bb else 1
        bb_position = max(0.0, min(1.0, (current_price - lower_bb) / bb_range))

        return {
            'cycle': cycle, 'trend': trend, 'rsi_phase': rsi_phase,
            'momentum': momentum, 'confidence': min(len(prices) / 90 * 100, 100),
            'rsi': rsi, 'macd_hist': hist, 'bb_position': bb_position
        }

    @staticmethod
    def calculate_30day_forecast(prices: List[float], cycle_info: Dict) -> Dict:
        """
        Real-time 30-day directional probability forecast.
        Uses RSI, MACD histogram, Bollinger Band position, trend, and momentum.
        Always normalises so Lower + Stable + Higher == 100%.
        """
        rsi          = cycle_info.get('rsi', 50.0)
        macd_hist    = cycle_info.get('macd_hist', 0.0)
        bb_pos       = cycle_info.get('bb_position', 0.5)   # 0=oversold end, 1=overbought end
        trend        = cycle_info.get('trend', 'Neutral')
        momentum     = cycle_info.get('momentum', 'Neutral')
        confidence   = cycle_info.get('confidence', 50.0)

        # ── Base scores (raw, not yet normalised) ────────────────────────────
        # RSI contribution: RSI > 50 → biases Higher; < 50 → biases Lower
        rsi_bias = (rsi - 50) / 50          # -1.0 … +1.0

        # MACD histogram: positive = upward momentum, negative = downward
        if prices:
            price_scale = max(abs(p) for p in prices[-10:]) or 1
            macd_norm   = max(-1.0, min(1.0, macd_hist / (price_scale * 0.01)))
        else:
            macd_norm = 0.0

        # Bollinger Band position: near upper band → more likely to revert lower
        # near lower band → more likely to revert higher
        bb_bias = (bb_pos - 0.5) * 2        # -1.0 … +1.0  (positive = near upper)

        # Trend weight
        trend_w = {'Uptrend': 0.35, 'Downtrend': -0.35, 'Neutral': 0.0}.get(trend, 0.0)

        # Momentum weight
        mom_w = {'Bullish': 0.25, 'Bearish': -0.25, 'Neutral': 0.0}.get(momentum, 0.0)

        # Composite directional score: positive = higher, negative = lower
        score = (rsi_bias * 0.30) + (macd_norm * 0.25) + (-bb_bias * 0.20) + (trend_w) + (mom_w)
        score = max(-1.0, min(1.0, score))

        # ── Convert score to raw probabilities ───────────────────────────────
        # score =  1.0 → Higher=70, Stable=20, Lower=10
        # score =  0.0 → Higher=33, Stable=34, Lower=33
        # score = -1.0 → Higher=10, Stable=20, Lower=70
        base_extreme = 60   # max swing from centre at |score|=1
        centre = 100 / 3

        p_higher = centre + score * base_extreme
        p_lower  = centre - score * base_extreme
        p_stable = 100 - p_higher - p_lower     # residual always sums to 100

        # Clamp each bucket (5–70) then renormalise
        p_higher = max(5.0, min(70.0, p_higher))
        p_lower  = max(5.0, min(70.0, p_lower))
        p_stable = max(5.0, min(70.0, p_stable))
        total    = p_higher + p_lower + p_stable
        p_higher = round(p_higher / total * 100)
        p_lower  = round(p_lower  / total * 100)
        p_stable = 100 - p_higher - p_lower     # ensure exact 100%

        # ── Confidence-scale: low data → flatten toward 33/34/33 ─────────────
        conf_factor = confidence / 100.0
        p_higher = round(p_higher * conf_factor + 33 * (1 - conf_factor))
        p_lower  = round(p_lower  * conf_factor + 33 * (1 - conf_factor))
        p_stable = 100 - p_higher - p_lower

        return {
            'higher': p_higher,
            'stable': p_stable,
            'lower':  p_lower,
            'score':  round(score, 3),
            'drivers': {
                'rsi_bias':   round(rsi_bias,  3),
                'macd_norm':  round(macd_norm, 3),
                'bb_bias':    round(bb_bias,   3),
                'trend_w':    round(trend_w,   3),
                'momentum_w': round(mom_w,     3),
            }
        }

# --- 10. PROJECT CALCULATOR ENGINE (Fixed) ---

class ProjectCalculator:
    """Dynamic real-time project cost calculator"""

    # NERC 2024 Multi-Year Tariff Order (₦/kWh by load band)
    NERC_TARIFF_BANDS = {
        "residential":  68.27,
        "commercial":   84.65,
        "industrial":   92.40,
        "data_center": 104.50,
        "medical":      92.40,
        "mixed":        76.50,
        "telecom":      92.40,
    }

    def __init__(self):
        self.market_engine = market_engine

    def calculate_kva_from_watts(self, watts: float, load_type: str = "mixed", 
                                power_factor: float = 0.8) -> Dict:
        """Calculate kVA requirements from watts with load analysis"""
        load_config = LOAD_TYPE_MULTIPLIERS.get(load_type, LOAD_TYPE_MULTIPLIERS["mixed"])

        # Base calculation
        apparent_power = watts / power_factor  # kVA = kW / PF
        demand_adjusted = apparent_power * load_config["demand_factor"]
        diversified = demand_adjusted * load_config["diversity_factor"]

        # Apply safety margin
        required_kva = diversified * load_config["safety_margin"]

        # Recommend standard size
        standard_sizes = [5, 10, 20, 50, 100, 200, 500]
        recommended_kva = next((s for s in standard_sizes if s >= required_kva), 500)

        # Future expansion recommendation (20% headroom)
        future_kva = required_kva * 1.2

        return {
            "input_watts": watts,
            "apparent_power_kva": round(apparent_power, 2),
            "demand_adjusted_kva": round(demand_adjusted, 2),
            "diversified_kva": round(diversified, 2),
            "required_kva": round(required_kva, 2),
            "recommended_kva": recommended_kva,
            "future_expansion_kva": round(future_kva, 2),
            "load_type": load_type,
            "power_factor": power_factor,
            "safety_margin_applied": load_config["safety_margin"],
            "utilization_at_load": round((required_kva / recommended_kva) * 100, 1)
        }

    def select_equipment(self, kva_required: float, phase: str = "auto") -> Dict:
        """Select appropriate equipment based on kVA requirements"""
        prices = self.market_engine.calculate_equipment_prices("Nigeria")

        # Find best matching stabilizer — exclude plug-in/entry residential units for project sizing
        stabilizers = prices.get("Voltage Stabilizers", {})
        suitable_stabs = []

        for name, data in stabilizers.items():
            # Skip 1kVA and 2kVA residential relay units for project auto-selection
            if any(x in name for x in ["1kVA Residential", "2kVA Residential"]):
                if kva_required > 2:
                    continue
            watts = data['specifications'].get('watts', 0)
            stab_kva = watts / 1000
            if stab_kva >= kva_required * 0.8:  # Allow 20% undersizing for parallel configs
                suitable_stabs.append({
                    "name": name,
                    "kva": stab_kva,
                    "watts": watts,
                    "price_ngn": data['price_ngn'],
                    "price_usd": data['price_usd'],
                    "efficiency": data['specifications'].get('efficiency', 0.95),
                    "stock_level": data['stock_level'],
                    "warranty_months": data['warranty_months'],
                    "install_hours": data['specifications'].get('install_hours', 4),
                    "commissioning_hours": data['specifications'].get('commissioning_hours', 2),
                    "phase": data['specifications'].get('phase', 'Single'),
                    "technology": data['specifications'].get('technology', 'Standard'),
                    "schematic_type": data['specifications'].get('schematic_type', 'standard'),
                    "description": data['specifications'].get('description', ''),
                })

        if not suitable_stabs:
            return {"error": "No suitable equipment found for requirements"}

        # Sort by closest match (not oversized)
        suitable_stabs.sort(key=lambda x: abs(x['kva'] - kva_required))
        primary = suitable_stabs[0]

        # Calculate quantity needed
        qty = max(1, int(kva_required / primary['kva']) + (1 if kva_required % primary['kva'] > 0 else 0))

        # Select surge protection — skip plug-in units for project-level auto-selection
        surge_options = prices.get("Surge Protection", {})
        suitable_surge = []
        for name, data in surge_options.items():
            # Skip residential plug-in suppressors for project auto-selection
            if "Plug-In" in name:
                continue
            coverage = data['specifications'].get('watts', 0)
            if coverage >= kva_required * 1000 * 0.8:
                suitable_surge.append({
                    "name": name,
                    "coverage_watts": coverage,
                    "price_ngn": data['price_ngn'],
                    "price_usd": data['price_usd'],
                    "protection_level": data['specifications'].get('protection_level', 'Type 2'),
                    "install_hours": data['specifications'].get('install_hours', 1),
                    "description": data['specifications'].get('description', ''),
                })

        suitable_surge.sort(key=lambda x: x['coverage_watts'])
        surge = suitable_surge[0] if suitable_surge else None

        return {
            "primary_stabilizer": primary,
            "quantity_required": qty,
            "total_stabilizer_kva": primary['kva'] * qty,
            "surge_protection": surge,
            "parallel_configuration": qty > 1,
            "phase_recommendation": "Three Phase" if kva_required > 15 else "Single Phase",
            "backup_recommendation": suitable_stabs[1] if len(suitable_stabs) > 1 else None
        }

    def calculate_workmanship(self, equipment_selection: Dict, region: str = "Nigeria",
                             complexity: str = "standard") -> Dict:
        """Calculate labor and workmanship costs"""
        multipliers = REGIONAL_MULTIPLIERS.get(region, REGIONAL_MULTIPLIERS["Nigeria"])
        labor_rate = multipliers['labor_rate_per_hour']
        workmanship_factor = multipliers['workmanship_factor']

        # Base hours from equipment
        stab = equipment_selection['primary_stabilizer']
        base_hours = (stab['install_hours'] + stab['commissioning_hours']) * equipment_selection['quantity_required']

        # Surge protection hours
        surge_hours = equipment_selection['surge_protection']['install_hours'] if equipment_selection['surge_protection'] else 0

        # Complexity adjustment
        complexity_multipliers = {
            "simple": 0.7, "standard": 1.0, "complex": 1.5, "very_complex": 2.0
        }
        complexity_mult = complexity_multipliers.get(complexity, 1.0)

        total_hours = (base_hours + surge_hours + 4) * complexity_mult  # +4 for testing/verification

        # Team composition
        if total_hours <= 4:
            team = {"technicians": 1, "electricians": 1, "engineers": 0}
        elif total_hours <= 16:
            team = {"technicians": 2, "electricians": 2, "engineers": 1}
        else:
            team = {"technicians": 3, "electricians": 2, "engineers": 1}

        # Calculate costs
        technician_cost = team['technicians'] * labor_rate * 0.6 * total_hours
        electrician_cost = team['electricians'] * labor_rate * total_hours
        engineer_cost = team['engineers'] * labor_rate * 2.0 * total_hours * 0.3  # Engineer only 30% of time

        subtotal_labor = (technician_cost + electrician_cost + engineer_cost) * workmanship_factor

        # Additional costs
        transport = 15000 * complexity_mult
        accommodation = 25000 * complexity_mult if total_hours > 8 else 0
        tools_equipment = 10000 * complexity_mult

        total_workmanship = subtotal_labor + transport + accommodation + tools_equipment

        return {
            "labor_hours": round(total_hours, 1),
            "team_composition": team,
            "labor_breakdown": {
                "technicians": round(technician_cost * workmanship_factor, 2),
                "electricians": round(electrician_cost * workmanship_factor, 2),
                "engineers": round(engineer_cost * workmanship_factor, 2)
            },
            "additional_costs": {
                "transport": round(transport, 2),
                "accommodation": round(accommodation, 2),
                "tools_and_equipment": round(tools_equipment, 2)
            },
            "total_workmanship_ngn": round(total_workmanship, 2),
            "workmanship_factor_applied": workmanship_factor,
            "complexity_level": complexity
        }

    def calculate_taxes_and_duties(self, equipment_cost_ngn: float, region: str = "Nigeria") -> Dict:
        """Calculate all applicable taxes and duties"""
        multipliers = REGIONAL_MULTIPLIERS.get(region, REGIONAL_MULTIPLIERS["Nigeria"])
        tax_structure = multipliers['tax_structure']

        # VAT calculation
        vat_rate = tax_structure.get('vat', 0.075)
        vat_amount = equipment_cost_ngn * vat_rate

        # Withholding tax (if applicable)
        withholding_rate = tax_structure.get('withholding', 0.05)
        withholding_amount = equipment_cost_ngn * withholding_rate

        # Import duty (already factored in equipment price, but show breakdown)
        import_duty_rate = multipliers['import_duty'] - 1  # Convert from multiplier to percentage

        # Local levies (estimated)
        local_levies = equipment_cost_ngn * 0.02

        total_taxes = vat_amount + withholding_amount + local_levies

        return {
            "vat": {"rate": vat_rate, "amount": round(vat_amount, 2)},
            "withholding_tax": {"rate": withholding_rate, "amount": round(withholding_amount, 2)},
            "import_duty": {"rate": import_duty_rate, "amount": "Included in base price"},
            "local_levies": {"rate": 0.02, "amount": round(local_levies, 2)},
            "total_tax_burden": round(total_taxes, 2),
            "effective_tax_rate": round((total_taxes / equipment_cost_ngn) * 100, 2) if equipment_cost_ngn > 0 else 0
        }

    def generate_full_estimate(self, watts: float = None, kva: float = None, 
                              load_type: str = "mixed", region: str = "Nigeria",
                              risk_profile: str = "medium", complexity: str = "standard",
                              urgency: str = "standard", distance_km: float = 50) -> Dict:
        """Generate comprehensive project estimate"""

        # Step 1: Determine kVA requirements
        if watts and not kva:
            kva_calc = self.calculate_kva_from_watts(watts, load_type)
            kva_required = kva_calc['recommended_kva']
        else:
            kva_required = kva or 50
            kva_calc = {
                "input_watts": kva_required * 800,
                "recommended_kva": kva_required,
                "load_type": load_type
            }

        # Step 2: Select equipment
        equipment = self.select_equipment(kva_required)
        if "error" in equipment:
            return equipment

        # Step 3: Get real-time pricing
        fx_data = self.market_engine.fetch_exchange_rate("USD", "NGN")
        commodities = self.market_engine.fetch_commodity_prices()

        # Step 4: Calculate equipment costs
        stab = equipment['primary_stabilizer']
        qty = equipment['quantity_required']

        cost_stabilizers = stab['price_ngn'] * qty
        cost_surge = equipment['surge_protection']['price_ngn'] if equipment['surge_protection'] else 0

        # Accessories (cables, breakers, etc.) - estimated at 15% of equipment
        cost_accessories = (cost_stabilizers + cost_surge) * 0.15

        subtotal_equipment = cost_stabilizers + cost_surge + cost_accessories

        # Step 5: Calculate workmanship
        workmanship = self.calculate_workmanship(equipment, region, complexity)

        # Step 6: Calculate taxes
        taxes = self.calculate_taxes_and_duties(subtotal_equipment, region)

        # Step 7: Apply risk contingency
        risk_config = RISK_PROFILES.get(risk_profile, RISK_PROFILES["medium"])
        contingency = (subtotal_equipment + workmanship['total_workmanship_ngn']) * risk_config['contingency']

        # Step 8: Urgency premium
        urgency_multipliers = {"standard": 1.0, "urgent": 1.15, "emergency": 1.30}
        urgency_mult = urgency_multipliers.get(urgency, 1.0)
        urgency_premium = (subtotal_equipment + workmanship['total_workmanship_ngn']) * (urgency_mult - 1)

        # Step 9: Logistics (distance-based)
        logistics_cost = distance_km * 200  # ₦200 per km

        # Step 10: Calculate totals
        subtotal_project = (subtotal_equipment + workmanship['total_workmanship_ngn'] + 
                           taxes['total_tax_burden'] + contingency + urgency_premium + logistics_cost)

        # Warranty extension (if applicable)
        warranty_extension_cost = 0
        if risk_config['warranty_extension'] > 0:
            warranty_extension_cost = subtotal_equipment * 0.05 * (risk_config['warranty_extension'] / 12)

        grand_total = subtotal_project + warranty_extension_cost

        # Financing options
        financing = {
            "upfront_payment": {"discount": 0.05, "total": grand_total * 0.95},
            "50_50_split": {"discount": 0.02, "total": grand_total * 0.98, "milestone": "50% upfront, 50% on completion"},
            "quarterly_payments": {"discount": 0, "total": grand_total, "terms": "4 quarterly payments"},
            "monthly_12": {"discount": 0, "total": grand_total * 1.08, "terms": "12 monthly payments with 8% service charge"}
        }

        # ROI calculations
        annual_energy_cost = kva_required * 0.8 * 8760 * 50  # Assuming 80% load, 8760 hours, ₦50/kWh
        efficiency_gain = stab['efficiency'] - 0.85  # Compared to no stabilizer
        annual_savings = annual_energy_cost * efficiency_gain

        payback_period = grand_total / annual_savings if annual_savings > 0 else float('inf')

        return {
            "project_id": db.get_next_id(),
            "timestamp": datetime.now(WAT).isoformat(),
            "valid_until": (datetime.now(WAT) + timedelta(hours=24)).isoformat(),
            "input_parameters": {
                "watts": watts,
                "kva": kva,
                "load_type": load_type,
                "region": region,
                "risk_profile": risk_profile,
                "complexity": complexity,
                "urgency": urgency,
                "distance_km": distance_km
            },
            "power_analysis": kva_calc,
            "equipment_selection": equipment,
            "market_conditions": {
                "fx_rate": fx_data['rate'] if fx_data else 1550,
                "fx_source": fx_data.get('source', 'Unknown') if fx_data else 'Fallback',
                "copper_price": commodities.get('COPPER', {}).get('price', 0),
                "steel_price": commodities.get('STEEL', {}).get('price', 0),
                "commodity_trend": "Rising" if commodities.get('COPPER', {}).get('change_pct', 0) > 0 else "Falling"
            },
            "cost_breakdown": {
                "equipment": {
                    "stabilizers": {"unit_price": stab['price_ngn'], "quantity": qty, "total": cost_stabilizers},
                    "surge_protection": {"unit_price": equipment['surge_protection']['price_ngn'] if equipment['surge_protection'] else 0, "total": cost_surge},
                    "accessories": {"description": "Cables, breakers, conduit", "total": cost_accessories},
                    "subtotal": subtotal_equipment
                },
                "workmanship": workmanship,
                "taxes_and_duties": taxes,
                "risk_contingency": {"rate": risk_config['contingency'], "amount": round(contingency, 2)},
                "urgency_premium": {"multiplier": urgency_mult, "amount": round(urgency_premium, 2)},
                "logistics": {"distance_km": distance_km, "cost": logistics_cost},
                "warranty_extension": {"months": risk_config['warranty_extension'], "cost": round(warranty_extension_cost, 2)}
            },
            "summary": {
                "subtotal_project": round(subtotal_project, 2),
                "grand_total_ngn": round(grand_total, 2),
                "grand_total_usd": round(grand_total / (fx_data['rate'] if fx_data else 1550), 2),
                "financing_options": financing
            },
            "roi_analysis": {
                "estimated_annual_savings": round(annual_savings, 2),
                "payback_period_years": round(payback_period, 2) if payback_period != float('inf') else "N/A",
                "10_year_savings": round(annual_savings * 10, 2),
                "efficiency_gain_percent": round(efficiency_gain * 100, 1)
            },
            "recommendations": self._generate_recommendations(equipment, risk_profile, urgency, commodities)
        }

    def _generate_recommendations(self, equipment: Dict, risk_profile: str, 
                                  urgency: str, commodities: Dict) -> List[str]:
        """Generate smart recommendations based on project parameters"""
        recs = []
        stab = equipment['primary_stabilizer']

        if equipment['parallel_configuration']:
            recs.append("⚡ Parallel configuration recommended for redundancy. Consider automatic transfer switch for seamless failover.")

        if stab['stock_level'] == 'Order':
            recs.append(f"{stab['name']} requires ordering. Lead time: 4-6 weeks. Expedite for urgent delivery (+15% cost).")

        if commodities.get('COPPER', {}).get('change_pct', 0) > 2:
            recs.append("📈 Copper prices rising sharply. Lock pricing immediately to avoid cost increases.")
        elif commodities.get('COPPER', {}).get('change_pct', 0) < -2:
            recs.append("📉 Copper prices declining. Consider delaying non-urgent procurement for better pricing.")

        if risk_profile == "critical":
            recs.append("🛡️ Critical installation: Recommend redundant systems and 24/7 monitoring package.")

        if urgency == "emergency":
            recs.append("🚨 Emergency deployment available. Premium covers expedited shipping and overtime labor.")

        if stab['efficiency'] > 0.97:
            recs.append("✅ High-efficiency unit selected. Eligible for green energy tax credits in some regions.")

        return recs

# Initialize calculator
project_calculator = ProjectCalculator()

# --- 11. SCHEMATIC GENERATOR (Fixed with Real-Time Wiring Diagrams) ---

class SchematicGenerator:
    """Landscape block-diagram schematics for Telegram (mobile + desktop).
    All diagrams embed:
      • Live copper price, USD/NGN FX rate, Brent oil price
      • Live retail NGN price for the specific item (from /shop or /price)
      • Stock status badge for /shop items
      • Bot operational status banner
    """

    # ── Block width constant ──────────────────────────────────────────────
    # Each block:  [XXXXXXX]  = exactly 9 chars
    # Arrow:       ──►  = 3 chars
    # Row budget:  4 blocks + 3 arrows = 4×9 + 3×3 = 45 chars (fits mobile)

    @staticmethod
    def get_current_prices(item_sku: str = None):
        """Fetch live market data + optionally the retail price for a shop SKU."""
        result = {"fx_rate": 1550, "copper": 4.15, "oil": 75.50, "timestamp": "N/A",
                  "fx_source": "estimated", "item_retail_ngn": None, "item_name": None,
                  "item_stock": None}
        try:
            fx = market_engine.fetch_exchange_rate("USD", "NGN")
            c  = market_engine.fetch_commodity_prices()
            if fx and fx.get("rate"):
                result["fx_rate"]   = round(fx["rate"])
                result["fx_source"] = fx.get("source", "live")
            if c:
                result["copper"] = c.get("COPPER",  {}).get("price", 4.15)
                result["oil"]    = c.get("OIL_WTI", {}).get("price", 75.50)
            result["timestamp"] = datetime.now(WAT).strftime("%H:%M")
        except Exception:
            pass

        if item_sku:
            try:
                all_items = {p["sku"]: p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}
                if item_sku in all_items:
                    item  = all_items[item_sku]
                    ovr   = {}
                    path  = os.path.join(DATA_DIR, "shop_price_overrides.json")
                    if os.path.exists(path):
                        with open(path) as f:
                            ovr = json.load(f)
                    base   = float(ovr.get(item_sku, {}).get("override_ngn", item["base_ngn"]))
                    margin = get_shop_margin()
                    result["item_retail_ngn"] = round(base * (1 + margin / 100))
                    result["item_name"]       = item["name"]
                    result["item_stock"]      = get_item_stock(item_sku, item.get("stock_level", "in_stock"))
            except Exception:
                pass
        return result

    # ── Diagram primitives ────────────────────────────────────────────────
    @staticmethod
    def _blk(label: str) -> str:
        """Compact 7-char block — fits 3 across on 320px screens."""
        return f"[{label[:6]:^6}]"

    @staticmethod
    def _row(*labels) -> str:
        """Horizontal row — kept to max 3 blocks to fit all screens."""
        return "→".join(SchematicGenerator._blk(l) for l in labels)

    @staticmethod
    def _vrow(*labels) -> str:
        """Vertical stack for small screens — each block on its own line with arrow."""
        parts = [SchematicGenerator._blk(l) for l in labels]
        return "\n  ↓\n".join(parts)

    @staticmethod
    def _connector(n_blocks: int, idx: int) -> str:
        blk_w = 8; arr_w = 1; unit_w = blk_w + arr_w
        centre = idx * unit_w + blk_w // 2 + 1
        return " " * centre + "│"

    @staticmethod
    def _vdown(n_blocks: int, idx: int) -> str:
        blk_w = 8; arr_w = 1; unit_w = blk_w + arr_w
        centre = idx * unit_w + blk_w // 2 + 1
        return " " * centre + "▼"

    @staticmethod
    def _hdr(title: str, sub: str) -> str:
        return f"*{title}*\n_{sub}_\n"

    @staticmethod
    def _specs(items: list) -> str:
        return "\n".join(f"  • *{k}:* {v}" for k, v in items)

    @staticmethod
    def _steps(steps: list) -> str:
        return "\n".join(f"  {i+1}. {s}" for i, s in enumerate(steps))

    @staticmethod
    def _warns(ws: list) -> str:
        return "\n".join(f"  ⚠️ {w}" for w in ws)

    @staticmethod
    def _mkt(p: dict, item_sku: str = None) -> str:
        """Market footer — each metric on its own line for all screen sizes."""
        base = (
            f"  💰 ₦{p['fx_rate']:,.0f}/$\n"
            f"  🪙 Cu ${p['copper']:.2f}/lb · Oil ${p['oil']:.2f}/bbl\n"
            f"  _({p['fx_source']})_"
        )
        if p.get("item_retail_ngn") and p.get("item_name"):
            s_icon = STOCK_LABELS.get(p.get("item_stock", "in_stock"), ("❓",""))[0]
            base += (
                f"\n  🛒 *{p['item_name'][:30]}*\n"
                f"  Retail: ₦{p['item_retail_ngn']:,.0f} {s_icon}"
            )
        return base

    @staticmethod
    def _diag(*rows: str) -> str:
        """
        Wrap diagram rows in a code block.
        Each row should be ≤ 30 chars to fit all screen sizes.
        """
        return "```\n" + "\n".join(rows) + "\n```\n"

    @staticmethod
    def _wire_gauge(kva: float):
        if   kva <= 1:   return "2.5mm²", "10A",   "16mm"
        elif kva <= 2:   return "4.0mm²", "20A",   "20mm"
        elif kva <= 5:   return "6.0mm²", "32A",   "20mm"
        elif kva <= 10:  return "10mm²",  "63A",   "25mm"
        elif kva <= 20:  return "25mm²",  "100A",  "32mm"
        elif kva <= 30:  return "35mm²",  "125A",  "40mm"
        elif kva <= 50:  return "50mm²",  "200A",  "40mm"
        elif kva <= 100: return "95mm²",  "400A",  "63mm"
        else:            return "185mm²", "630A",  "75mm"

    @staticmethod
    def _sku_for_kva(kva: float, phase: str = "single") -> str:
        """Return the best-matching shop SKU for a given kVA + phase."""
        is_3ph = phase.lower() not in ("single", "1", "1phase")
        if kva <= 2:    return "STAB-2KVA"
        elif kva <= 5:  return "STAB-5KVA"
        elif kva <= 10: return "STAB-10KVA-3PH" if is_3ph else "STAB-10KVA-1PH"
        elif kva <= 15: return "STAB-15KVA-3PH" if is_3ph else "STAB-15KVA-1PH"
        elif kva <= 20: return "STAB-20KVA-1PH"
        elif kva <= 30: return "STAB-30KVA-3PH" if is_3ph else "STAB-30KVA-1PH"
        else:           return "STAB-50KVA-3PH"

    # ════════════════════════════════════════════════════════════════════════
    # 1. RESIDENTIAL WIRING DIAGRAM
    # ════════════════════════════════════════════════════════════════════════
    @staticmethod
    def generate_residential_schematic(kva: float = 2.0) -> str:
        sku = SchematicGenerator._sku_for_kva(kva, "single")
        p   = SchematicGenerator.get_current_prices(sku)
        R   = SchematicGenerator

        if kva <= 1:
            stab = "1kVA AVS"; br = "10A DP";  wire = "2.5mm²"
            spd  = "PlugIn SPD"; spd_note = "plug into wall socket"
        elif kva <= 2:
            stab = "2kVA AVS"; br = "20A DP";  wire = "4.0mm²"
            spd  = "DIN SPD";  spd_note = "inside consumer unit"
        elif kva <= 5:
            stab = "5kVA AVS"; br = "32A DP";  wire = "6.0mm²"
            spd  = "T2 SPD";   spd_note = "inside consumer unit"
        else:
            wire, br, _ = R._wire_gauge(kva)
            stab = f"{kva:.0f}kVA AVS"; spd = "T2 SPD"; spd_note = "inside consumer unit"

        r1   = R._row("METER", "DB/MCB")
        r2   = R._row(spd[:6], stab[:6])
        r3   = R._row("TV/AV", "FRIDGE")
        r4   = R._row("SOCKETS", "AC/Fan")

        diag = (
            "```\n"
            f"{r1}\n"
            "  ↓\n"
            f"{r2}\n"
            "  ↓ (to loads)\n"
            f"{r3}\n"
            f"{r4}\n"
            "```\n"
        )

        stock_note = ""
        if p.get("item_retail_ngn"):
            s_icon = STOCK_LABELS.get(p.get("item_stock","in_stock"), ("❓",""))[0]
            stock_note = (
                f"\n💡 *Shop price for {p['item_name']}:*\n"
                f"  🛒 ₦{p['item_retail_ngn']:,.0f} retail {s_icon}\n"
                f"  `/invoice {sku} 1` to generate checkout invoice\n"
            )

        return (
            R._hdr(f"Residential — {kva:.0f}kVA Home Wiring",
                   f"Generated {p['timestamp']} WAT | ₦{p['fx_rate']:,.0f}/$") +
            "\n📐 *BLOCK DIAGRAM*\n" + diag +
            "🔑 *KEY*\n"
            f"  METER   = Prepaid kWh meter\n"
            f"  DB/MCB  = Consumer unit ({br} MCB)\n"
            f"  spd= 20kA surge suppressor ({spd_note})\n"
            f"  stab= Voltage stabilizer — 140–260V in → 220V out\n\n"
            "🔧 *SPECS*\n" +
            R._specs([
                ("Wire",    wire + " (L + N + PE)"),
                ("Breaker", br + " MCB"),
                ("Earth",   "10mm² G/Y → earth rod"),
                ("SPD",     spd_note),
            ]) +
            "\n\n🔌 *INSTALLATION STEPS*\n" +
            R._steps([
                "Turn OFF main switch at meter — verify 0V",
                "Fit SPD: L→L, N→N, PE→Earth bar",
                "Wire stabilizer INPUT from DB output",
                "Wire stabilizer OUTPUT to load circuits",
                "Restore power — verify 220V ±5% at output",
                "Confirm SPD indicator LED is 🟢 GREEN",
            ]) +
            "\n\n" + R._warns([
                "Earth MUST be connected — SPD is useless without it",
                "Total appliance watts must not exceed stabilizer rating",
                "3-second startup delay on power-up is normal",
                "Never plug the stabilizer into its own output",
            ]) +
            stock_note +
            "\n\n" + R._mkt(p) + "\n"
        )

    # ════════════════════════════════════════════════════════════════════════
    # 2. VOLTAGE REGULATOR / STABILIZER WIRING
    # ════════════════════════════════════════════════════════════════════════
    @staticmethod
    def generate_regulator_schematic(kva: float, phase: str = "single",
                                     with_surge: bool = True,
                                     with_bypass: bool = False) -> str:
        sku  = SchematicGenerator._sku_for_kva(kva, phase)
        p    = SchematicGenerator.get_current_prices(sku)
        R    = SchematicGenerator
        wire, breaker, conduit = R._wire_gauge(kva)
        is_3ph = phase.lower() not in ("single", "1", "1phase")

        if is_3ph:
            ph_lbl  = "3Ø+N+PE"
            volt    = "380–415V L-L"
            poles   = "4P"
            reg_lbl = f"{kva:.0f}kVA 3Ø"
            warns   = [
                "Verify phase rotation (L1-L2-L3) BEFORE energising",
                "Phase current imbalance must stay within 15%",
                "Bond neutral to earth at MAIN panel ONLY — never at sub-DB",
            ]
        else:
            ph_lbl  = "1Ø+N+PE"
            volt    = "220–240V L-N"
            poles   = "2P"
            reg_lbl = f"{kva:.0f}kVA 1Ø"
            warns   = [
                "Verify 0V at all terminals before wiring",
                "SPD lead lengths must be under 500mm",
                "SPD LED must be 🟢 GREEN after power-on",
            ]

        r1 = R._row("SUPPLY", breaker[:6])
        r2 = R._row("TYPE2SPD", reg_lbl[:6])
        r3 = R._blk("LOAD/DB")

        bypass_blk = ""
        if with_bypass:
            rb = R._vrow("SUPPLY", "BYPASS", "LOAD/DB")
            bypass_blk = (
                "\n*🔄 BYPASS (maintenance mode):*\n"
                "```\n"
                f"{rb}\n"
                "```\n"
                "_Close bypass BEFORE opening regulator isolator_\n"
            )

        diag = (
            "```\n"
            f"{r1}\n"
            "  ↓\n"
            f"{r2}\n"
            "  ↓\n"
            f"{r3}\n"
            "```\n"
        )

        # Live retail cost for this item
        cost_note = ""
        if p.get("item_retail_ngn"):
            s_icon = STOCK_LABELS.get(p.get("item_stock","in_stock"),("❓",""))[0]
            cost_note = (
                f"\n💡 *Closest shop match — {p['item_name']}:*\n"
                f"  SKU: `{sku}` {s_icon}\n"
                f"  🛒 Retail: ₦{p['item_retail_ngn']:,.0f}\n"
                f"  `/invoice {sku} 1` — checkout invoice\n"
                f"  `/shop {sku}` — full product details\n"
            )

        return (
            R._hdr(
                f"{'3-Phase' if is_3ph else 'Single Phase'} Stabilizer/AVS — {kva:.1f}kVA",
                f"Generated {p['timestamp']} WAT | ₦{p['fx_rate']:,.0f}/$"
            ) +
            "\n📐 *BLOCK DIAGRAM*\n" + diag +
            bypass_blk +
            "🔑 *KEY*\n"
            f"  SUPPLY   = {ph_lbl} mains ({volt})\n"
            f"  breaker = {poles}-pole MCCB main isolator\n"
            f"  TYPE2SPD = Type 2 SPD, 40kA, <25ns response\n"
            f"  reg_lbl[:7] = Servo AVS voltage stabilizer\n"
            f"  LOAD/DB  = Distribution board or direct load\n\n" +
            "🔧 *SPECS*\n" +
            R._specs([
                ("Phase",    ph_lbl + " — " + volt),
                ("Wire",     wire + " per phase"),
                ("Breaker",  breaker + " " + poles + "-pole MCCB"),
                ("Conduit",  conduit + " rigid steel"),
                ("Torque",   "2.5–3.0 Nm (1Ø) / 3.5–4.5 Nm (3Ø)"),
                ("Output",   "220V ±2% (1Ø) / 380V ±3% (3Ø)"),
            ]) +
            "\n\n🔌 *INSTALLATION STEPS*\n" +
            R._steps([
                "Turn OFF breaker — verify 0V (L-N, L-PE, N-PE)",
                "Mount stabilizer + SPD on DIN rail or panel",
                "Connect SPD: L→L, N→N, PE→Earth bar",
                "Wire stabilizer INPUT from SPD output",
                "Wire stabilizer OUTPUT to DB or load",
                "Restore power — verify output voltage under load",
                "Confirm output: 220V ±5% (1Ø) / 380V ±5% (3Ø)",
            ]) +
            "\n\n" + R._warns(warns) +
            cost_note +
            "\n\n" + R._mkt(p) + "\n"
        )

    # ════════════════════════════════════════════════════════════════════════
    # 3. SURGE PROTECTIVE DEVICE (SPD)
    # ════════════════════════════════════════════════════════════════════════
    @staticmethod
    def generate_surge_schematic(protection_level: str = "type2",
                                  phases: str = "single") -> str:
        p   = SchematicGenerator.get_current_prices()
        R   = SchematicGenerator
        lvl = protection_level.lower()

        if lvl in ("type1", "t1"):
            cap = "200kA"; resp = "<5ns"
            pos  = "Main service entrance (before meter)"
            desc = "Type 1 — direct lightning current"
            mcb  = "63A fuse"
        elif lvl in ("type1+2", "t1+2", "combined"):
            cap = "100kA"; resp = "<15ns"
            pos  = "Service entry + distribution board"
            desc = "Type 1+2 — combined entry & DB"
            mcb  = "40A MCB"
        elif lvl in ("residential", "res", "type3", "t3", "plug-in"):
            cap = "6kA"; resp = "<1ns"
            pos  = "Wall socket — point of use"
            desc = "Type 3 — residential plug-in suppressor"
            mcb  = "None required"
        else:
            cap = "40kA"; resp = "<25ns"
            pos  = "Distribution board (DB) DIN rail"
            desc = "Type 2 — standard distribution board"
            mcb  = "20A MCB"

        is_3ph = phases.lower() not in ("single", "1", "1phase")
        ph_str = "3Ø+N+PE" if is_3ph else "1Ø+N+PE"
        spd_lbl = protection_level.upper()[:7]

        r1 = R._row("SUPPLY", mcb[:6])
        r2 = R._row(spd_lbl[:6], "PROT DB")

        diag = (
            "```\n"
            f"{r1}\n"
            "  ↓\n"
            f"{r2}\n"
            "  └→ " + R._blk("EARTH") + "\n"
            "```\n"
        )

        return (
            R._hdr(f"SPD — {protection_level.upper()} ({ph_str})",
                   f"Generated {p['timestamp']} WAT | ₦{p['fx_rate']:,.0f}/$") +
            f"\n_{desc}_\n"
            f"_{pos}_\n\n"
            "📐 *BLOCK DIAGRAM*\n" + diag +
            "🔑 *KEY*\n"
            f"  SUPPLY   = {ph_str} incoming supply\n"
            f"  mcb[:7] = Backup MCB upstream of SPD\n"
            f"  spd_lbl = SPD ({cap} discharge, {resp} response)\n"
            f"  PROT DB  = Protected distribution board\n"
            f"  EARTH    = Earth bar → earth electrode (<1Ω)\n\n"
            "📊 *STATUS INDICATORS*\n"
            "  🟢 Green  = Protected and fully operational\n"
            "  🔴 Red    = SPD element failed — replace immediately\n"
            "  ⚫ Off     = No supply — check upstream MCB\n\n"
            "🔧 *SPECS*\n" +
            R._specs([
                ("Type",       protection_level.upper()),
                ("Discharge",  cap + " (8/20µs waveform)"),
                ("Response",   resp),
                ("Phase",      ph_str),
                ("Modes",      "L-N, L-PE, N-PE all protected"),
                ("Backup MCB", mcb),
                ("Wire",       "6mm² min — leads < 500mm each"),
                ("Standard",   "IEC 61643-11 / BS EN 61643-11"),
            ]) +
            "\n\n🔌 *INSTALLATION STEPS*\n" +
            R._steps([
                "Turn OFF main breaker — verify 0V at all terminals",
                "Fit backup MCB upstream of SPD on DIN rail",
                "Mount SPD on DIN rail: L→L, N→N, PE→Earth bar",
                "Keep ALL leads under 500mm to minimise inductance",
                "Restore power — verify SPD LED is 🟢 GREEN",
                "Label SPD with installation date for audit trail",
            ]) +
            "\n\n" + R._warns([
                "Earth connection is mandatory — no earth = no protection",
                "Never exceed 500mm lead length (L, N and PE to SPD)",
                "Replace IMMEDIATELY when LED turns 🔴 RED",
                "Always fit backup MCB in series upstream of SPD",
                "Type 1 must be installed by qualified electrician only",
            ]) +
            "\n\n" + R._mkt(p) + "\n"
        )

    # ════════════════════════════════════════════════════════════════════════
    # 4. SAFE DISCONNECT / LOTO PROCEDURE
    # ════════════════════════════════════════════════════════════════════════
    @staticmethod
    def generate_disconnect_procedure(equipment_type: str = "regulator") -> str:
        p   = SchematicGenerator.get_current_prices()
