    # ── /cart command — manage cart from text interface ────────────────────────
    def _cmd_cart(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """Manage shopping cart: /cart, /cart delivery [state], /cart clear, /cart checkout"""
        parts  = text.split()
        action = parts[1].lower() if len(parts) > 1 else 'view'

        if action == 'clear':
            self._save_cart(user_id, {})
            self.send_message(chat_id, "🗑 Cart cleared.")
            return

        if action == 'delivery':
            state = ' '.join(parts[2:]).strip()
            if not state:
                self.send_message(chat_id,
                    "Usage: `/cart delivery [state]`\nExample: `/cart delivery Kano`")
                return
            # Validate state
            logi = get_logistics_fee(state, 1)
            if not logi:
                self.send_message(chat_id,
                    f"*{state}* not recognised. Use `/shop zones` to see all states.")
                return
            cart = self._load_cart(user_id)
            cart['_delivery_state'] = logi['matched_state']
            self._save_cart(user_id, cart)
            self.send_message(chat_id,
                f"Delivery state set to *{logi['matched_state'].title()}*.\n"
                f"Zone: {logi['zone_label']} · ETA: {logi['days']}\n\n"
                f"_Use `/cart` to see updated total, or `/cart checkout` to pay._"
            )
            return

        if action == 'checkout':
            delivery_state = ' '.join(parts[2:]).strip()
            cart = self._load_cart(user_id)
            if not cart or all(k.startswith('_') for k in cart):
                self.send_message(chat_id,
                    "🛒 Your cart is empty.\nUse `/shop` to browse and add items.")
                return
            if not delivery_state:
                delivery_state = cart.get('_delivery_state', '')
            # Trigger same logic as callback checkout
            fake_update = {'callback_query': {
                'id': '0', 'from': {'id': user_id},
                'message': {'chat': {'id': chat_id}},
                'data': f'cart_checkout|{delivery_state}'
            }}
            self.handle_callback(fake_update)
            return

        # Default: view cart
        cart      = self._load_cart(user_id)
        del_state = cart.get('_delivery_state', '')
        text_out  = self._cart_summary_text(cart, del_state)
        keyboard  = self._cart_keyboard(cart, del_state)
        self.send_message(chat_id, text_out, reply_markup=keyboard)

    def _chunk_message(self, text: str, max_length: int) -> List[str]:
        """Split message into chunks"""
        if len(text) <= max_length:
            return [text]

        chunks = []
        current = ""
        paragraphs = text.split('\n\n')

        for para in paragraphs:
            if len(current) + len(para) + 2 <= max_length:
                current += para + '\n\n'
            else:
                if current:
                    chunks.append(current.strip())
                if len(para) > max_length:
                    while para:
                        chunk = para[:max_length]
                        chunks.append(chunk)
                        para = para[max_length:]
                else:
                    current = para + '\n\n'

        if current:
            chunks.append(current.strip())

        return chunks

    def get_updates(self, offset: int = 0, limit: int = 100) -> List[Dict]:
        """Get updates from Telegram"""
        try:
            payload = {'offset': offset, 'limit': limit, 'timeout': 30}
            response = requests.get(
                self.base_url + "getUpdates",
                json=payload,
                timeout=35
            )
            if response.json().get('ok'):
                return response.json().get('result', [])
            return []
        except Exception as e:
            logger.error(f"Error getting updates: {e}")
            return []

    def _is_premium(self, user_id: int) -> bool:
        """Return True if user is admin OR has a valid, unexpired premium subscription."""
        if admin_manager.is_admin(user_id):
            return True
        try:
            premium  = FirebaseManager.db_load('premium')
            user_key = str(user_id)
            if user_key in premium:
                user_data = premium[user_key]
                exp_str   = user_data.get('expiry') if isinstance(user_data, dict) else user_data
                queries_left = user_data.get('queries_left', 0) if isinstance(user_data, dict) else 0
                exp_date  = WAT.localize(datetime.strptime(exp_str, "%Y-%m-%d"))
                if datetime.now(WAT) <= exp_date:
                    return queries_left == "unlimited" or queries_left > 0
        except Exception:
            pass
        return False

    def _is_partner(self, user_id: int) -> bool:
        """Return True if user has an active partner plan (installer/safety inspection)."""
        if admin_manager.is_admin(user_id):
            return True
        try:
            premium  = FirebaseManager.db_load('premium')
            user_key = str(user_id)
            if user_key in premium:
                user_data = premium[user_key]
                if isinstance(user_data, dict):
                    plan = user_data.get('plan', '')
                    exp_str = user_data.get('expiry', '')
                    if plan == 'partner' and exp_str:
                        exp_date = WAT.localize(datetime.strptime(exp_str, "%Y-%m-%d"))
                        return datetime.now(WAT) <= exp_date
        except Exception:
            pass
        return False

