    def check_user_limit(self, user_id: int, is_private: bool,
                         command: str = '') -> Tuple[bool, str, int]:
        """Check user access.

        Rules:
          • Admins       — always allowed, unlimited.
          • Banned users — always blocked.
          • FREE_COMMANDS (/price, /shop, /invoice, /cart, /search, /compare,
                           /related, /pricehistory, /notify, /track, /flash,
                           /bulk, /start, /help, /subscribe, /status)
                         — always allowed, no counter, no premium needed.
          • All other commands — premium subscribers only.
            Free users who try a gated command get a subscribe prompt.
        """
        # ── Ban check (applies to everyone, even free commands) ───────────────
        is_banned, ban_reason = user_manager.is_banned(user_id)
        if is_banned:
            return False, f"🚫 Banned: {ban_reason}", 0

        # ── Admin bypass ──────────────────────────────────────────────────────
        if admin_manager.is_admin(user_id):
            return True, "👑 Admin", -1

        # ── Free commands — always open, never counted ────────────────────────
        cmd = command.split('@')[0].lower() if command else ''
        # Normalise: FREE_COMMANDS entries have a leading '/' but the dispatcher
        # strips it before calling check_user_limit — so add it back if missing.
        cmd_with_slash = cmd if cmd.startswith('/') else '/' + cmd
        if cmd_with_slash in FREE_COMMANDS:
            return True, "🆓 Free", -1

        # ── All other commands need premium ───────────────────────────────────
        premium  = FirebaseManager.db_load('premium')
        user_key = str(user_id)
        if user_key in premium:
            user_data    = premium[user_key]
            exp_str      = user_data.get('expiry') if isinstance(user_data, dict) else user_data
            queries_left = user_data.get('queries_left', 0) if isinstance(user_data, dict) else 0
            try:
                exp_date = WAT.localize(datetime.strptime(exp_str, "%Y-%m-%d"))
                if datetime.now(WAT) <= exp_date:
                    if queries_left == "unlimited" or queries_left > 0:
                        return True, f"Premium ({queries_left} left)", 9999
            except Exception:
                pass

        # Not premium — block with friendly upsell
        return (False,
                f"*Premium required*\n\n"
                f"This command is for premium subscribers.\n\n"
                f"*Free forever (no login needed):*\n"
                f"  🏪 /shop · /search · /compare · /related · /pricehistory\n"
                f"  💰 /price · /taxes · /oil\n"
                f"  🧾 /invoice · /cart · /track\n"
                f"  🔔 /notify · /flash · /bulk\n\n"
                f"*Premium unlocks:*\n"
                f"  📊 /report · /analysis · /global · /stocks · /cycle\n"
                f"  🧮 /project · /trade · /dict · /alert\n"
                f"  📐 /schematic — real-time wiring diagrams on every shop item\n\n"
                f"*To unlock all commands:*\n"
                f"  `/subscribe` — plans from ₦500/day\n"
                f"  Pay → send screenshot to {SUPPORT_HANDLE}\n\n"
                f"_Activated within 15 minutes._",
                0)


    def _check_command_lock(self, command: str, user_id: int) -> Tuple[bool, Optional[str]]:
        """Check if command is locked"""
        if admin_manager.is_admin(user_id):
            return False, None
        return command_lock_manager.is_locked(command)

