    def _load_verified_badges(self) -> dict:
        try:
            if os.path.exists(VERIFIED_BADGES_FILE):
                with open(VERIFIED_BADGES_FILE, 'r', encoding='utf-8') as f:
                    return json.load(f)
        except Exception:
            pass
        return {}

    def _save_verified_badges(self, data: dict):
        try:
            tmp = VERIFIED_BADGES_FILE + '.tmp'
            with open(tmp, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2)
            os.replace(tmp, VERIFIED_BADGES_FILE)
        except Exception as e:
            logger.error(f'_save_verified_badges error: {e}')

    def _get_installer_avg_rating(self, installer_id: str) -> tuple:
        """Return (avg_rating, review_count) for an installer."""
        reviews = self._load_reviews()
        entries = reviews.get(installer_id, [])
        if not entries:
            return (0.0, 0)
        ratings = [r.get('rating', 0) for r in entries if r.get('rating')]
        return (round(sum(ratings) / len(ratings), 1), len(entries)) if ratings else (0.0, 0)

    def _stars(self, rating: float) -> str:
        """Convert numeric rating to star emoji string."""
        full  = int(rating)
        half  = 1 if (rating - full) >= 0.5 else 0
        empty = 5 - full - half
        return '★' * full + ('½' if half else '') + '☆' * empty

    def _get_verified_level(self, user_id: int) -> dict:
        """Return verification record for a user or empty dict."""
        badges = self._load_verified_badges()
        return badges.get(str(user_id), {})

    def _verified_badge_label(self, user_id: int) -> str:
        """Return a rich verification badge label for display."""
        v = self._get_verified_level(user_id)
        if not v:
            return ''
        level = v.get('level', 'basic')
        labels = {
            'basic':      '✅ ID Verified',
            'certified':  '🏅 Certified Technician',
            'expert':     '⭐ Expert Verified',
            'partner':    '💎 Partner Verified',
        }
        certs = v.get('certifications', [])
        label = labels.get(level, '✅ Verified')
        if certs:
            label += f"  |  Certs: {', '.join(certs)}"
        return label

    def _get_availability_label(self, user_id: int) -> str:
        """Return availability label for display in browse listings."""
        avail = self._load_availability()
        status = avail.get(str(user_id), {}).get('status', 'unknown')
        map_ = {
            'available':  '🟢 Available',
            'busy':       '🟡 Busy',
            'unavailable':'🔴 Unavailable',
            'unknown':    '⚪ Status Unknown',
        }
        return map_.get(status, '⚪ Unknown')

    def _cmd_installer_profile(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/profile [id|iVolt_ID] — View a full installer/safety inspector profile."""
        parts = text.strip().split(None, 2)
        installers = self._load_installers()

        # Determine whose profile to show
        if len(parts) > 1:
            target_key = parts[1].strip()
            # Support iVolt public IDs
            if target_key.upper().startswith('IVT-'):
                record = _resolve_public_id(target_key)
                if not record:
                    self.send_message(chat_id, f"No profile found for ID `{target_key}`.")
                    return
                target_uid = str(record['user_id'])
            else:
                target_uid = target_key
        else:
            target_uid = str(user_id)

        entry = installers.get(target_uid)
        if not entry:
            self.send_message(chat_id,
                "*Profile Not Found*\n\n"
                "No installer or safety inspector listing found for that ID.\n\n"
                "Register: `/installer register` or `/safety register`")
            return

        pid       = _get_or_create_marketplace_id(int(target_uid), entry.get('type', 'installer'))
        avg, cnt  = self._get_installer_avg_rating(target_uid)
        stars_str = self._stars(avg) if avg else 'No ratings yet'
        vbadge    = self._verified_badge_label(int(target_uid))
        avail_lbl = self._get_availability_label(int(target_uid))
        is_partner_flag = self._is_partner(int(target_uid))

        stype     = entry.get('type', 'installer').title()
        rate_key  = 'rate_per_day' if entry.get('type') == 'installer' else 'rate_per_inspection'
        rate_lbl  = 'Daily Rate' if entry.get('type') == 'installer' else 'Inspection Fee'

        # Past jobs (from completed escrows)
        escrows   = self._load_escrow() if hasattr(self, '_load_escrow') else {}
        past_jobs = [e for e in escrows.values()
                     if str(e.get('partner_id')) == target_uid and e.get('status') == 'released']
        jobs_count = len(past_jobs)
        last_job   = max((e.get('updated_at', '') for e in past_jobs), default=None)

        # Recent reviews
        reviews = self._load_reviews()
        recent_reviews = reviews.get(target_uid, [])[-3:]

        msg = (
            f"{'💎 ' if is_partner_flag else ''}*{entry.get('name', '—')}* — {stype}\n"
            f"iVolt ID: `{pid}`\n"
            f"{vbadge + chr(10) if vbadge else ''}"
            f"📍 {entry.get('state', '—')}"
            + (f", {entry.get('city')}" if entry.get('city') else '')
            + (f"\n🏠 {entry.get('address')}" if entry.get('address') else '') + "\n"
            f"📞 {entry.get('phone', '—')}\n"
            f"🔧 {entry.get('services', '—')}\n"
            f"💰 {rate_lbl}: NGN {entry.get(rate_key, 0):,.0f}\n"
            f"{avail_lbl}\n"
            f"⭐ Rating: {stars_str}  ({cnt} review{'s' if cnt != 1 else ''})\n"
            f"✅ Completed Jobs: {jobs_count}"
            + (f"\nLast job: {last_job[:10] if last_job else '—'}" if jobs_count else '') +
            f"\nMember since: {entry.get('registered_at', '—')[:10]}\n"
        )

        if recent_reviews:
            msg += "\n*Recent Reviews:*\n"
            for r in reversed(recent_reviews):
                msg += (
                    f"{self._stars(r.get('rating', 0))} — _{r.get('comment', '(no comment)')}_\n"
                    f"  — {r.get('reviewer_name', 'Customer')}  |  {r.get('date', '')[:10]}\n\n"
                )
        else:
            msg += "\n_No reviews yet._\n"

        msg += f"\nHire: `/escrow create {pid} <amount> <job description>`"

        keyboard = {'inline_keyboard': [
            [{'text': 'Hire via Escrow', 'callback_data': f'escrow_start_buyer'},
             {'text': 'Leave a Review', 'callback_data': f'review_start|{target_uid}'}],
        ]}
        self.send_message(chat_id, msg, reply_markup=keyboard)

    # ══════════════════════════════════════════════════════════════════════════
    # REVIEW & RATING SYSTEM
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_review(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/review <installer_id> <1-5> <comment> — Leave a review for a completed job.

        Usage:
          /review IVT-INS-AB12CD 5 Very professional, came on time and did a clean job
          /review <user_id> 4 Good work, minor delay
        """
        parts = text.strip().split(None, 3)
        if len(parts) < 4:
            self.send_message(chat_id,
                "*Leave a Review*\n\n"
                "Usage: `/review <installer_id> <rating 1-5> <your comment>`\n\n"
                "Example:\n"
                "`/review IVT-INS-AB12CD 5 Very professional, highly recommend`\n\n"
                "Rating guide:\n"
                "5 ⭐ — Excellent\n"
                "4 ⭐ — Good\n"
                "3 ⭐ — Average\n"
                "2 ⭐ — Below average\n"
                "1 ⭐ — Poor")
            return

        target_raw = parts[1]
        try:
            rating = int(parts[2])
            if not 1 <= rating <= 5:
                raise ValueError
        except ValueError:
            self.send_message(chat_id, "Rating must be a number from 1 to 5.")
            return
        comment = parts[3].strip()

        # Resolve installer
        installers = self._load_installers()
        if target_raw.upper().startswith('IVT-'):
            record = _resolve_public_id(target_raw)
            if not record:
                self.send_message(chat_id, f"Installer ID `{target_raw}` not found.")
                return
            target_uid = str(record['user_id'])
        else:
            target_uid = target_raw

        if target_uid not in installers:
            self.send_message(chat_id,
                f"No installer found with ID `{target_raw}`.\n"
                "Browse: `/installer` or `/safety`")
            return

        # Verify reviewer has a completed escrow with this installer
        escrows = self._load_escrow() if hasattr(self, '_load_escrow') else {}
        has_job = any(
            str(e.get('buyer_id')) == str(user_id)
            and str(e.get('partner_id')) == target_uid
            and e.get('status') == 'released'
            for e in escrows.values()
        )
        if not has_job and not admin_manager.is_admin(user_id):
            self.send_message(chat_id,
                "⚠️ You can only review an installer after a completed and released escrow job.\n\n"
                "Complete a job via `/escrow create`, then release it after the work is done.")
            return

        # Check: max 1 review per buyer per installer
        reviews = self._load_reviews()
        existing = reviews.get(target_uid, [])
        already  = any(str(r.get('reviewer_id')) == str(user_id) for r in existing)
        if already and not admin_manager.is_admin(user_id):
            self.send_message(chat_id,
                "You have already left a review for this installer.\n"
                "Contact support to update it: " + SUPPORT_HANDLE)
            return

        installer = installers[target_uid]
        pid       = _get_or_create_marketplace_id(int(target_uid), installer.get('type', 'installer'))
        now_str   = datetime.now(WAT).isoformat()

        new_review = {
            'reviewer_id':   user_id,
            'reviewer_name': f"Customer {str(user_id)[-4:]}",
            'rating':        rating,
            'comment':       comment,
            'date':          now_str,
        }
        existing.append(new_review)
        reviews[target_uid] = existing
        self._save_reviews(reviews)

        avg, cnt = self._get_installer_avg_rating(target_uid)

        self.send_message(chat_id,
            f"*Review Submitted* ✅\n\n"
            f"Installer: *{installer.get('name', '—')}*\n"
            f"Your rating: {self._stars(rating)} ({rating}/5)\n"
            f"Comment: _{comment}_\n\n"
            f"New average: {self._stars(avg)} ({avg}/5 from {cnt} review{'s' if cnt != 1 else ''})\n\n"
            f"View full profile: `/profile {pid}`")

        # Notify installer
        try:
            self.send_message(int(target_uid),
                f"⭐ *New Review Received*\n\n"
                f"Rating: {self._stars(rating)} ({rating}/5)\n"
                f"Comment: _{comment}_\n\n"
                f"New average: {self._stars(avg)} ({avg}/5 from {cnt} reviews)\n"
                f"View profile: `/profile`")
        except Exception:
            pass

    # ══════════════════════════════════════════════════════════════════════════
    # IN-BOT LEAD MANAGEMENT
    # ══════════════════════════════════════════════════════════════════════════

    def _create_lead(self, buyer_id: int, buyer_chat: int, partner_id: int,
                     job_desc: str, amount: float, escrow_id: str = ''):
        """Create a lead notification for a partner installer."""
        leads = self._load_leads()
        leads.setdefault(str(partner_id), [])
        lead_id = f"LED-{hashlib.md5(f'{buyer_id}{partner_id}{time.time()}'.encode()).hexdigest()[:8].upper()}"
        now_str = datetime.now(WAT).isoformat()
        lead = {
            'lead_id':   lead_id,
            'buyer_id':  buyer_id,
            'buyer_chat': buyer_chat,
            'job_desc':  job_desc,
            'amount':    amount,
            'escrow_id': escrow_id,
            'status':    'pending',   # pending | accepted | declined
            'created_at': now_str,
            'responded_at': None,
        }
        leads[str(partner_id)].append(lead)
        self._save_leads(leads)

        # Notify the installer
        try:
            keyboard = {'inline_keyboard': [[
                {'text': '✅ Accept Job',  'callback_data': f'lead_accept|{lead_id}|{partner_id}'},
                {'text': '❌ Decline',     'callback_data': f'lead_decline|{lead_id}|{partner_id}'},
            ]]}
            self.send_message(int(partner_id),
                f"🔔 *New Job Lead!*\n\n"
                f"Lead ID: `{lead_id}`\n"
                f"Job: {job_desc}\n"
                f"Budget: NGN {amount:,.0f}\n"
                f"Escrow: `{escrow_id}`\n\n"
                f"Respond below or use:\n"
                f"`/leads accept {lead_id}`\n"
                f"`/leads decline {lead_id}`",
                reply_markup=keyboard)
        except Exception:
            pass

        return lead_id

    def _cmd_leads(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/leads — View and respond to incoming job leads (installers only).

        Usage:
          /leads              — view all open leads
          /leads accept <id>  — accept a job lead
          /leads decline <id> [reason] — decline with optional reason
          /leads history      — view past accepted/declined leads
        """
        parts  = text.strip().split(None, 3)
        sub    = parts[1].lower() if len(parts) > 1 else 'view'
        leads  = self._load_leads()
        my_leads = leads.get(str(user_id), [])

        # Check this user is a registered installer/safety inspector
        installers = self._load_installers()
        if str(user_id) not in installers and not admin_manager.is_admin(user_id):
            self.send_message(chat_id,
                "*Lead Management*\n\n"
                "Only registered installers and safety inspectors can use /leads.\n\n"
                "Register: `/installer register` or `/safety register`")
            return

        # Leads are a Partner Plan benefit
        if not (self._is_partner(user_id) or admin_manager.is_admin(user_id)):
            self.send_message(chat_id,
                "*Lead Notifications — Partner Feature*\n\n"
                "Receiving job leads from buyers requires a *Partner Plan*.\n\n"
                "Partner Plan (₦30,000/year) includes:\n"
                "• Lead notifications from buyers\n"
                "• Active listing visible in marketplace\n"
                "• 💎 Partner badge & priority placement\n\n"
                "Upgrade now: `/subscribe partner`")
            return

        if sub == 'view' or sub == 'open':
            open_leads = [l for l in my_leads if l.get('status') == 'pending']
            if not open_leads:
                self.send_message(chat_id,
                    "*My Open Leads*\n\n"
                    "No open leads right now.\n\n"
                    "Make sure your listing is active and your availability is set to 🟢 Available.\n"
                    "`/available set available`")
                return
            msg = f"*My Open Leads* ({len(open_leads)} pending)\n\n"
            keyboard_rows = []
            for l in open_leads[-5:]:
                msg += (
                    f"🔔 Lead `{l['lead_id']}`\n"
                    f"Job: {l.get('job_desc', '—')}\n"
                    f"Budget: NGN {l.get('amount', 0):,.0f}\n"
                    f"Received: {l.get('created_at', '')[:10]}\n\n"
                )
                keyboard_rows.append([
                    {'text': f"✅ Accept {l['lead_id'][-6:]}",
                     'callback_data': f"lead_accept|{l['lead_id']}|{user_id}"},
                    {'text': f"❌ Decline {l['lead_id'][-6:]}",
                     'callback_data': f"lead_decline|{l['lead_id']}|{user_id}"},
                ])
            self.send_message(chat_id, msg, reply_markup={'inline_keyboard': keyboard_rows})

        elif sub == 'accept':
            lead_id = parts[2] if len(parts) > 2 else ''
            self._respond_to_lead(chat_id, user_id, lead_id, 'accepted', '')

        elif sub == 'decline':
            lead_id = parts[2] if len(parts) > 2 else ''
            reason  = parts[3] if len(parts) > 3 else 'No reason given'
            self._respond_to_lead(chat_id, user_id, lead_id, 'declined', reason)

        elif sub == 'history':
            done = [l for l in my_leads if l.get('status') in ('accepted', 'declined')]
            if not done:
                self.send_message(chat_id, "No lead history yet.")
                return
            msg = "*Lead History*\n\n"
            for l in reversed(done[-10:]):
                status_icon = '✅' if l.get('status') == 'accepted' else '❌'
                msg += (
                    f"{status_icon} `{l['lead_id']}` — {l.get('status', '').upper()}\n"
                    f"Job: {l.get('job_desc', '—')}\n"
                    f"Budget: NGN {l.get('amount', 0):,.0f}\n"
                    f"Date: {l.get('created_at', '')[:10]}\n\n"
                )
            self.send_message(chat_id, msg)

        else:
            self.send_message(chat_id,
                "*Lead Management*\n\n"
                "`/leads` — view open leads\n"
                "`/leads accept <lead_id>` — accept a job\n"
                "`/leads decline <lead_id> [reason]` — decline a job\n"
                "`/leads history` — view past leads")

    def _respond_to_lead(self, chat_id: int, user_id: int, lead_id: str,
                         response: str, reason: str):
        """Accept or decline a lead and notify the buyer."""
        leads = self._load_leads()
        my_leads = leads.get(str(user_id), [])
        target = next((l for l in my_leads if l.get('lead_id') == lead_id), None)

        if not target:
            self.send_message(chat_id,
                f"Lead `{lead_id}` not found.\n"
                "View open leads: `/leads`")
            return
        if target.get('status') != 'pending':
            self.send_message(chat_id,
                f"Lead `{lead_id}` has already been {target.get('status')}.")
            return

        target['status']       = response
        target['responded_at'] = datetime.now(WAT).isoformat()
        if reason:
            target['decline_reason'] = reason
        self._save_leads(leads)

        installers   = self._load_installers()
        installer    = installers.get(str(user_id), {})
        name         = installer.get('name', f"Installer {str(user_id)[-4:]}")
        icon         = '✅' if response == 'accepted' else '❌'
        response_str = response.upper()

        self.send_message(chat_id,
            f"{icon} Lead `{lead_id}` — *{response_str}*\n\n"
            f"Job: {target.get('job_desc', '—')}\n"
            + (f"Reason: {reason}\n" if reason and response == 'declined' else '') +
            f"\nView all leads: `/leads`")

        # Notify buyer
        try:
            buyer_msg = (
                f"{icon} *Job Lead Update*\n\n"
                f"Installer *{name}* has *{response_str}* your job request.\n"
                f"Job: {target.get('job_desc', '—')}\n"
                f"Budget: NGN {target.get('amount', 0):,.0f}\n"
            )
            if response == 'accepted':
                pid = _get_or_create_marketplace_id(user_id, installer.get('type', 'installer'))
                buyer_msg += (
                    f"\nProceed with escrow payment:\n"
                    f"`/escrow create {pid} {target.get('amount', 0):.0f} {target.get('job_desc', '')}`"
                )
            elif reason:
                buyer_msg += f"\nReason: {reason}\nBrowse other installers: `/installer`"
            self.send_message(int(target['buyer_id']), buyer_msg)
        except Exception:
            pass

    # ══════════════════════════════════════════════════════════════════════════
    # AVAILABILITY MANAGEMENT
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_availability(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/available — Set your availability status.

        Usage:
          /available                      — view current status
          /available set available        — mark as open for jobs
          /available set busy             — currently on a job, check back soon
          /available set unavailable      — not taking jobs
          /available set available until 2024-12-31  — available until a date
        """
        parts = text.strip().split(None, 4)
        sub   = parts[1].lower() if len(parts) > 1 else 'view'

        installers = self._load_installers()
        if str(user_id) not in installers and not admin_manager.is_admin(user_id):
            self.send_message(chat_id,
                "Only registered installers and safety inspectors can set availability.\n"
                "Register: `/installer register`")
            return

        avail = self._load_availability()

        if sub == 'view':
            status_data = avail.get(str(user_id), {})
            status      = status_data.get('status', 'not set')
            until       = status_data.get('until', '')
            updated     = status_data.get('updated_at', '')
            map_ = {
                'available':  '🟢 Available — open for new jobs',
                'busy':       '🟡 Busy — currently on a job',
                'unavailable':'🔴 Unavailable — not taking jobs',
                'not set':    '⚪ Not set',
            }
            self.send_message(chat_id,
                f"*My Availability*\n\n"
                f"Status: {map_.get(status, status)}\n"
                + (f"Until: {until}\n" if until else '') +
                (f"Last updated: {updated[:10]}\n" if updated else '') +
                f"\nChange: `/available set available|busy|unavailable`",
                reply_markup={'inline_keyboard': [
                    [{'text': '🟢 Set Available',   'callback_data': 'avail_set|available'},
                     {'text': '🟡 Set Busy',         'callback_data': 'avail_set|busy'}],
                    [{'text': '🔴 Set Unavailable', 'callback_data': 'avail_set|unavailable'}],
                ]})

        elif sub == 'set':
            new_status = parts[2].lower() if len(parts) > 2 else ''
            if new_status not in ('available', 'busy', 'unavailable'):
                self.send_message(chat_id,
                    "Valid statuses: `available`, `busy`, `unavailable`\n"
                    "Example: `/available set available`")
                return
            until   = parts[4] if len(parts) > 4 and parts[3].lower() == 'until' else ''
            now_str = datetime.now(WAT).isoformat()
            avail[str(user_id)] = {
                'status':     new_status,
                'until':      until,
                'updated_at': now_str,
            }
            self._save_availability(avail)
            icons = {'available': '🟢', 'busy': '🟡', 'unavailable': '🔴'}
            self.send_message(chat_id,
                f"{icons.get(new_status, '⚪')} Availability set to *{new_status.upper()}*\n"
                + (f"Until: {until}\n" if until else '') +
                f"\nBuyers browsing `/installer` will see your updated status.")
        else:
            self.send_message(chat_id,
                "*Availability*\n\n"
                "`/available` — view status\n"
                "`/available set available` — open for jobs\n"
                "`/available set busy` — on a job\n"
                "`/available set unavailable` — not taking jobs")

