    def _cmd_marketplace_ids(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/marketplace — Super admin: view all marketplace public IDs and real user IDs.

        Usage:
          /marketplace            — list all (paginated, up to 20)
          /marketplace installer  — filter by role
          /marketplace safety     — filter by role
          /marketplace buyer      — filter by role
          /marketplace all        — full list (all roles)
          /marketplace search <name_or_id> — search by name or partial ID
        """
        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "Admin only.")
            return

        parts       = text.strip().split(None, 2)
        filter_arg  = parts[1].lower() if len(parts) > 1 else 'all'
        search_term = parts[2].strip().lower() if len(parts) > 2 and filter_arg == 'search' else ''

        ids        = _load_marketplace_ids()
        installers = self._load_installers()

        if not ids:
            self.send_message(chat_id,
                "*Marketplace ID Registry*\n\n"
                "No IDs assigned yet.\n"
                "IDs are created when users first run /start, /status, /ping, "
                "or register as installer/safety inspector.")
            return

        # Build enriched records
        records = []
        for uid_str, rec in ids.items():
            role      = rec.get('role', 'buyer')
            public_id = rec.get('public_id', '—')
            uid       = rec.get('user_id', uid_str)
            created   = rec.get('created_at', '')[:10]

            # Get name from installer/safety registry if available
            entry = installers.get(str(uid), {})
            name  = entry.get('name', '—') if entry else '—'
            state = entry.get('state', '') if entry else ''
            phone = entry.get('phone', '') if entry else ''

            records.append({
                'uid':       uid,
                'public_id': public_id,
                'role':      role,
                'name':      name,
                'state':     state,
                'phone':     phone,
                'created':   created,
            })

        # Filter
        if filter_arg in ('installer', 'safety', 'buyer', 'admin'):
            records = [r for r in records if r['role'] == filter_arg]
        elif filter_arg == 'search' and search_term:
            records = [r for r in records
                       if search_term in r['name'].lower()
                       or search_term in r['public_id'].lower()
                       or search_term in str(r['uid'])]

        # Sort: installers & safety first, then buyers
        role_order = {'admin': 0, 'installer': 1, 'safety': 2, 'buyer': 3}
        records.sort(key=lambda r: (role_order.get(r['role'], 9), r.get('name', '')))

        total = len(records)
        if total == 0:
            self.send_message(chat_id, f"No records found for filter: `{filter_arg}`")
            return

        # Role summary first
        role_counts = {}
        for r in ids.values():
            role_counts[r.get('role','buyer')] = role_counts.get(r.get('role','buyer'), 0) + 1

        summary = (
            f"*Marketplace ID Registry*\n"
            f"Total: {len(ids)} | "
            + " | ".join(f"{k.title()}: {v}" for k, v in sorted(role_counts.items()))
            + "\n\n"
            f"Filter: `/marketplace installer|safety|buyer|all`\n"
            f"Search: `/marketplace search <name>`\n"
            f"Lookup: `/idlookup <public_id_or_user_id>`\n\n"
        )

        # Paginate — send up to 20 per message
        chunk_size = 20
        shown = records[:chunk_size]

        role_icons = {'installer': 'INS', 'safety': 'SAF', 'buyer': 'BYR', 'admin': 'ADM'}

        lines = []
        for r in shown:
            icon   = role_icons.get(r['role'], 'BYR')
            detail = f" | {r['state']}" if r['state'] else ''
            detail += f" | {r['phone']}" if r['phone'] else ''
            lines.append(
                f"[{icon}] `{r['public_id']}`\n"
                f"       User ID: `{r['uid']}` | {r['name']}{detail}\n"
                f"       Joined: {r['created']}"
            )

        body = "\n\n".join(lines)
        if total > chunk_size:
            body += f"\n\n_Showing {chunk_size} of {total}. Use `/marketplace search <name>` to find specific users._"

        self.send_message(chat_id, summary + body)

        # If more than 20, send separate filtered pages
        if total > chunk_size:
            for role in ['installer', 'safety', 'admin']:
                role_recs = [r for r in records if r['role'] == role]
                if not role_recs:
                    continue
                msg = f"*{role.title()}s ({len(role_recs)})*\n\n"
                for r in role_recs[:30]:
                    detail = f" | {r['state']}" if r['state'] else ''
                    detail += f" | {r['phone']}" if r['phone'] else ''
                    msg += (
                        f"`{r['public_id']}` — `{r['uid']}`\n"
                        f"{r['name']}{detail}\n\n"
                    )
                self.send_message(chat_id, msg)

    def _cmd_id_lookup(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/idlookup — Look up any user by public ID or user ID (super admin only).

        Usage:
          /idlookup IVT-INS-AB12CD    — look up by public ID
          /idlookup 987654321          — look up by user ID
        """
        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "Admin only.")
            return

        parts = text.strip().split()
        if len(parts) < 2:
            self.send_message(chat_id,
                "*ID Lookup*\n\n"
                "Usage:\n"
                "`/idlookup IVT-INS-AB12CD` — by public ID\n"
                "`/idlookup 987654321` — by Telegram user ID")
            return

        query = parts[1].strip()
        ids   = _load_marketplace_ids()
        installers = self._load_installers()

        record = None
        if query.upper().startswith('IVT-'):
            record = _resolve_public_id(query)
        else:
            try:
                uid_int = int(query)
                record  = ids.get(str(uid_int))
            except ValueError:
                pass

        if not record:
            self.send_message(chat_id,
                f"No record found for `{query}`.\n\n"
                f"They may not have interacted with the bot yet.\n"
                f"List all IDs: `/marketplace`")
            return

        uid     = record.get('user_id', '—')
        pub_id  = record.get('public_id', '—')
        role    = record.get('role', 'buyer')
        created = record.get('created_at', '')[:10]

        # Enrich from installer/safety registry
        entry   = installers.get(str(uid), {})
        name    = entry.get('name', '—')
        state   = entry.get('state', '—')
        phone   = entry.get('phone', '—')
        svc     = entry.get('services', '—')
        rate_key = 'rate_per_day' if role == 'installer' else 'rate_per_inspection'
        rate     = entry.get(rate_key, 0)
        active   = entry.get('active', False)
        verified = entry.get('verified', False)

        # Escrow history
        escrows    = self._load_escrow()
        as_buyer   = [e for e in escrows.values() if e.get('buyer_id') == uid]
        as_partner = [e for e in escrows.values() if e.get('partner_id') == uid]

        # Premium info
        premium  = db.load('premium')
        p_data   = premium.get(str(uid), {})
        plan     = p_data.get('plan', 'free').title() if isinstance(p_data, dict) else 'Legacy'
        expiry   = p_data.get('expiry', 'N/A') if isinstance(p_data, dict) else str(p_data)
        is_admin_u = admin_manager.is_admin(uid) if uid != '—' else False

        msg = (
            f"*ID Lookup Result*\n\n"
            f"*Public ID:* `{pub_id}`\n"
            f"*User ID:* `{uid}`\n"
            f"*Role:* {role.title()}\n"
            f"*Joined:* {created}\n"
            f"*Admin:* {'Yes' if is_admin_u else 'No'}\n\n"
            f"*Subscription:* {plan} | Expires: {expiry}\n\n"
        )

        if role in ('installer', 'safety'):
            msg += (
                f"*Marketplace Listing:*\n"
                f"  Name: {name}\n"
                f"  State: {state}\n"
                f"  Phone: {phone}\n"
                f"  Services: {svc}\n"
                f"  Rate: NGN {rate:,.0f}\n"
                f"  Active: {'Yes' if active else 'No'}\n"
                f"  Verified: {'Yes' if verified else 'No'}\n\n"
            )

        if as_buyer or as_partner:
            msg += f"*Escrow History:*\n"
            if as_buyer:
                msg += f"  As buyer: {len(as_buyer)} job(s)\n"
                active_b = [e for e in as_buyer if e.get('status') in ('pending_payment','active','pending_release','disputed')]
                if active_b:
                    msg += f"  Active: {len(active_b)}\n"
            if as_partner:
                msg += f"  As partner: {len(as_partner)} job(s)\n"
                active_p = [e for e in as_partner if e.get('status') in ('pending_payment','active','pending_release','disputed')]
                if active_p:
                    msg += f"  Active: {len(active_p)}\n"
            msg += "\n"

        msg += f"*Actions:*\n"
        if role in ('installer', 'safety'):
            msg += f"`/marketplace search {name.split()[0] if name != '—' else uid}` — find similar\n"
        msg += (
            f"`/activate {uid} <plan> <days>` — activate subscription\n"
            f"`/escrow all` — view all escrow records\n"
        )

        keyboard = {'inline_keyboard': [
            [{'text': f'Activate {pub_id}', 'callback_data': f'ping_activate|{uid}|{pub_id}'}],
            [{'text': 'View All IDs',       'callback_data': 'mktplace_all'},
             {'text': 'Ping Log',           'callback_data': 'ping_viewlog'}],
        ]}
        self.send_message(chat_id, msg, reply_markup=keyboard)

