            r = f"*💱 Live FX Dictionary — {len(SYMBOLS['FOREX'])} pairs*\n_{datetime.now(WAT).strftime('%Y-%m-%d %H:%M WAT')}_\n"
            for sym, cfg in SYMBOLS["FOREX"].items():
                base, quote = sym[:3], sym[3:]
                try:
                    live = market_engine.fetch_exchange_rate(base, quote)
                    if live and live.get("rate"):
                        rate_str  = f"*{live['rate']:,.4f}*"
                        src_str   = live.get("source", cfg["source"])
                        chg_str   = f" ({live.get('change_pct', 0):+.2f}%)" if "change_pct" in live else ""
                        qe        = "🟢"
                    else:
                        rate_str, src_str, chg_str, qe = f"~{cfg['fallback']}", cfg["source"], " (fallback)", "🟠"
                except Exception:
                    rate_str, src_str, chg_str, qe = f"~{cfg['fallback']}", cfg["source"], " (error)", "🔴"
                r += f"{qe} `{sym}` {base}/{quote}: {rate_str}{chg_str}\n   Source: {src_str}\n\n"
            r += f"_Status: {status}_"
            self.send_message(chat_id, r)
            return

