            r = f"*⚡ NERC Electricity Tariff Dictionary*\n_2024 Multi-Year Tariff Order | {datetime.now(WAT).strftime('%H:%M WAT')}_\n\n"
            r += "Used in `/project` ROI analysis to calculate annual energy savings.\n\n"
