    def _scrape_mercury_direct(self, url: str, fetch_product_pages: bool = True) -> list:
        """
        Dedicated scraper for mercurydirect.com.ng.
        Handles both:
          • /product-category/stabilizer/
          • /solar/  (custom WP page with WooCommerce product grid)

        Key differences from the generic scraper:
          1. Dual-img lazy-load: real image is in the SECOND <img> src, not data-src
          2. Sale prices: current price in <ins>, original in <del>
          3. Product detail pages scraped for spec table and 600px gallery image
          4. Descriptions and specs enriched from MERCURY_DESC_MAP / MERCURY_SPECS_MAP
          5. Weights from MERCURY_WEIGHT_MAP keyed by kVA/W in product name
          6. Category auto-detected from MERCURY_CATEGORY_MAP
          7. Source label set to 'Mercury Direct' (never 'scraped')
        """
        try:
            from bs4 import BeautifulSoup
        except ImportError:
            raise RuntimeError("beautifulsoup4 not installed — run: pip install beautifulsoup4 lxml")

        import re as _re

        HEADERS = {
            "User-Agent": "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
                          "(KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
            "Accept-Language": "en-US,en;q=0.9",
            "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
            "Referer": "https://mercurydirect.com.ng/",
        }

        def _clean_price(txt: str) -> float:
            digits = _re.sub(r'[^\d.]', '', str(txt).replace(',', ''))
            try:
                return float(digits)
            except Exception:
                return 0.0

        def _mercury_image(card) -> str:
            """
            Extract real image URL from Mercury's dual-img lazy-load pattern.
            Pattern: first <img> has data:image/svg placeholder as src,
                     second <img> (or same img with data-src) has the real URL.
            Also handles .webp URLs (keep as-is, Telegram supports webp).
            """
            imgs = card.select('img')
            real_url = ''
            for img in imgs:
                src = img.get('src', '')
                dsrc = img.get('data-src', '')
                # Skip SVG placeholders
                if src.startswith('data:image/svg'):
                    src = ''
                # Prefer data-src over src (lazy load)
                candidate = dsrc or src
                if candidate and not candidate.startswith('data:'):
                    real_url = candidate
                    break
            # If still empty, try srcset
            if not real_url:
                for img in imgs:
                    ss = img.get('srcset', '') or img.get('data-srcset', '')
                    if ss:
                        # Take last (highest res) entry from srcset
                        parts = [p.strip().split(' ')[0] for p in ss.split(',') if p.strip()]
                        if parts:
                            real_url = parts[-1]
                            break
            # Ensure absolute URL
            if real_url and real_url.startswith('//'):
                real_url = 'https:' + real_url
            return real_url

        def _mercury_weight(name: str) -> float:
            """Lookup weight from MERCURY_WEIGHT_MAP by kVA/W string in name."""
            n = name.lower()
            # Try direct map first
            for key, kg in self.MERCURY_WEIGHT_MAP.items():
                if key in n:
                    return float(kg)
            # Fallback: extract kVA number and estimate
            m = _re.search(r'(\d+\.?\d*)\s*k[vw]a?', n)
            if m:
                kva = float(m.group(1))
                return round(min(max(kva * 3.5, 5), 500), 1)
            m2 = _re.search(r'(\d+)\s*w(?:att)?s?\b', n)
            if m2:
                w = int(m2.group(1))
                return round(w * 0.06, 1)  # ~0.06 kg/W for panels
            return 20.0

        def _mercury_category(name: str) -> str:
            n = name.lower()
            for keyword, cat in self.MERCURY_CATEGORY_MAP.items():
                if keyword in n:
                    return cat
            return 'Solar & Inverters'

        def _mercury_sku(name: str, idx: int) -> str:
            """Generate a clean SKU from product name."""
            n = name.upper()
            # Stabilizers
            m = _re.search(r'(\d+\.?\d*)\s*KVA.*?(SINGLE|3.PHASE|THREE|3PH)', n)
            if m and any(x in n for x in ('STAB', 'STABILIZER', 'AVR', 'AVS', 'SERVO')):
                kva = m.group(1).replace('.', '')
                ph  = '3PH' if any(x in m.group(2) for x in ('3', 'THREE')) else '1PH'
                return f"STAB-{kva}KVA-{ph}"
            m2 = _re.search(r'(\d+\.?\d*)\s*KVA', n)
            if m2 and any(x in n for x in ('STAB', 'STABILIZER', 'AVR', 'AVS', 'SERVO')):
                return f"STAB-{m2.group(1).replace('.','')[:6]}KVA"
            # Inverters
            if any(x in n for x in ('INVERTER', 'HYBRID', 'SOLAR')):
                m3 = _re.search(r'(\d+\.?\d*)\s*KVA', n)
                if m3:
                    return f"INV-{m3.group(1).replace('.','')[:4]}KVA-HYBRID"
            # Panels
            if 'PANEL' in n or 'WATT' in n or _re.search(r'\d+W\b', n):
                mw = _re.search(r'(\d+)\s*W', n)
                if mw:
                    return f"SOLAR-{mw.group(1)}W-MONO"
            # Fallback
            slug = _re.sub(r'[^A-Z0-9]+', '-', n).strip('-')[:20]
            return f"MD-{slug}-{idx:02d}"

        def _fetch_product_detail(prod_url: str) -> dict:
            """
            Fetch a single product page and extract:
            - Full 600px gallery image URL
            - Description text from #tab-description
            - Spec table values
            Returns dict with keys: photo_url, description, specs
            """
            try:
                time.sleep(0.8)  # polite delay
                r = requests.get(prod_url, headers=HEADERS, timeout=20)
                r.raise_for_status()
                s = BeautifulSoup(r.text, 'lxml')

                # Gallery image — 600px version preferred over 300px thumbnail
                photo = ''
                gallery = s.select_one('div.woocommerce-product-gallery__image a')
                if gallery:
                    photo = gallery.get('href', '')
                if not photo:
                    gallery_img = s.select_one('div.woocommerce-product-gallery img')
                    if gallery_img:
                        photo = gallery_img.get('data-large_image', '') or \
                                gallery_img.get('src', '')
                if not photo or photo.startswith('data:'):
                    photo = ''

                # Description
                desc = ''
                desc_el = s.select_one('div#tab-description')
                if desc_el:
                    # Get first non-empty paragraph
                    for p in desc_el.select('p'):
                        txt = p.get_text(strip=True)
                        if txt and len(txt) > 30:
                            desc = txt[:250]
                            break

                # Spec table — woocommerce attributes or custom table
                specs_pairs = []
                tbl = (s.select_one('table.woocommerce-product-attributes')
                       or s.select_one('table.shop_attributes'))
                if tbl:
                    for row in tbl.select('tr')[:8]:
                        lbl = row.select_one('th') or row.select_one('td:first-child')
                        val = row.select_one('td:last-child')
                        if lbl and val:
                            l = lbl.get_text(strip=True)
                            v = val.get_text(separator=' ', strip=True)
                            if l and v and l.lower() not in ('', 'n/a'):
                                specs_pairs.append(f"{l}: {v}")
                specs = ' · '.join(specs_pairs[:5]) if specs_pairs else ''

                return {'photo_url': photo, 'description': desc, 'specs': specs}
            except Exception as e:
                logger.debug(f"[Mercury] product detail fetch failed {prod_url}: {e}")
                return {'photo_url': '', 'description': '', 'specs': ''}

        # ── Fetch the category/page ───────────────────────────────────────────
        try:
            resp = requests.get(url, headers=HEADERS, timeout=25)
            resp.raise_for_status()
        except Exception as e:
            raise RuntimeError(f"Mercury Direct unreachable: {e}")

        soup = BeautifulSoup(resp.text, 'lxml')
        products = []

        # ── Parse product grid (li.product — works for both /stabilizer/ and /solar/) ─
        cards = soup.select('li.product')
        if not cards:
            # /solar/ might use a different wrapper on some themes
            cards = soup.select('.products .product, .woocommerce ul.products li')

        seen_names = set()  # deduplicate (solar page has duplicates)

        for i, card in enumerate(cards):
            # Name
            name_el = (card.select_one('h2.woocommerce-loop-product__title')
                       or card.select_one('h2') or card.select_one('h3'))
            name = name_el.get_text(strip=True) if name_el else f"Mercury Product {i+1}"
            if not name or name in seen_names:
                continue
            seen_names.add(name)

            # Price — handle sale prices (ins/del tags)
            price = 0.0
            price_el = card.select_one('span.price')
            if price_el:
                # Sale: current price in <ins>
                ins_el = price_el.select_one('ins span.woocommerce-Price-amount')
                if ins_el:
                    price = _clean_price(ins_el.get_text())
                else:
                    amt_el = price_el.select_one('span.woocommerce-Price-amount')
                    if amt_el:
                        price = _clean_price(amt_el.get_text())
            if price == 0.0:
                # Fallback: any price text
                raw_p = card.select_one('.price, .amount')
                if raw_p:
                    price = _clean_price(raw_p.get_text())

            # Image — Mercury dual-img lazy-load pattern
            photo_url = _mercury_image(card)

            # Product URL
            link_el = (card.select_one('a.woocommerce-LoopProduct-link')
                       or card.select_one('a[href*="/product/"]')
                       or card.select_one('a'))
            prod_url = link_el.get('href', url) if link_el else url

            # Stock status — WooCommerce adds 'outofstock' class to li
            is_oos = 'outofstock' in card.get('class', [])
            stock_status = 'out_of_stock' if is_oos else 'in_stock'

            # Weight from name
            weight_kg = _mercury_weight(name)

            # Category
            category = _mercury_category(name)

            # Generate SKU
            sku_hint = _mercury_sku(name, i)

            # SCRAPER POLICY: Only pull name and price.
            # Description, specs, weight, and photos must be added manually
            # by the super admin via /shop edititem or photo upload.
            # Existing admin-set meta overrides are preserved by _apply_item_meta.

            products.append({
                'name':         name,
                'price_ngn':    price,
                'photo_url':    '',         # Admin uploads photo manually
                'source_url':   prod_url,
                'description':  '',         # Admin sets description manually
                'specs':        '',         # Admin sets specs manually
                'sku_hint':     sku_hint,
                'weight_kg':    weight_kg,  # Estimated from name — admin can override
                'stock_status': stock_status,
                'category':     category,
                'source_label': 'Mercury Direct',
            })

        return products

    def _is_mercury_url(self, url: str) -> bool:
        """Return True if URL is from mercurydirect.com.ng."""
        return 'mercurydirect.com.ng' in url

    # URL SCRAPER — WooCommerce, Shopify, and generic sites
    # ══════════════════════════════════════════════════════════════════════════
    def _scrape_shop_url(self, url: str) -> list:
        """
        Scrape a product category or product page.
        Routes Mercury Direct URLs to the dedicated _scrape_mercury_direct() scraper.
        For all other sites: WooCommerce, Shopify, generic schema.org.
        """
        # ── Mercury Direct — use dedicated scraper ────────────────────────────
        if self._is_mercury_url(url):
            return self._scrape_mercury_direct(url)

        try:
            from bs4 import BeautifulSoup
        except ImportError:
            raise RuntimeError("beautifulsoup4 not installed — run: pip install beautifulsoup4 lxml")

        import re as _re

        headers = {
            "User-Agent": "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
                          "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
            "Accept-Language": "en-US,en;q=0.9",
            "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
        }

        def _clean_price(txt: str) -> float:
            digits = _re.sub(r'[^\d.]', '', str(txt).replace(',', ''))
            try:
                return float(digits)
            except Exception:
                return 0.0

        def _slug_to_sku(name: str, idx: int) -> str:
            slug = _re.sub(r'[^a-z0-9]+', '-', name.lower()).strip('-')[:20].upper()
            return f"SCRAPED-{slug}-{idx:02d}"

        def _auto_category(name: str) -> str:
            n = name.lower()
            if any(x in n for x in ('solar', 'pv', 'panel')):              return 'Solar'
            if any(x in n for x in ('inverter', 'invertor')):              return 'Inverters'
            if any(x in n for x in ('battery', 'lithium', 'agm', 'gel')): return 'Batteries'
            if any(x in n for x in ('stabilizer', 'avs', 'avr', 'servo', 'stab')): return 'Voltage Stabilizers'
            if any(x in n for x in ('surge', 'spd', 'suppressor')):       return 'Surge Protection'
            if any(x in n for x in ('transformer', 'transf')):             return 'Transformers'
            if any(x in n for x in ('ups', 'uninterruptible')):            return 'UPS'
            return 'Additional Products'

        def _guess_weight(name: str) -> float:
            """Rough weight estimate from kVA/kW in product name."""
            m = _re.search(r'(\d+\.?\d*)\s*k[vw]a?', name.lower())
            if m:
                kva = float(m.group(1))
                return round(min(max(kva * 3.5, 5), 500), 1)
            return 20.0

        resp = requests.get(url, headers=headers, timeout=25)
        resp.raise_for_status()

        # ── Shopify products JSON API (/products.json or /products/slug.json) ──
        if '/products.json' in url or (url.endswith('.json') and '/products/' in url):
            try:
                jdata = resp.json()
                raw_products = jdata.get('products', [jdata.get('product', {})])
                products = []
                for i, prod in enumerate(raw_products):
                    if not prod:
                        continue
                    name      = prod.get('title', f'Product {i+1}')
                    variant   = (prod.get('variants') or [{}])[0]
                    price     = _clean_price(variant.get('price', '0'))
                    images    = prod.get('images', [])
                    img_url   = images[0].get('src', '') if images else ''
                    desc_html = prod.get('body_html', '')
                    soup_d    = BeautifulSoup(desc_html, 'lxml')
                    desc      = soup_d.get_text(separator=' ', strip=True)[:200]
                    stock_ok  = variant.get('available', True)
                    handle    = prod.get('handle', '')
                    prod_url  = f"{url.split('/products')[0]}/products/{handle}" if handle else url
                    products.append({
                        'name':         name,
                        'price_ngn':    price,
                        'photo_url':    '',  # Admin uploads manually
                        'source_url':   prod_url,
                        'description':  '',  # Admin sets manually
                        'specs':        f"SKU: {variant.get('sku','—')} · Vendor: {prod.get('vendor','')}",
                        'sku_hint':     _slug_to_sku(name, i),
                        'weight_kg':    _guess_weight(name),
                        'stock_status': 'in_stock' if stock_ok else 'out_of_stock',
                        'category':     _auto_category(name),
                    })
                if products:
                    return products
            except Exception:
                pass  # fall through to HTML parsing

        soup = BeautifulSoup(resp.text, 'lxml')
        products = []

        # ── Shopify collection page (/collections/*) ──────────────────────────
        # Shopify embeds product JSON in a <script> block or uses product-card divs
        shopify_json_block = None
        for script in soup.find_all('script', type='application/json'):
            txt = script.string or ''
            if '"products"' in txt or '"price"' in txt:
                try:
                    shopify_json_block = json.loads(txt)
                    break
                except Exception:
                    pass

        if shopify_json_block and 'products' in shopify_json_block:
            raw = shopify_json_block['products']
            for i, prod in enumerate(raw):
                name    = prod.get('title', f'Product {i+1}')
                variant = (prod.get('variants') or [{}])[0]
                price   = _clean_price(str(variant.get('price', 0))) / 100  # Shopify prices in cents
                images  = prod.get('images', [])
                img_url = images[0].get('src', '') if images else ''
                handle  = prod.get('handle', '')
                base    = resp.url.split('/collections')[0] if '/collections' in resp.url else resp.url
                prod_url = f"{base}/products/{handle}" if handle else url
                products.append({
                    'name':         name,
                    'price_ngn':    price if price > 100 else price * 1640,  # convert USD→NGN if looks like USD
                    'photo_url':    '',  # Admin uploads manually
                    'source_url':   prod_url,
                    'description':  '',
                    'specs':        f"Vendor: {prod.get('vendor','')}",
                    'sku_hint':     _slug_to_sku(name, i),
                    'weight_kg':    _guess_weight(name),
                    'stock_status': 'in_stock' if variant.get('available', True) else 'out_of_stock',
                    'category':     _auto_category(name),
                })
            if products:
                return products

        # Shopify product-card HTML (collection grid)
        shopify_cards = soup.select('.product-card, .card--product, [data-product-id]')
        if shopify_cards:
            for i, card in enumerate(shopify_cards):
                name_el  = (card.select_one('.card__heading') or card.select_one('.product-card__title')
                            or card.select_one('h3') or card.select_one('h2'))
                price_el = (card.select_one('.price__regular .price-item')
                            or card.select_one('.price') or card.select_one('[data-price]'))
                img_el   = card.select_one('img')
                link_el  = card.select_one('a[href*="/products/"]')
                name     = name_el.get_text(strip=True) if name_el else f'Product {i+1}'
                price_t  = price_el.get_text(strip=True) if price_el else ''
                img_url  = (img_el.get('data-src') or img_el.get('src', '')) if img_el else ''
                href     = link_el.get('href', '') if link_el else ''
                prod_url = (f"https://{resp.url.split('/')[2]}{href}" if href.startswith('/') else href) or url
                price    = _clean_price(price_t)
                if not name:
                    continue
                products.append({
                    'name':         name,
                    'price_ngn':    price,
                    'photo_url':    '',  # Admin uploads manually
                    'source_url':   prod_url,
                    'description':  '',
                    'specs':        'See product page',
                    'sku_hint':     _slug_to_sku(name, i),
                    'weight_kg':    _guess_weight(name),
                    'stock_status': 'in_stock',
                    'category':     _auto_category(name),
                })
            if products:
                return products

        # ── WooCommerce category page (li.product grid) ───────────────────────
        cards = soup.select('li.product')
        if cards:
            for i, card in enumerate(cards):
                name_el  = (card.select_one('h2.woocommerce-loop-product__title')
                            or card.select_one('h2') or card.select_one('h3'))
                price_el = (card.select_one('span.woocommerce-Price-amount bdi')
                            or card.select_one('span.woocommerce-Price-amount')
                            or card.select_one('.price'))
                img_el   = card.select_one('img')
                link_el  = (card.select_one('a.woocommerce-LoopProduct-link') or card.select_one('a'))
                # Stock: WooCommerce adds class 'outofstock' to the <li>
                is_oos   = 'outofstock' in card.get('class', [])

                name     = name_el.get_text(strip=True)  if name_el  else f"Product {i+1}"
                price_t  = price_el.get_text(strip=True) if price_el else ''
                img_url  = (img_el.get('data-src') or img_el.get('src', '')) if img_el else ''
                prod_url = link_el.get('href', url) if link_el else url
                price    = _clean_price(price_t)

                if not name:
                    continue
                products.append({
                    'name':         name,
                    'price_ngn':    price,
                    'photo_url':    '',  # Admin uploads manually
                    'source_url':   prod_url,
                    'description':  '',
                    'specs':        'See product page',
                    'sku_hint':     _slug_to_sku(name, i),
                    'weight_kg':    _guess_weight(name),
                    'stock_status': 'out_of_stock' if is_oos else 'in_stock',
                    'category':     _auto_category(name),
                })
            return products

        # ── WooCommerce single product page ───────────────────────────────────
        name_el  = (soup.select_one('h1.product_title') or soup.select_one('h1.entry-title')
                    or soup.select_one('h1'))
        price_el = (soup.select_one('p.price span.woocommerce-Price-amount bdi')
                    or soup.select_one('span.woocommerce-Price-amount'))
        img_el   = (soup.select_one('div.woocommerce-product-gallery img')
                    or soup.select_one('img.wp-post-image'))
        desc_el  = (soup.select_one('div.woocommerce-product-details__short-description')
                    or soup.select_one('div#tab-description p'))
        specs_el = soup.select_one('table.woocommerce-product-attributes')
        weight_el = soup.select_one('.woocommerce-product-attributes-item--weight .woocommerce-product-attributes-item__value')
        oos_el   = soup.select_one('.out-of-stock, .stock.out-of-stock')

        name    = name_el.get_text(strip=True)  if name_el  else ''
        price_t = price_el.get_text(strip=True) if price_el else ''
        img_url = (img_el.get('data-src') or img_el.get('src', '')) if img_el else ''
        desc    = desc_el.get_text(strip=True)[:200] if desc_el else ''
        price   = _clean_price(price_t)
        weight  = _clean_price(weight_el.get_text()) if weight_el else _guess_weight(name)
        # Parse attribute table for specs
        specs_txt = 'See product page'
        if specs_el:
            rows = specs_el.select('tr')
            spec_pairs = []
            for row in rows[:5]:
                label = row.select_one('th')
                val   = row.select_one('td')
                if label and val:
                    spec_pairs.append(f"{label.get_text(strip=True)}: {val.get_text(strip=True)}")
            if spec_pairs:
                specs_txt = ' · '.join(spec_pairs)

        if name:
            products.append({
                'name':         name,
                'price_ngn':    price,
                'photo_url':    '',  # Admin uploads manually
                'source_url':   url,
                'description':  '',  # Admin sets manually
                'specs':        '',  # Admin sets manually
                'sku_hint':     _slug_to_sku(name, 0),
                'weight_kg':    weight,
                'stock_status': 'out_of_stock' if oos_el else 'in_stock',
                'category':     _auto_category(name),
            })
            return products

        # ── Generic fallback — schema.org Product + og: meta tags ─────────────
        # Try schema.org JSON-LD first
        for script in soup.find_all('script', type='application/ld+json'):
            try:
                ld = json.loads(script.string or '{}')
                if isinstance(ld, list):
                    ld = next((x for x in ld if x.get('@type') == 'Product'), {})
                if ld.get('@type') == 'Product':
                    offers = ld.get('offers', {})
                    if isinstance(offers, list):
                        offers = offers[0]
                    price   = _clean_price(str(offers.get('price', '0')))
                    curr    = offers.get('priceCurrency', 'NGN')
                    if curr == 'USD' and price < 100000:
                        price *= 1640  # rough USD→NGN
                    images = ld.get('image', [])
                    img_url = (images[0] if isinstance(images, list) else images) or ''
                    name    = ld.get('name', '')
                    desc    = ld.get('description', '')[:200]
                    sku_raw = ld.get('sku', '')
                    avail   = offers.get('availability', '')
                    stock   = 'out_of_stock' if 'OutOfStock' in avail else 'in_stock'
                    if name:
                        products.append({
                            'name':         name,
                            'price_ngn':    price,
                            'photo_url':    '',  # Admin uploads manually
                            'source_url':   url,
                            'description':  '',  # Admin sets manually
                            'specs':        f"SKU: {sku_raw}" if sku_raw else 'See product page',
                            'sku_hint':     sku_raw.upper()[:20] if sku_raw else _slug_to_sku(name, 0),
                            'weight_kg':    _guess_weight(name),
                            'stock_status': stock,
                            'category':     _auto_category(name),
                        })
                        return products
            except Exception:
                pass

        # og: meta tag last-resort fallback
        og_title = soup.find('meta', property='og:title')
        og_img   = soup.find('meta', property='og:image')
        og_price = (soup.find('meta', property='product:price:amount')
                    or soup.find('meta', {'name': 'twitter:data1'}))
        if og_title:
            pname = og_title.get('content', 'Product')
            products.append({
                'name':         pname,
                'price_ngn':    _clean_price(og_price.get('content', '0') if og_price else '0'),
                'photo_url':    og_img.get('content', '') if og_img else '',
                'source_url':   url,
                'description':  '',
                'specs':        'See product page',
                'sku_hint':     _slug_to_sku(pname, 0),
                'weight_kg':    _guess_weight(pname),
                'stock_status': 'in_stock',
                'category':     _auto_category(pname),
            })

        return products

    def _merge_scraped_to_catalogue(self, scraped: list, source_url: str) -> tuple:
        """
        Merge a list of scraped products into NIGERIA_SHOP_CATALOGUE dynamically.
        New items are added; existing items (matched by name similarity) have their
        price and photo updated.
        Returns (added_count, updated_count, skipped_count).
        """
        import re as _re

        # Load any previously scraped items from disk
        scraped_store = {}
        if os.path.exists(SHOP_SCRAPED_FILE):
            try:
                with open(SHOP_SCRAPED_FILE, 'r', encoding='utf-8') as f:
                    scraped_store = json.load(f)
            except Exception:
                pass

        added = updated = skipped = 0
        catalogue_items = {
            p['sku']: p
            for cat in NIGERIA_SHOP_CATALOGUE.values()
            for p in cat
        }

        def _name_key(n: str) -> str:
            return _re.sub(r'[^a-z0-9]', '', n.lower())

        catalogue_keys = {_name_key(p['name']): p['sku'] for p in catalogue_items.values()}

        for item in scraped:
            if not item.get('name') or not item.get('price_ngn', 0):
                skipped += 1
                continue

            key = _name_key(item['name'])

            # Check for close match in existing catalogue
            matched_sku = catalogue_keys.get(key)
            # Partial match fallback
            if not matched_sku:
                for ckey, csku in catalogue_keys.items():
                    if key[:10] in ckey or ckey[:10] in key:
                        matched_sku = csku
                        break

            if matched_sku and matched_sku in catalogue_items:
                # Update price and photo on existing item
                old_price = catalogue_items[matched_sku]['base_ngn']
                new_price = item['price_ngn']
                catalogue_items[matched_sku]['base_ngn']  = new_price
                if item.get('photo_url'):
                    catalogue_items[matched_sku]['photo_url'] = item['photo_url']
                if item.get('source_url'):
                    catalogue_items[matched_sku]['source_url'] = item['source_url']
                # Record price history
                self._record_shop_price(matched_sku, new_price)
                # Trigger price-drop notifications if price fell
                if new_price < old_price:
                    self._check_price_drop_notifications(matched_sku, new_price)
                updated += 1
            else:
                # New item — add to catalogue and scraped store
                sku = item['sku_hint']
                # Ensure SKU is unique
                while sku in catalogue_items:
                    sku = sku + 'X'

                new_entry = {
                    'name':         item['name'],
                    'sku':          sku,
                    'base_ngn':     item['price_ngn'],
                    'weight_kg':    item.get('weight_kg', 20),
                    'stock_level':  item.get('stock_status', 'in_stock'),
                    'description':  item.get('description') or item['name'],
                    'specs':        item.get('specs') or 'See product page',
                    'source_url':   item.get('source_url', source_url),
                    'photo_url':    item.get('photo_url', ''),
                    'source_label': item.get('source_label', 'Supplier'),
                }
                cat_bucket = item.get('category', 'Additional Products')
                NIGERIA_SHOP_CATALOGUE.setdefault(cat_bucket, []).append(new_entry)
                catalogue_items[sku] = new_entry
                catalogue_keys[_name_key(item['name'])] = sku
                scraped_store[sku] = new_entry
                added += 1

        # Persist scraped items to disk
        try:
            tmp = SHOP_SCRAPED_FILE + '.tmp'
            with open(tmp, 'w', encoding='utf-8') as f:
                json.dump(scraped_store, f, indent=2)
            os.replace(tmp, SHOP_SCRAPED_FILE)
        except Exception as e:
            logger.error(f'_merge_scraped error saving: {e}')

        # Sync updated catalogue to Firebase for Enterprise API
        threading.Thread(target=catalogue_sync.sync_silent, kwargs={'force': True}, daemon=True).start()

        return added, updated, skipped

    def _load_scraped_catalogue(self):
        """On bot startup, re-load any previously scraped items into the live catalogue."""
        if not os.path.exists(SHOP_SCRAPED_FILE):
            return
        try:
            with open(SHOP_SCRAPED_FILE, 'r', encoding='utf-8') as f:
                scraped = json.load(f)
            bucket = NIGERIA_SHOP_CATALOGUE.setdefault('Additional Products', [])
            existing_skus = {p['sku'] for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}
            count = 0
            for sku, item in scraped.items():
                if sku not in existing_skus:
                    bucket.append(item)
                    count += 1
            if count:
                logger.info(f'Loaded {count} scraped shop items from disk')
        except Exception as e:
            logger.error(f'_load_scraped_catalogue error: {e}')

    def _seed_mercury_schedule(self):
        """
        Ensure Mercury Direct URLs are registered in the auto-scrape schedule.
        Only seeds on first run — existing jobs are never overwritten.
        """
        SCRAPE_SCHEDULE_FILE = os.path.join(DATA_DIR, 'scrape_schedule.json')
        MERCURY_URLS = [
            'https://mercurydirect.com.ng/product-category/stabilizer/',
            'https://mercurydirect.com.ng/product-category/stabilizer/servo-stabilizer/',
            'https://mercurydirect.com.ng/product-category/solar-inverter/',
            'https://mercurydirect.com.ng/product-category/surge-protector/',
            'https://mercurydirect.com.ng/product-category/ups/',
            'https://mercurydirect.com.ng/product-category/solar/solar-hybrid-inverter/',
            'https://mercurydirect.com.ng/product-category/online-ups-inverter/',
        ]
        try:
            sched = {'jobs': {}, 'paused': False}
            if os.path.exists(SCRAPE_SCHEDULE_FILE):
                with open(SCRAPE_SCHEDULE_FILE, 'r', encoding='utf-8') as f:
                    sched = json.load(f)
            changed = False
            for url in MERCURY_URLS:
                if url not in sched.get('jobs', {}):
                    sched.setdefault('jobs', {})[url] = {
                        'url':        url,
                        'interval_h': 12,
                        'added_at':   datetime.now(WAT).isoformat(),
                        'added_by':   'system',
                        'last_run':   None,
                        'next_run':   datetime.now(WAT).isoformat(),
                    }
                    changed = True
                    logger.info(f'[MercurySeed] Registered auto-scrape: {url}')
            if changed:
                tmp = SCRAPE_SCHEDULE_FILE + '.tmp'
                with open(tmp, 'w', encoding='utf-8') as f:
                    json.dump(sched, f, indent=2)
                os.replace(tmp, SCRAPE_SCHEDULE_FILE)
        except Exception as e:
            logger.error(f'_seed_mercury_schedule error: {e}')

    def _check_price_drop_notifications(self, sku: str, new_price: float):
        """Send price-drop alerts to subscribers whose threshold is now met."""
        data = self._load_notify()
        subs = data.get('price', {}).get(sku, [])
        if not subs:
            return
        all_items = {p['sku']: p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}
        item = all_items.get(sku, {})
        notified_uids = []
        for entry in subs:
            if new_price <= entry['threshold']:
                try:
                    self.send_message(int(entry['uid']),
                        f"*Price Drop Alert!*\n\n"
                        f"*{item.get('name', sku)}* has dropped below your target!\n\n"
                        f"New price: *₦{new_price:,.0f}*\n"
                        f"🎯 Your target: ₦{entry['threshold']:,.0f}\n"
                        f"💚 You save: ₦{entry['threshold'] - new_price:,.0f}\n\n"
                        f"Order now:\n"
                        f"  `/invoice {sku} 1` — instant invoice\n"
                        f"  `/shop {sku}` — product details\n\n"
                        f"_`/notify remove {sku}` to cancel this alert_"
                    )
                    notified_uids.append(entry['uid'])
                except Exception:
                    pass
        # Remove triggered alerts
        data['price'][sku] = [e for e in subs if e['uid'] not in notified_uids]
        self._save_notify(data)

    # ══════════════════════════════════════════════════════════════════════════
    # /search — search across shop items and /price catalogue (free)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_search(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /search [keyword]         — search shop + price catalogue
        /search shop [keyword]    — shop items only
        /search price [keyword]   — /price catalogue only
        """
        parts   = text.split(None, 2)
        scope   = 'all'
        keyword = ''

        if len(parts) == 1:
            self.send_message(chat_id,
                "*Search*\n\n"
                "Usage: `/search [keyword]`\n"
                "       `/search shop [keyword]`\n"
                "       `/search price [keyword]`\n\n"
                "Examples:\n"
                "`/search 10kVA`\n"
                "`/search single phase`\n"
                "`/search shop servo`\n"
                "`/search price surge`"
            )
            return
        if len(parts) == 2:
            keyword = parts[1]
        else:
            if parts[1].lower() in ('shop', 'price'):
                scope   = parts[1].lower()
                keyword = parts[2]
            else:
                keyword = parts[1] + ' ' + parts[2]

        kw = keyword.strip().lower()
        if not kw:
            self.send_message(chat_id, "❌ Please enter a keyword to search.")
            return

        results = []

        # Shop catalogue
        if scope in ('all', 'shop'):
            margin = get_shop_margin()
            ovr = {}
            try:
                path = os.path.join(DATA_DIR, 'shop_price_overrides.json')
                if os.path.exists(path):
                    with open(path) as f:
                        ovr = json.load(f)
            except Exception:
                pass
            stock_data = _load_shop_stock()
            for cat, items in NIGERIA_SHOP_CATALOGUE.items():
                for p in items:
                    searchable = f"{p['name']} {p['specs']} {p.get('description','')} {p['sku']}".lower()
                    if kw in searchable:
                        base = float(ovr.get(p['sku'],{}).get('override_ngn', p['base_ngn']))
                        retail = round(base * (1 + margin / 100))
                        s_status = stock_data.get(p['sku'], p.get('stock_level','in_stock'))
                        s_icon = STOCK_LABELS.get(s_status, ('❓',''))[0]
                        results.append({
                            'source': '🏪',
                            'name':   p['name'],
                            'detail': p['specs'],
                            'price':  f"₦{retail:,.0f} {s_icon}",
                            'action': f"`/invoice {p['sku']} 1` · `/shop {p['sku']}`",
                        })

        # /price EQUIPMENT_DATABASE
        if scope in ('all', 'price'):
            try:
                ngn = market_engine.calculate_equipment_prices('Nigeria')
                profit_margin = get_profit_margin()
                for cat, items in ngn.items():
                    for name, data in items.items():
                        searchable = f"{name} {cat}".lower()
                        if kw in searchable:
                            retail = data['price_ngn'] * (1 + profit_margin / 100)
                            results.append({
                                'source': '📦',
                                'name':   name,
                                'detail': cat,
                                'price':  f"₦{retail:,.0f}",
                                'action': f"`/invoice {name} 1`",
                            })
            except Exception:
                pass

        if not results:
            self.send_message(chat_id,
                f"No results for *{keyword}*.\n\n"
                "_Try a broader keyword, e.g. `kVA`, `single`, `surge`, `servo`._"
            )
            return

        msg = f"*Results for '{keyword}'* ({len(results)} found)\n\n"
        for r in results[:12]:
            msg += (
                f"{r['source']} *{r['name']}*\n"
                f"  _{r['detail']}_\n"
                f"  {r['price']}\n"
                f"  {r['action']}\n\n"
            )
        if len(results) > 12:
            msg += f"_+{len(results)-12} more — refine your search_\n"
        self.send_message(chat_id, msg)

    # ══════════════════════════════════════════════════════════════════════════
    # /track — order tracking (free)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_track(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /track                    — list your orders
        /track [INV-ID]           — status of a specific order
        Admin:
        /track update [INV-ID] [status] [note]  — update order status
        """
        parts  = text.split(None, 3)
        action = parts[1].upper() if len(parts) > 1 else 'LIST'
        orders = self._load_orders()
        uid    = str(user_id)

        STATUS_ICONS = {k: v[0] for k, v in self.ORDER_STATUSES.items()}
        STATUS_LABELS = {k: v[1] for k, v in self.ORDER_STATUSES.items()}

        # ADMIN: UPDATE ORDER STATUS
        if parts[1].lower() == 'update' if len(parts) > 1 else False:
            if not admin_manager.is_admin(user_id):
                self.send_message(chat_id, "⛔ Admin only.")
                return
            if len(parts) < 4:
                statuses = ', '.join(f'`{s}`' for s in self.ORDER_STATUSES)
                self.send_message(chat_id,
                    f"Usage: `/track update [INV-ID] [status] [note]`\n"
                    f"Statuses: {statuses}\n"
                    f"Example: `/track update INV-ABC123 shipped Via GIG`"
                )
                return
            sub_parts = parts[2].split(None, 2)  # inv_id status note
            inv_id    = sub_parts[0].upper()
            new_status= sub_parts[1].lower() if len(sub_parts) > 1 else ''
            note      = sub_parts[2] if len(sub_parts) > 2 else ''

            if new_status not in self.ORDER_STATUSES:
                self.send_message(chat_id,
                    f"Unknown status. Choose: {', '.join(self.ORDER_STATUSES)}")
                return

            if inv_id not in orders:
                # Create order record from invoice if it exists
                try:
                    if os.path.exists(INVOICE_FILE):
                        with open(INVOICE_FILE) as f:
                            invoices = json.load(f)
                        if inv_id in invoices:
                            inv = invoices[inv_id]
                            orders[inv_id] = {
                                'inv_id':   inv_id,
                                'user_id':  str(inv.get('user_id', '')),
                                'item':     inv.get('item_name', ''),
                                'total':    inv.get('total', 0),
                                'status':   new_status,
                                'history':  [],
                                'created':  inv.get('date', ''),
                            }
                except Exception:
                    pass

            if inv_id not in orders:
                self.send_message(chat_id, f"Invoice `{inv_id}` not found.")
                return

            old_status = orders[inv_id].get('status', 'pending')
            orders[inv_id]['status'] = new_status
            orders[inv_id].setdefault('history', []).append({
                'status': new_status,
                'note':   note,
                'ts':     datetime.now(WAT).isoformat(),
                'by':     str(user_id),
            })
            self._save_orders(orders)

            icon  = STATUS_ICONS.get(new_status, '📋')
            label = STATUS_LABELS.get(new_status, new_status)
            self.send_message(chat_id,
                f"Order `{inv_id}` updated to {icon} *{label}*\n"
                + (f"Note: _{note}_" if note else '')
            )

            # Notify the customer
            cust_uid = orders[inv_id].get('user_id', '')
            if cust_uid:
                try:
                    self.send_message(int(cust_uid),
                        f"*Order Update — {inv_id}*\n\n"
                        f"{icon} *{label}*\n"
                        + (f"_{note}_\n" if note else '') +
                        f"\n_`/track {inv_id}` to check full history_"
                    )
                except Exception:
                    pass
            return

        # LIST USER'S ORDERS
        if action == 'LIST':
            mine = {k: v for k, v in orders.items()
                    if str(v.get('user_id', '')) == uid}
            if not mine:
                self.send_message(chat_id,
                    "📦 *Your Orders*\n\nNo orders found.\n\n"
                    f"_After payment, send proof to {SUPPORT_HANDLE} with your Invoice No._"
                )
                return
            msg = f"*Your Orders* ({len(mine)})\n\n"
            for inv_id, o in sorted(mine.items(),
                                    key=lambda x: x[1].get('created',''), reverse=True)[:8]:
                icon  = STATUS_ICONS.get(o.get('status','pending'), '📋')
                label = STATUS_LABELS.get(o.get('status','pending'), o.get('status',''))
                msg  += (
                    f"{icon} `{inv_id}` — {o.get('item','')[:30]}\n"
                    f"   *{label}* · ₦{o.get('total',0):,.0f} · {o.get('created','')[:10]}\n\n"
                )
            msg += "_`/track [INV-ID]` for full details_"
            self.send_message(chat_id, msg)
            return

        # SINGLE ORDER DETAIL
        inv_id = action
        order  = orders.get(inv_id)

        # Try to match loosely
        if not order:
            for k, v in orders.items():
                if inv_id in k:
                    order  = v
                    inv_id = k
                    break

        if not order:
            self.send_message(chat_id,
                f"Order `{inv_id}` not found.\n"
                f"Use `/track` to see your orders.")
            return

        icon  = STATUS_ICONS.get(order.get('status','pending'), '📋')
        label = STATUS_LABELS.get(order.get('status','pending'), order.get('status',''))

        hist = order.get('history', [])
        hist_lines = ''
        for h in hist[-5:]:
            h_icon = STATUS_ICONS.get(h['status'],'📋')
            h_lbl  = STATUS_LABELS.get(h['status'], h['status'])
            ts     = h.get('ts','')[:16].replace('T',' ')
            note   = f" — _{h['note']}_" if h.get('note') else ''
            hist_lines += f"  {h_icon} *{h_lbl}* {ts}{note}\n"

        self.send_message(chat_id,
            f"*Order {inv_id}*\n\n"
            f"Item: {order.get('item','')}\n"
            f"Total: ₦{order.get('total',0):,.0f}\n"
            f"Placed: {order.get('created','')[:10]}\n\n"
            f"*Current Status:* {icon} {label}\n\n"
            + (f"*History:*\n{hist_lines}" if hist_lines else '') +
            f"\n_Questions? Contact {SUPPORT_HANDLE}_"
        )

    # ══════════════════════════════════════════════════════════════════════════
    # /flash — admin flash sale management
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_flash(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /flash                              — list active flash sales
        Admin:
        /flash set [SKU] [discount%] [hours]  — start a flash sale
        /flash end [SKU]                      — end a flash sale early
        /flash broadcast                      — announce all active sales to group
        """
        parts  = text.split()
        action = parts[1].lower() if len(parts) > 1 else 'list'
        sales  = self._load_flash_sales()
        all_items = {p['sku']: p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}
        margin = get_shop_margin()
        ovr = {}
        try:
            path = os.path.join(DATA_DIR, 'shop_price_overrides.json')
            if os.path.exists(path):
                with open(path) as f: ovr = json.load(f)
        except Exception:
            pass

        def _retail(sku):
            item  = all_items.get(sku, {})
            base  = float(ovr.get(sku,{}).get('override_ngn', item.get('base_ngn',0)))
            return round(base * (1 + margin / 100))

        # LIST (public)
        if action == 'list':
            now  = datetime.now(WAT)
            active = {}
            for sku, s in sales.items():
                try:
                    ends = datetime.fromisoformat(s['ends_at'])
                    if ends.tzinfo is None: ends = WAT.localize(ends)
                    if ends > now:
                        active[sku] = s
                except Exception:
                    pass
            if not active:
                self.send_message(chat_id,
                    "⚡ No flash sales active right now.\n\n"
                    "_Watch this space — flash sales appear here when live._"
                )
                return
            msg = "⚡ *Flash Sales — Limited Time!*\n\n"
            for sku, s in active.items():
                item  = all_items.get(sku, {})
                orig  = _retail(sku)
                disc  = float(s['discount_pct'])
                fp    = round(orig * (1 - disc / 100))
                ends  = s['ends_at'][:16].replace('T',' ')
                msg  += (
                    f"🔥 *{item.get('name', sku)}*\n"
                    f"  ~~₦{orig:,.0f}~~ → *₦{fp:,.0f}* ({disc:.0f}% OFF)\n"
                    f"  Ends: {ends} WAT\n"
                    f"  `/invoice {sku} 1`\n\n"
                )
            self.send_message(chat_id, msg)
            return

        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "⛔ Admin only for this sub-command.")
            return

        # SET
        if action == 'set':
            if len(parts) < 5:
                self.send_message(chat_id,
                    "Usage: `/flash set [SKU] [discount%] [hours]`\n"
                    "Example: `/flash set STAB-5KVA 15 24`  (15% off for 24 hours)")
                return
            sku   = parts[2].upper()
            disc  = float(parts[3].replace('%',''))
            hours = float(parts[4])
            if sku not in all_items:
                self.send_message(chat_id, f"SKU `{sku}` not found.")
                return
            ends_at = (datetime.now(WAT) + timedelta(hours=hours)).isoformat()
            sales[sku] = {
                'discount_pct': disc,
                'ends_at':      ends_at,
                'set_by':       str(user_id),
                'set_at':       datetime.now(WAT).isoformat(),
            }
            self._save_flash_sales(sales)
            orig = _retail(sku)
            fp   = round(orig * (1 - disc / 100))
            self.send_message(chat_id,
                f"*Flash Sale Started!*\n\n"
                f"*{all_items[sku]['name']}*\n"
                f"~~₦{orig:,.0f}~~ → *₦{fp:,.0f}* ({disc:.0f}% off)\n"
                f"Duration: {hours:.0f} hours\n"
                f"Ends: {ends_at[:16]} WAT\n\n"
                f"_Use `/flash broadcast` to announce to the group._"
            )
            return

        # END
        if action == 'end':
            sku = parts[2].upper() if len(parts) > 2 else ''
            if sku in sales:
                del sales[sku]
                self._save_flash_sales(sales)
                self.send_message(chat_id, f"Flash sale ended for `{sku}`.")
            else:
                self.send_message(chat_id, f"ℹ️ No active flash sale for `{sku}`.")
            return

        # BROADCAST
        if action == 'broadcast':
            now    = datetime.now(WAT)
            active = {}
            for sku, s in sales.items():
                try:
                    ends = datetime.fromisoformat(s['ends_at'])
                    if ends.tzinfo is None: ends = WAT.localize(ends)
                    if ends > now: active[sku] = s
                except Exception:
                    pass
            if not active:
                self.send_message(chat_id, "ℹ️ No active flash sales to broadcast.")
                return
            msg = "⚡ *iVolt Power Solutions — Flash Sale!*\n\n"
            for sku, s in active.items():
                item = all_items.get(sku, {})
                orig = _retail(sku)
                disc = float(s['discount_pct'])
                fp   = round(orig * (1 - disc / 100))
                ends = s['ends_at'][:16].replace('T',' ')
                msg += (
                    f"🔥 *{item.get('name', sku)}*\n"
                    f"  ~~₦{orig:,.0f}~~ → *₦{fp:,.0f}* ({disc:.0f}% OFF)\n"
                    f"  Ends: {ends} WAT\n"
                    f"  `/invoice {sku} 1`\n\n"
                )
            msg += "_Limited time! Order now before it ends._"
            try:
                self.send_message(GROUP_ID, msg)
                self.send_message(chat_id, f"Broadcast sent to group.")
            except Exception as e:
                self.send_message(chat_id, f"Broadcast failed: {e}")
            return

        self.send_message(chat_id,
            "Usage: `/flash` · `/flash set [SKU] [%] [hours]` · "
            "`/flash end [SKU]` · `/flash broadcast`"
        )

    # ══════════════════════════════════════════════════════════════════════════
    # /bulk — admin bulk/quantity discount management
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_bulk(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /bulk                              — show current bulk discount tiers
        Admin:
        /bulk set [SKU|_default] [min_qty] [discount%] [label]
        /bulk remove [SKU]
        """
        parts  = text.split(None, 4)
        action = parts[1].lower() if len(parts) > 1 else 'list'
        rules  = self._load_bulk_rules()

        if action == 'list':
            if not rules:
                self.send_message(chat_id,
                    "*📦 Bulk Discounts*\n\nNo bulk tiers set yet.\n\n"
                    "_Admins can add tiers with `/bulk set`_"
                )
                return
            msg = "*📦 Bulk / Quantity Discounts*\n\n"
            for sku_key, tiers in rules.items():
                label = "All items (default)" if sku_key == '_default' else sku_key
                msg  += f"*{label}*\n"
                for t in sorted(tiers, key=lambda x: x['min_qty']):
                    msg += f"  {t['min_qty']}+ units: {t['discount_pct']:.0f}% off — _{t.get('label','')}_\n"
                msg += "\n"
            msg += "_Discounts apply automatically when qty meets the threshold._\n"
            msg += "_Use `/invoice [SKU] [qty]` to see the discounted price._"
            self.send_message(chat_id, msg)
            return

        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "⛔ Admin only.")
            return

        if action == 'set':
            if len(parts) < 5:
                self.send_message(chat_id,
                    "Usage: `/bulk set [SKU|_default] [min_qty] [discount%] [label]`\n\n"
                    "Examples:\n"
                    "`/bulk set _default 3 5 3+ units`\n"
                    "`/bulk set _default 5 10 5+ units`\n"
                    "`/bulk set STAB-5KVA 2 8 Multi-buy deal`"
                )
                return
            sku_key  = parts[2].upper()
            min_qty  = int(parts[3])
            disc_pct = float(parts[4].split()[0].replace('%',''))
            label    = ' '.join(parts[4].split()[1:]) if len(parts[4].split()) > 1 else f"{disc_pct:.0f}% off"

            rules.setdefault(sku_key, [])
            # Remove existing tier for same min_qty then add new
            rules[sku_key] = [t for t in rules[sku_key] if t['min_qty'] != min_qty]
            rules[sku_key].append({'min_qty': min_qty, 'discount_pct': disc_pct, 'label': label})
            rules[sku_key].sort(key=lambda x: x['min_qty'])
            self._save_bulk_rules(rules)
            self.send_message(chat_id,
                f"Bulk tier saved: *{sku_key}* — {min_qty}+ units → {disc_pct:.0f}% off"
            )
            return

        if action == 'remove':
            sku_key = parts[2].upper() if len(parts) > 2 else ''
            if sku_key in rules:
                del rules[sku_key]
                self._save_bulk_rules(rules)
                self.send_message(chat_id, f"Bulk tiers removed for `{sku_key}`.")
            else:
                self.send_message(chat_id, f"ℹ️ No bulk tiers for `{sku_key}`.")
            return

        self.send_message(chat_id,
            "Usage: `/bulk` · `/bulk set [SKU] [qty] [%] [label]` · `/bulk remove [SKU]`"
        )

    # ══════════════════════════════════════════════════════════════════════════
    # /related — show related / complementary items
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_related(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /related [SKU]  — show related and complementary items
        """
        parts = text.split()
        sku   = parts[1].upper() if len(parts) > 1 else ''
        all_items = {p['sku']: p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}

        if not sku or sku not in all_items:
            self.send_message(chat_id,
                "Usage: `/related [SKU]`\n"
                "Example: `/related STAB-5KVA`\n\n"
                "Shows items that complement or are alternatives to the chosen item."
            )
            return

        item   = all_items[sku]
        specs  = item.get('specs', '')
        is_3ph = 'three' in specs.lower() or '3-phase' in specs.lower()
        import re as _re
        kva_m  = _re.search(r'(\d+(?:\.\d+)?)\s*kVA', specs, _re.I)
        kva    = float(kva_m.group(1)) if kva_m else 5.0

        margin = get_shop_margin()
        def _retail(p):
            return round(float(p['base_ngn']) * (1 + margin / 100))

        # Build related lists
        alternatives = []   # same phase, adjacent kVA
        complements  = []   # surge protectors, different phase version

        for s, p in all_items.items():
            if s == sku:
                continue
            ps = p.get('specs','')
            pk_m = _re.search(r'(\d+(?:\.\d+)?)\s*kVA', ps, _re.I)
            pk   = float(pk_m.group(1)) if pk_m else 0
            p_3ph = 'three' in ps.lower() or '3-phase' in ps.lower()

            # Alternative: same phase, close kVA
            if p_3ph == is_3ph and pk > 0 and abs(pk - kva) <= kva * 1.5:
                alternatives.append(p)
            # Complement: opposite phase version of same kVA
            elif p_3ph != is_3ph and pk > 0 and abs(pk - kva) <= kva * 0.5:
                complements.append(p)

        # Limit
        alternatives = alternatives[:3]
        complements  = complements[:2]

        msg = f"*Related to {item['name']}*\n\n"

        if alternatives:
            msg += "*🔄 Alternatives (similar kVA):*\n"
            for p in alternatives:
                s_icon = STOCK_LABELS.get(
                    get_item_stock(p['sku'], p.get('stock_level','in_stock')), ('❓',''))[0]
                msg += (
                    f"  • *{p['name']}* {s_icon}\n"
                    f"    {p['specs']}\n"
                    f"    ₦{_retail(p):,.0f} · `/shop {p['sku']}`\n\n"
                )

        if complements:
            msg += "*⚡ Phase complement (same kVA, opposite phase):*\n"
            for p in complements:
                s_icon = STOCK_LABELS.get(
                    get_item_stock(p['sku'], p.get('stock_level','in_stock')), ('❓',''))[0]
                msg += (
                    f"  • *{p['name']}* {s_icon}\n"
                    f"    {p['specs']}\n"
                    f"    ₦{_retail(p):,.0f} · `/shop {p['sku']}`\n\n"
                )

        if not alternatives and not complements:
            msg += "_No closely related items found in the current catalogue._\n"

        msg += (
            f"\n*Also consider:*\n"
            f"  🔍 `/search {kva:.0f}kVA` — all {kva:.0f}kVA items\n"
            f"  ⚖️ `/compare {sku} [other SKU]` — side-by-side comparison\n"
            f"  📐 `/schematic shop {sku}` — wiring diagram"
        )
        self.send_message(chat_id, msg)

    # ══════════════════════════════════════════════════════════════════════════
    # /pricehistory — shop price trend chart (text sparkline)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_pricehistory(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /pricehistory [SKU]   — show price history for a shop item
        """
        parts = text.split()
        sku   = parts[1].upper() if len(parts) > 1 else ''
        all_items = {p['sku']: p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}

        if not sku or sku not in all_items:
            sku_list = '\n'.join(f"  `{s}`" for s in list(all_items)[:6])
            self.send_message(chat_id,
                "Usage: `/pricehistory [SKU]`\n\n"
                f"Examples:\n  `{list(all_items)[0]}`\n\n"
                f"First few SKUs:\n{sku_list}"
            )
            return

        hist = {}
        if os.path.exists(SHOP_PRICE_HIST_FILE):
            try:
                with open(SHOP_PRICE_HIST_FILE) as f:
                    hist = json.load(f)
            except Exception:
                pass

        records = hist.get(sku, [])
        item    = all_items[sku]
        margin  = get_shop_margin()
        current = round(float(item['base_ngn']) * (1 + margin / 100))

        if not records:
            self.send_message(chat_id,
                f"📈 *Price History — {item['name']}*\n\n"
                f"Current retail: ₦{current:,.0f}\n\n"
                f"_No historical data yet. Price tracking starts when the bot "
                f"first fetches or is updated via `/shop items [url]`._"
            )
            return

        prices = [r['price'] for r in records[-30:]]
        dates  = [r['ts'][:10] for r in records[-30:]]

        # Text sparkline
        mn, mx = min(prices), max(prices)
        BARS = '▁▂▃▄▅▆▇█'
        spark = ''
        for p in prices:
            if mx == mn:
                idx = 4
            else:
                idx = int((p - mn) / (mx - mn) * (len(BARS) - 1))
            spark += BARS[idx]

        change    = prices[-1] - prices[0]
        change_pct = (change / prices[0] * 100) if prices[0] else 0
        trend_icon = "📈" if change > 0 else "📉" if change < 0 else "➡️"

        msg = (
            f"*Price History — {item['name']}*\n"
            f"_(last {len(prices)} records)_\n\n"
            f"```\n{spark}\n```\n\n"
            f"Lowest:   ₦{mn:,.0f}\n"
            f"Highest:  ₦{mx:,.0f}\n"
            f"Current:  ₦{current:,.0f}\n"
            f"{trend_icon} Change: {'+' if change>=0 else ''}₦{change:,.0f} "
            f"({change_pct:+.1f}%)\n\n"
            f"First recorded: {dates[0]}\n"
            f"Latest:         {dates[-1]}\n\n"
            f"_`/notify price {sku} [₦target]` — alert when price drops_"
        )
        self.send_message(chat_id, msg)

    # ══════════════════════════════════════════════════════════════════════════
    # /shop items [url] — auto-update catalogue from URL (admin)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_shopitems(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        Admin: scrape a product URL and merge into the live catalogue.
        /shop items [url]
        /shop items list          — show scraped items
        /shop items remove [SKU]  — remove a scraped item
        /shop items resync [url]  — re-scrape and update prices only
        """
        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "⛔ Admin only.")
            return

        parts  = text.split()
        # text is already the full "/shop items ..." command
        # parts[0]=/shop  parts[1]=items  parts[2]=url|list|remove  parts[3]=...
        sub = parts[2].lower() if len(parts) > 2 else ''
        url = parts[2] if len(parts) > 2 and parts[2].startswith('http') else ''

        # LIST scraped items
        if sub == 'list':
            scraped = {}
            if os.path.exists(SHOP_SCRAPED_FILE):
                try:
                    with open(SHOP_SCRAPED_FILE) as f:
                        scraped = json.load(f)
                except Exception:
                    pass
            if not scraped:
                self.send_message(chat_id,
                    "📋 No scraped items in catalogue.\n\n"
                    "_Use `/shop items [url]` to fetch from a website._"
                )
                return
            margin = get_shop_margin()
            msg    = f"*Additional Products* ({len(scraped)})\n\n"
            for sku, item in list(scraped.items())[:15]:
                retail = round(float(item['base_ngn']) * (1 + margin / 100))
                msg   += f"• `{sku}` — {item['name'][:35]}\n  ₦{retail:,.0f}\n"
            if len(scraped) > 15:
                msg += f"\n_+{len(scraped)-15} more_"
            msg += "\n_`/shop items remove [SKU]` to delete_"
            self.send_message(chat_id, msg)
            return

        # REMOVE a scraped item
        if sub == 'remove':
            sku = parts[3].upper() if len(parts) > 3 else ''
            if not sku:
                self.send_message(chat_id, "Usage: `/shop items remove [SKU]`")
                return
            scraped = {}
            if os.path.exists(SHOP_SCRAPED_FILE):
                try:
                    with open(SHOP_SCRAPED_FILE) as f:
                        scraped = json.load(f)
                except Exception:
                    pass
            if sku in scraped:
                del scraped[sku]
                tmp = SHOP_SCRAPED_FILE + '.tmp'
                with open(tmp, 'w') as f:
                    json.dump(scraped, f, indent=2)
                os.replace(tmp, SHOP_SCRAPED_FILE)
                # Remove from live catalogue
                for cat_name, cat_items in NIGERIA_SHOP_CATALOGUE.items():
                    NIGERIA_SHOP_CATALOGUE[cat_name] = [
                        p for p in cat_items if p['sku'] != sku
                    ]
                self.send_message(chat_id, f"Removed `{sku}` from catalogue.")
            else:
                self.send_message(chat_id, f"ℹ️ `{sku}` not found in scraped items.")
            return

        # SCRAPE / RESYNC from URL
        resync = sub == 'resync'
        if resync:
            url = parts[3] if len(parts) > 3 else ''
        if not url:
            self.send_message(chat_id,
                "*🌐 Auto-Update Catalogue from URL*\n\n"
                "Usage:\n"
                "`/shop items [url]` — scrape and add new items\n"
                "`/shop items resync [url]` — re-scrape and update prices only\n"
                "`/shop items list` — view scraped items\n"
                "`/shop items remove [SKU]` — remove a scraped item\n\n"
                "Supported:\n"
                "  • WooCommerce category pages (multiple products)\n"
                "  • WooCommerce single product pages\n"
                "  • Any page with open-graph price meta tags\n\n"
                "Examples:\n"
                "`/shop items https://mercurydirect.com.ng/product-category/stabilizer/`\n"
                "`/shop items https://mercurydirect.com.ng/product/mercury-2kva-voltage-stabilizer/`"
            )
            return

        self.send_message(chat_id, f"⏳ Fetching products from:\n_{url}_")

        try:
            scraped = self._scrape_shop_url(url)
        except Exception as e:
            self.send_message(chat_id,
                f"*Scrape failed:* {str(e)[:200]}\n\n"
                f"Possible reasons:\n"
                f"• Site is down or unreachable\n"
                f"• URL is not a product or category page\n"
                f"• Site requires login\n\n"
                f"The bot needs outbound internet access to scrape URLs.\n"
                f"Check your server's firewall/network settings."
            )
            return

        if not scraped:
            self.send_message(chat_id,
                f"No products found at that URL.\n\n"
                f"Make sure it is a WooCommerce product or category page."
            )
            return

        added, updated, skipped = self._merge_scraped_to_catalogue(scraped, url)

        summary = (
            f"*Catalogue Updated*\n\n"
            f"Source: {url[:60]}\n"
            f"Products found: {len(scraped)}\n\n"
            f"  ➕ Added:   {added} new items\n"
            f"  🔄 Updated: {updated} existing items (price + photo)\n"
            f"  ⏭ Skipped: {skipped} (no price/name)\n\n"
        )
        if added:
            summary += "*New items added:*\n"
            for item in scraped[:5]:
                if item.get('price_ngn', 0):
                    summary += f"  • {item['name'][:40]} — ₦{item['price_ngn']:,.0f}\n"
            if len(scraped) > 5:
                summary += f"  _...and {len(scraped)-5} more_\n"
        if updated:
            summary += f"\n_Price history recorded for {updated} items._\n"
        summary += (
            f"\n_Use `/shop` to see the updated catalogue._\n"
            f"_Use `/shop items list` to manage scraped items._"
        )
        self.send_message(chat_id, summary)

    # ══════════════════════════════════════════════════════════════════════════
    # /scrape — On-demand & scheduled web scraper (admin)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_scrape(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        Admin: multi-platform web scraper with schedule management.

        /scrape [url]                   — scrape once and merge into catalogue
        /scrape resync [url]            — re-scrape to update prices only (no new items)
        /scrape schedule add [url] [hh] — auto-scrape URL every hh hours (default 12)
        /scrape schedule list           — show scheduled scrape jobs
        /scrape schedule remove [url]   — remove a scheduled scrape job
        /scrape schedule pause          — pause all auto-scrape jobs
        /scrape schedule resume         — resume auto-scrape jobs
        /scrape list                    — list all scraped items (alias: /shop items list)
        /scrape remove [SKU]            — remove a scraped item
        /scrape status                  — show scraper engine status

        Supported platforms: WooCommerce, Shopify, Generic (schema.org/og:)
        """
        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "⛔ Admin only.")
            return

        parts  = text.split()
        sub    = parts[1].lower() if len(parts) > 1 else ''

        SCRAPE_SCHEDULE_FILE = os.path.join(DATA_DIR, 'scrape_schedule.json')

        def _load_schedule() -> dict:
            try:
                if os.path.exists(SCRAPE_SCHEDULE_FILE):
                    with open(SCRAPE_SCHEDULE_FILE, 'r', encoding='utf-8') as f:
                        return json.load(f)
            except Exception:
                pass
            return {'jobs': {}, 'paused': False}

        def _save_schedule(data: dict):
            try:
                tmp = SCRAPE_SCHEDULE_FILE + '.tmp'
                with open(tmp, 'w', encoding='utf-8') as f:
                    json.dump(data, f, indent=2)
                os.replace(tmp, SCRAPE_SCHEDULE_FILE)
            except Exception as e:
                logger.error(f'_save_schedule error: {e}')

        # ── STATUS ────────────────────────────────────────────────────────────
        if sub == 'status':
            sched  = _load_schedule()
            jobs   = sched.get('jobs', {})
            paused = sched.get('paused', False)
            scraped_count = 0
            if os.path.exists(SHOP_SCRAPED_FILE):
                try:
                    with open(SHOP_SCRAPED_FILE) as f:
                        scraped_count = len(json.load(f))
                except Exception:
                    pass
            status_lines = (
                f"*🌐 Scraper Status*\n\n"
                f"Scraped items in catalogue: *{scraped_count}*\n"
                f"Scheduled jobs: *{len(jobs)}*\n"
                f"Auto-scrape: *{'⏸ Paused' if paused else '▶️ Active'}*\n\n"
            )
            if jobs:
                status_lines += "*Scheduled jobs:*\n"
                for url_key, job in jobs.items():
                    last = job.get('last_run', 'never')[:16] if job.get('last_run') else 'never'
                    status_lines += (
                        f"  • `{url_key[:50]}`\n"
                        f"    Every {job.get('interval_h', 12)}h · Last run: {last}\n"
                    )
            status_lines += "\n_Use `/scrape schedule list` for full details._"
            self.send_message(chat_id, status_lines)
            return

        # ── LIST scraped items ────────────────────────────────────────────────
        if sub == 'list':
            self._cmd_shopitems(chat_id, user_id, '/shop items list', is_private)
            return

        # ── REMOVE a scraped item ─────────────────────────────────────────────
        if sub == 'remove':
            sku = parts[2].upper() if len(parts) > 2 else ''
            self._cmd_shopitems(chat_id, user_id, f'/shop items remove {sku}', is_private)
            return

        # ── SCHEDULE management ───────────────────────────────────────────────
        if sub == 'schedule':
            sched_action = parts[2].lower() if len(parts) > 2 else 'list'

            if sched_action == 'list':
                sched = _load_schedule()
                jobs  = sched.get('jobs', {})
                paused = sched.get('paused', False)
                if not jobs:
                    self.send_message(chat_id,
                        "📅 *No scheduled scrape jobs.*\n\n"
                        "Add one with:\n"
                        "`/scrape schedule add [url] [interval_hours]`\n\n"
                        "Example:\n"
                        "`/scrape schedule add https://mercurydirect.com.ng/solar/ 6`"
                    )
                    return
                msg = f"📅 *Scheduled Scrape Jobs* ({'⏸ Paused' if paused else '▶️ Active'})\n\n"
                for url_key, job in jobs.items():
                    last = job.get('last_run', 'never')[:16] if job.get('last_run') else 'never'
                    nxt  = job.get('next_run',  'soon')[:16]  if job.get('next_run')  else 'soon'
                    msg += (
                        f"`{url_key[:55]}`\n"
                        f"   Interval: every *{job.get('interval_h', 12)}h*\n"
                        f"   Last run: {last}\n"
                        f"   Next run: {nxt}\n\n"
                    )
                msg += "_Use `/scrape schedule remove [url]` to remove a job._"
                self.send_message(chat_id, msg)
                return

            if sched_action == 'add':
                url  = parts[3] if len(parts) > 3 else ''
                interval_h = int(parts[4]) if len(parts) > 4 else 12
                if not url or not url.startswith('http'):
                    self.send_message(chat_id,
                        "Usage: `/scrape schedule add [url] [interval_hours]`\n"
                        "Example: `/scrape schedule add https://mercurydirect.com.ng/solar/ 6`"
                    )
                    return
                sched = _load_schedule()
                sched.setdefault('jobs', {})[url] = {
                    'url':        url,
                    'interval_h': max(1, interval_h),
                    'added_at':   datetime.now(WAT).isoformat(),
                    'added_by':   str(user_id),
                    'last_run':   None,
                    'next_run':   datetime.now(WAT).isoformat(),  # run immediately on next tick
                }
                _save_schedule(sched)
                self.send_message(chat_id,
                    f"*Scrape Job Scheduled*\n\n"
                    f"URL: `{url}`\n"
                    f"Interval: every *{interval_h}h*\n\n"
                    f"_First scrape will run within 15 minutes._\n"
                    f"_Use `/scrape schedule list` to manage jobs._"
                )
                return

            if sched_action == 'remove':
                url = parts[3] if len(parts) > 3 else ''
                if not url:
                    self.send_message(chat_id, "Usage: `/scrape schedule remove [url]`")
                    return
                sched = _load_schedule()
                if url in sched.get('jobs', {}):
                    del sched['jobs'][url]
                    _save_schedule(sched)
                    self.send_message(chat_id, f"Removed schedule for `{url[:60]}`.")
                else:
                    self.send_message(chat_id, f"ℹ️ No scheduled job found for that URL.")
                return

            if sched_action == 'pause':
                sched = _load_schedule()
                sched['paused'] = True
                _save_schedule(sched)
                self.send_message(chat_id, "⏸ Auto-scrape jobs paused. Use `/scrape schedule resume` to re-enable.")
                return

            if sched_action == 'resume':
                sched = _load_schedule()
                sched['paused'] = False
                _save_schedule(sched)
                self.send_message(chat_id, "▶️ Auto-scrape jobs resumed.")
                return

            self.send_message(chat_id,
                "*📅 Schedule Commands:*\n\n"
                "`/scrape schedule list` — view all jobs\n"
                "`/scrape schedule add [url] [hours]` — add job\n"
                "`/scrape schedule remove [url]` — delete job\n"
                "`/scrape schedule pause` — pause all jobs\n"
                "`/scrape schedule resume` — resume all jobs\n"
            )
            return

        # ── SCRAPE / RESYNC from URL ──────────────────────────────────────────
        resync = sub == 'resync'
        if resync:
            url = parts[2] if len(parts) > 2 else ''
        else:
            url = parts[1] if len(parts) > 1 else ''

        if not url or not url.startswith('http'):
            self.send_message(chat_id,
                "*🌐 iVolt Web Scraper*\n\n"
                "*On-demand scraping:*\n"
                "`/scrape [url]` — scrape and add new items to catalogue\n"
                "`/scrape resync [url]` — re-scrape and update prices only\n\n"
                "*Schedule management:*\n"
                "`/scrape schedule add [url] [hours]` — auto-scrape every N hours\n"
                "`/scrape schedule list` — view all scheduled jobs\n"
                "`/scrape schedule remove [url]` — delete a job\n"
                "`/scrape schedule pause/resume` — toggle auto-scrape\n\n"
                "*Manage scraped items:*\n"
                "`/scrape list` — view scraped items in catalogue\n"
                "`/scrape remove [SKU]` — remove an item\n"
                "`/scrape status` — scraper engine info\n\n"
                "*Supported platforms:*\n"
                "  • WooCommerce (category & single product pages)\n"
                "  • Shopify (/collections/* and /products/*.json)\n"
                "  • Generic (schema.org Product + og: meta tags)\n\n"
                "*Examples:*\n"
                "`/scrape https://mercurydirect.com.ng/product-category/stabilizer/`\n"
                "`/scrape https://shop.solarstore.ng/collections/inverters`\n"
                "`/scrape https://myshop.myshopify.com/products.json`\n"
                "`/scrape resync https://mercurydirect.com.ng/solar/`"
            )
            return

        self.send_message(chat_id,
            f"⏳ *Scraping...*\n\n"
            f"URL: `{url[:80]}`\n"
            f"Mode: {'🔄 Resync (prices only)' if resync else '➕ Full scrape (new + update)'}\n"
            f"_This may take 10–30 seconds..._"
        )
        try:
            scraped = self._scrape_shop_url(url)
        except Exception as e:
            self.send_message(chat_id,
                f"*Scrape failed:* {str(e)[:200]}\n\n"
                f"Possible reasons:\n"
                f"• Site is down or unreachable\n"
                f"• URL is not a product or category page\n"
                f"• Site requires login or blocks bots\n\n"
                f"The bot needs outbound internet access to scrape URLs."
            )
            return

        if not scraped:
            self.send_message(chat_id,
                f"*No products found.*\n\n"
                f"URL: `{url[:80]}`\n\n"
                f"Supported: WooCommerce, Shopify, schema.org Product pages.\n"
                f"Make sure the URL is a product listing or product detail page."
            )
            return

        added, updated, skipped = self._merge_scraped_to_catalogue(scraped, url)

        # Build platform detection string
        platform = 'WooCommerce'
        if 'myshopify.com' in url or '/collections/' in url or '/products.json' in url:
            platform = 'Shopify'
        elif not any(x in url for x in ('woocommerce', 'wp-content', 'product-category')):
            platform = 'Generic'

        summary = (
            f"*Scrape Complete*\n\n"
            f"Source: `{url[:60]}`\n"
            f"🏭 Platform: *{platform}*\n"
            f"Products found: *{len(scraped)}*\n\n"
            f"  ➕ Added:   *{added}* new items\n"
            f"  🔄 Updated: *{updated}* items (price + photo)\n"
            f"  ⏭ Skipped: *{skipped}* (no price/name)\n\n"
        )
        if added:
            summary += "*New items added:*\n"
            for item in scraped[:6]:
                if item.get('price_ngn', 0):
                    wt = item.get('weight_kg', 20)
                    summary += f"  • {item['name'][:38]} — ₦{item['price_ngn']:,.0f} · {wt}kg\n"
            if len(scraped) > 6:
                summary += f"  _...and {len(scraped)-6} more_\n"
        if updated:
            summary += f"\n_Price history recorded for {updated} items._\n"
        summary += (
            f"\n_Use `/shop` to see the updated catalogue._\n"
            f"_Use `/scrape list` to manage scraped items._\n"
            f"_Use `/scrape schedule add {url[:40]}... 12` to auto-refresh._"
        )
        self.send_message(chat_id, summary)

    # ══════════════════════════════════════════════════════════════════════════
    # /notify — Subscribe to back-in-stock and price-drop alerts (free)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_notify(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /notify                          — show your active alerts
        /notify stock [SKU]              — alert when SKU is back in stock
        /notify price [SKU] [threshold]  — alert when price drops below ₦threshold
        /notify remove [SKU]             — remove all alerts for a SKU
        /notify clear                    — clear all your alerts
        """
        parts  = text.split()
        action = parts[1].lower() if len(parts) > 1 else 'list'
        data   = self._load_notify()
        uid    = str(user_id)

        all_items = {p['sku'].upper(): p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}

        # LIST
        if action == 'list' or len(parts) == 1:
            stock_alerts = [sku for sku, uids in data.get('stock', {}).items() if uid in uids]
            price_alerts = {sku: v for sku, v in data.get('price', {}).items()
                            if uid in [e['uid'] for e in v]}
            if not stock_alerts and not price_alerts:
                self.send_message(chat_id,
                    "🔔 *Your Alerts*\n\nNo active alerts.\n\n"
                    "*Add alerts:*\n"
                    "`/notify stock STAB-5KVA` — back-in-stock\n"
                    "`/notify price STAB-5KVA 160000` — price drop below ₦160,000"
                )
                return
            msg = "🔔 *Your Active Alerts*\n\n"
            if stock_alerts:
                msg += "*Back-in-stock:*\n"
                for sku in stock_alerts:
                    name = all_items.get(sku, {}).get('name', sku)
                    msg += f"  📦 `{sku}` — {name}\n"
            if price_alerts:
                msg += "\n*Price-drop:*\n"
                for sku, entries in price_alerts.items():
                    for e in entries:
                        if e['uid'] == uid:
                            name = all_items.get(sku, {}).get('name', sku)
                            msg += f"  💰 `{sku}` — {name} below ₦{e['threshold']:,.0f}\n"
            msg += "\n_`/notify remove [SKU]` to cancel an alert_"
            self.send_message(chat_id, msg)
            return

        # CLEAR ALL
        if action == 'clear':
            for sku in list(data.get('stock', {}).keys()):
                data['stock'][sku] = [u for u in data['stock'][sku] if u != uid]
            for sku in list(data.get('price', {}).keys()):
                data['price'][sku] = [e for e in data['price'][sku] if e['uid'] != uid]
            self._save_notify(data)
            self.send_message(chat_id, "✅ All your alerts cleared.")
            return

        # REMOVE ONE SKU
        if action == 'remove':
            sku = parts[2].upper() if len(parts) > 2 else ''
            if not sku:
                self.send_message(chat_id, "Usage: `/notify remove [SKU]`")
                return
            removed = False
            if sku in data.get('stock', {}):
                before = len(data['stock'][sku])
                data['stock'][sku] = [u for u in data['stock'][sku] if u != uid]
                if len(data['stock'][sku]) < before:
                    removed = True
            if sku in data.get('price', {}):
                before = len(data['price'][sku])
                data['price'][sku] = [e for e in data['price'][sku] if e['uid'] != uid]
                if len(data['price'][sku]) < before:
                    removed = True
            self._save_notify(data)
            self.send_message(chat_id,
                f"Alerts removed for `{sku}`." if removed
                else f"ℹ️ No alerts found for `{sku}`."
            )
            return

        # STOCK ALERT
        if action == 'stock':
            sku = parts[2].upper() if len(parts) > 2 else ''
            if not sku or sku not in all_items:
                sku_list = '\n'.join(f"  `{s}`" for s in all_items)
                self.send_message(chat_id,
                    f"Usage: `/notify stock [SKU]`\n\n*SKUs:*\n{sku_list}")
                return
            s_status = get_item_stock(sku, all_items[sku].get('stock_level', 'in_stock'))
            if s_status == 'in_stock':
                self.send_message(chat_id,
                    f"ℹ️ *{all_items[sku]['name']}* is already *In Stock*!\n\n"
                    f"Order now: `/invoice {sku} 1`")
                return
            data.setdefault('stock', {}).setdefault(sku, [])
            if uid not in data['stock'][sku]:
                data['stock'][sku].append(uid)
                self._save_notify(data)
                self.send_message(chat_id,
                    f"*Alert set!*\n\n"
                    f"You'll be notified when *{all_items[sku]['name']}* is back in stock.\n"
                    f"SKU: `{sku}`\n\n"
                    f"_`/notify remove {sku}` to cancel_"
                )
            else:
                self.send_message(chat_id,
                    f"ℹ️ You already have a back-in-stock alert for `{sku}`.")
            return

        # PRICE DROP ALERT
        if action == 'price':
            sku = parts[2].upper() if len(parts) > 2 else ''
            threshold_str = parts[3] if len(parts) > 3 else ''
            if not sku or sku not in all_items:
                self.send_message(chat_id,
                    "Usage: `/notify price [SKU] [threshold_ngn]`\n"
                    "Example: `/notify price STAB-5KVA 160000`\n\n"
                    "_You'll be notified when the retail price drops below your threshold._")
                return
            try:
                threshold = float(threshold_str.replace(',', '').replace('₦', ''))
                assert threshold > 0
            except Exception:
                self.send_message(chat_id,
                    "❌ Invalid threshold. Example: `/notify price STAB-5KVA 160000`")
                return

            data.setdefault('price', {}).setdefault(sku, [])
            # Remove existing alert for this user+sku, then add new one
            data['price'][sku] = [e for e in data['price'][sku] if e['uid'] != uid]
            data['price'][sku].append({
                'uid':       uid,
                'threshold': threshold,
                'set_at':    datetime.now(WAT).isoformat(),
            })
            self._save_notify(data)
            self.send_message(chat_id,
                f"*Price-drop alert set!*\n\n"
                f"*{all_items[sku]['name']}*\n"
                f"Alert when retail price drops below: *₦{threshold:,.0f}*\n"
                f"SKU: `{sku}`\n\n"
                f"_`/notify remove {sku}` to cancel_"
            )
            return

        self.send_message(chat_id,
            "❓ Unknown sub-command.\n\n"
            "Usage:\n"
            "`/notify` — list alerts\n"
            "`/notify stock [SKU]` — back-in-stock alert\n"
            "`/notify price [SKU] [₦threshold]` — price-drop alert\n"
            "`/notify remove [SKU]` — cancel\n"
            "`/notify clear` — cancel all"
        )

    # ══════════════════════════════════════════════════════════════════════════
    # /compare — Side-by-side shop item comparison (free)
    # ══════════════════════════════════════════════════════════════════════════
    def _cmd_compare(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /compare [SKU1] [SKU2]           — compare two shop items side by side
        /compare [SKU1] [SKU2] [state]   — also show delivery difference
        /compare list                    — show all SKUs to compare
        """
        parts  = text.split()
        action = parts[1].upper() if len(parts) > 1 else 'LIST'

        all_items = {p['sku']: p for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat}

        if action == 'LIST' or len(parts) < 3:
            sku_list = '\n'.join(
                f"  `{p['sku']}` — {p['name']}"
                for cat in NIGERIA_SHOP_CATALOGUE.values() for p in cat
            )
            self.send_message(chat_id,
                "*⚖️ Compare Shop Items*\n\n"
                "Usage: `/compare [SKU1] [SKU2]`\n"
                "       `/compare [SKU1] [SKU2] [state]` — include delivery\n\n"
                "Example:\n"
                "`/compare STAB-5KVA STAB-10KVA-1PH`\n"
                "`/compare STAB-10KVA-1PH STAB-10KVA-3PH Lagos`\n\n"
                f"*Available SKUs:*\n{sku_list}"
            )
            return

        sku1 = parts[1].upper()
        sku2 = parts[2].upper()
        state = ' '.join(parts[3:]).strip() if len(parts) > 3 else ''

        missing = [s for s in (sku1, sku2) if s not in all_items]
        if missing:
            self.send_message(chat_id,
                f"SKU(s) not found: {', '.join(f'`{s}`' for s in missing)}\n"
                f"Use `/compare list` to see all SKUs."
            )
            return

        item1, item2 = all_items[sku1], all_items[sku2]
        margin = get_shop_margin()
        ovr = {}
        try:
            path = os.path.join(DATA_DIR, 'shop_price_overrides.json')
            if os.path.exists(path):
                with open(path) as f:
                    ovr = json.load(f)
        except Exception:
            pass

        def _eff(item):
            base = float(ovr.get(item['sku'], {}).get('override_ngn', item['base_ngn']))
            return round(base * (1 + margin / 100))

        r1, r2 = _eff(item1), _eff(item2)
        s1 = stock_badge(sku1, item1.get('stock_level', 'in_stock'))
        s2 = stock_badge(sku2, item2.get('stock_level', 'in_stock'))

        def _row(label, v1, v2):
            return f"*{label}*\n  _{sku1}:_ {v1}\n  _{sku2}:_ {v2}\n"

        msg = (
            f"*Comparison*\n\n"
            f"*{item1['name']}*\nvs\n*{item2['name']}*\n\n"
            + _row("Specs",     item1['specs'],                     item2['specs'])
            + _row("Weight",    f"{item1.get('weight_kg','—')}kg",  f"{item2.get('weight_kg','—')}kg")
            + _row("Stock",     s1,                                  s2)
            + _row("Retail",    f"₦{r1:,.0f}",                      f"₦{r2:,.0f}")
        )

        price_diff = r2 - r1
        if price_diff != 0:
            msg += f"\n💰 *Price difference:* ₦{abs(price_diff):,.0f} ({'cheaper' if price_diff > 0 else 'more expensive'} for {sku1})\n"

        if state:
            w1 = float(item1.get('weight_kg', 20))
            w2 = float(item2.get('weight_kg', 20))
            try:
                comms = market_engine.fetch_commodity_prices()
                fx    = market_engine.fetch_exchange_rate('USD', 'NGN')
                fxr   = fx.get('rate', _FALLBACK_USDNGN) if fx else _FALLBACK_USDNGN
            except Exception:
                comms, fxr = {}, _FALLBACK_USDNGN
            l1 = get_logistics_fee(state, w1, _commodities=comms, _fx_rate=fxr)
            l2 = get_logistics_fee(state, w2, _commodities=comms, _fx_rate=fxr)
            if l1 and l2:
                msg += (
                    f"\n🚚 *Delivery to {l1['matched_state'].title()}*\n"
                    f"  {sku1}: ₦{l1['fee_ngn']:,.0f} ({l1['days']})\n"
                    f"  {sku2}: ₦{l2['fee_ngn']:,.0f} ({l2['days']})\n\n"
                    f"*Total delivered:*\n"
                    f"  {sku1}: ₦{r1 + l1['fee_ngn']:,.0f}\n"
                    f"  {sku2}: ₦{r2 + l2['fee_ngn']:,.0f}\n"
                )

        msg += (
            f"\n*Order:*\n"
            f"  `/invoice {sku1} 1` · `/invoice {sku2} 1`\n"
            f"  `/shop {sku1}` · `/shop {sku2}`"
        )
        self.send_message(chat_id, msg)

    def _cmd_taxedit(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """
        /taxedit — Admin: edit regional cost structure fields live.

        Usage:
          /taxedit                             — show all regions & current values
          /taxedit [region] [field] [value]    — update a field
          /taxedit [region] reset              — restore region to defaults
          /taxedit changes                     — list all active overrides

        Editable fields (value format):
          import_duty   — multiplier, e.g. 1.15 = 15% duty
          vat           — multiplier, e.g. 1.075 = 7.5% VAT
          logistics     — multiplier, e.g. 1.12 = 12%
          fx_risk       — multiplier, e.g. 1.08 = 8%
          local_content — multiplier, e.g. 0.95 = 5% discount  (< 1 = discount)
          inflation_adj — multiplier, e.g. 1.25 = 25%
          labor_rate_per_hour — integer, e.g. 2500 (₦/hr)
          workmanship_factor  — float, e.g. 1.0
        """
        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "⛔ Admin only.\nUse `/taxes` to view the current rates.")
            return

        parts = text.strip().split()

        # Editable fields with validation rules: (type, min, max, display_name)
        EDITABLE_FIELDS = {
            "insurance":           (float, 1.0, 1.05,  "Insurance multiplier (1.005=0.5%, 1.010=1.0% of CIF)"),
            "import_duty":         (float, 1.0, 2.0,   "Import Duty multiplier (1.0=0%, 1.15=15%)"),
            "vat":                 (float, 1.0, 1.30,  "VAT multiplier (1.0=0%, 1.075=7.5%)"),
            "logistics":           (float, 1.0, 1.50,  "Logistics markup (1.12=12%)"),
            "fx_risk":             (float, 1.0, 1.30,  "FX Risk buffer (1.08=8%)"),
            "local_content":       (float, 0.5, 1.50,  "Local content (0.95=5% disc, 1.10=10% premium)"),
            "inflation_adj":       (float, 1.0, 2.0,   "Inflation adjustment (1.25=25%)"),
            "labor_rate_per_hour": (float, 100, 50000, "Labour rate (₦/hr)"),
            "workmanship_factor":  (float, 0.1, 10.0,  "Workmanship factor multiplier"),
        }

        PERCENT_FIELDS = {"insurance", "import_duty", "vat", "logistics", "fx_risk", "local_content", "inflation_adj"}

        def pct_display(field, val):
            """Show a multiplier as a human-readable % string."""
            if field in PERCENT_FIELDS:
                if field == "local_content":
                    disc = (1 - val) * 100
                    return f"{val} ({'−'+f'{disc:.1f}%' if disc > 0 else '+'+f'{abs(disc):.1f}%'})"
                return f"{val} ({(val-1)*100:+.1f}%)"
            return str(val)

        regions = list(REGIONAL_MULTIPLIERS.keys())
        flag_map = {"Nigeria":"🇳🇬","UK":"🇬🇧","China":"🇨🇳","USA":"🇺🇸",
                    "Europe":"🇪🇺","India":"🇮🇳","UAE":"🇦🇪","Japan":"🇯🇵"}

        # ── LIST ALL CURRENT VALUES ──────────────────────────────────────
        if len(parts) == 1:
            current = get_regional_multipliers()
            overrides = _load_regional_overrides()
            r = "*⚙️ Regional Cost Structure Editor*\n"
            r += "_Admin only · Changes take effect immediately_\n\n"
            r += "*Usage:* `/taxedit [region] [field] [value]`\n\n"
            r += "*Regions:* " + " · ".join(f"`{rg.lower()}`" for rg in regions) + "\n\n"
            r += "*Editable fields:*\n"
            for field, (typ, mn, mx, desc) in EDITABLE_FIELDS.items():
                ov_mark = " 🔵" if any(field in ov for ov in overrides.values()) else ""
                r += f"`{field}`{ov_mark} — {desc}\n"
            r += "\n*Active overrides:* " + (f"{sum(len(v) for v in overrides.values())} field(s)" if overrides else "none")
            r += "\n\n_`/taxedit changes` to see all active overrides_"
            r += f"\n_`/taxedit [region] reset` to restore a region's defaults_"
            self.send_message(chat_id, r)
            return

        # ── SHOW ACTIVE OVERRIDES ────────────────────────────────────────
        if parts[1].lower() == "changes":
            overrides = _load_regional_overrides()
            if not overrides:
                self.send_message(chat_id, "✅ No active overrides. All regions using default values.\n_Use `/taxedit` to edit._")
                return
            r = "*🔵 Active Regional Rate Overrides*\n\n"
            for region, fields in overrides.items():
                flag = flag_map.get(region, "🌐")
                r += f"{flag} *{region}*\n"
                defaults = REGIONAL_MULTIPLIERS.get(region, {})
                for field, val in fields.items():
                    default_val = defaults.get(field, "?")
                    r += f"  `{field}`: {pct_display(field, val)} _(default: {pct_display(field, default_val) if isinstance(default_val, (int,float)) else default_val})_\n"
                r += "\n"
            r += "_`/taxedit [region] [field] [value]` to change · `/taxedit [region] reset` to restore_"
            self.send_message(chat_id, r)
            return

        # ── NEED AT LEAST: /taxedit [region] [field|reset] ───────────────
        if len(parts) < 3:
            self.send_message(chat_id,
                "Usage:\n"
                "`/taxedit [region] [field] [value]` — update a field\n"
                "`/taxedit [region] reset` — restore defaults\n"
                "`/taxedit changes` — list all active overrides\n\n"
                "Regions: " + ", ".join(f"`{r.lower()}`" for r in regions)
            )
            return

        # Match region
        region_input = parts[1].title()
        region_match = None
        for rname in regions:
            if rname.lower() == parts[1].lower() or rname.lower().startswith(parts[1].lower()):
                region_match = rname
                break

        if not region_match:
            self.send_message(chat_id,
                f"Unknown region `{parts[1]}`\n"
                f"Available: {', '.join(f'`{r.lower()}`' for r in regions)}"
            )
            return

        flag = flag_map.get(region_match, "🌐")

        # ── RESET REGION TO DEFAULTS ─────────────────────────────────────
        if parts[2].lower() == "reset":
            overrides = _load_regional_overrides()
            if region_match in overrides:
                removed_fields = list(overrides[region_match].keys())
                del overrides[region_match]
                _save_regional_overrides(overrides)
                admin_manager._log_action(user_id, "taxedit_reset", region_match,
                                          f"Cleared: {', '.join(removed_fields)}")
                self.send_message(chat_id,
                    f"{flag} *{region_match}* restored to defaults\n"
                    f"Cleared {len(removed_fields)} override(s): `{'`, `'.join(removed_fields)}`\n\n"
                    f"_All /price calculations now use default values for {region_match}._"
                )
            else:
                self.send_message(chat_id, f"ℹ️ {flag} *{region_match}* already using default values. Nothing to reset.")
            return

        # ── SHOW CURRENT VALUES FOR A REGION ─────────────────────────────
        if len(parts) == 2:
            current = get_regional_multipliers()[region_match]
            defaults = REGIONAL_MULTIPLIERS[region_match]
            overrides = _load_regional_overrides().get(region_match, {})

            r = f"{flag} *{region_match} — Current Cost Structure*\n\n"
            for field, (typ, mn, mx, desc) in EDITABLE_FIELDS.items():
                val = current.get(field, defaults.get(field, "?"))
                is_overridden = field in overrides
                mark = " 🔵" if is_overridden else ""
                r += f"`{field}`{mark}: *{pct_display(field, val) if isinstance(val,(int,float)) else val}*\n"
            r += f"\n_🔵 = admin override active_"
            r += f"\n_`/taxedit {region_match.lower()} [field] [value]` to edit_"
            r += f"\n_`/taxedit {region_match.lower()} reset` to restore defaults_"
            self.send_message(chat_id, r)
            return

        # ── UPDATE A FIELD ───────────────────────────────────────────────
        if len(parts) < 4:
            self.send_message(chat_id,
                f"Usage: `/taxedit {region_match.lower()} [field] [value]`\n\n"
                f"Fields: {', '.join(f'`{f}`' for f in EDITABLE_FIELDS)}"
            )
            return

        field = parts[2].lower()
        if field not in EDITABLE_FIELDS:
            close = [f for f in EDITABLE_FIELDS if f.startswith(field[:3])]
            hint  = f"\nDid you mean: {', '.join(f'`{f}`' for f in close)}" if close else ""
            self.send_message(chat_id,
                f"Unknown field `{field}`{hint}\n\n"
                f"Valid fields: {', '.join(f'`{f}`' for f in EDITABLE_FIELDS)}"
            )
            return

        typ, mn, mx, desc = EDITABLE_FIELDS[field]
        try:
            new_val = typ(parts[3])
        except ValueError:
            self.send_message(chat_id, f"Invalid value `{parts[3]}` — must be a number.")
            return

        if not (mn <= new_val <= mx):
            self.send_message(chat_id,
                f"Value out of range.\n"
                f"`{field}` must be between {mn} and {mx}\n"
                f"Got: {new_val}"
            )
            return

        # Persist the override
        overrides = _load_regional_overrides()
        old_val   = get_regional_multipliers()[region_match].get(field)
        if region_match not in overrides:
            overrides[region_match] = {}
        overrides[region_match][field] = new_val
        overrides[region_match]["_updated_by"] = str(user_id)
        overrides[region_match]["_updated_at"] = datetime.now(WAT).isoformat()
        _save_regional_overrides(overrides)

        # Log the action
        admin_manager._log_action(user_id, "taxedit", region_match,
                                  f"{field}: {old_val} → {new_val}")

        # Show impact (recompute total overhead before/after)
        def compute_overhead(m):
            return ((m.get('insurance', 1.005) * m['import_duty'] * m['vat'] * m['logistics'] *
                     m['fx_risk'] * m['local_content'] * m['inflation_adj']) - 1) * 100

        old_region = dict(get_regional_multipliers()[region_match])
        old_overhead = compute_overhead(old_region)
        new_region   = dict(old_region)
        new_region[field] = new_val
        new_overhead = compute_overhead(new_region)
        delta_overhead = new_overhead - old_overhead

        old_disp = pct_display(field, old_val) if isinstance(old_val, (int, float)) else str(old_val)
        new_disp = pct_display(field, new_val)
        arrow    = "▲" if new_overhead > old_overhead else "▼"

        self.send_message(chat_id,
            f"{flag} *{region_match}* updated\n\n"
            f"Field: `{field}`\n"
            f"Old: {old_disp}\n"
            f"New: *{new_disp}*\n\n"
            f"Total import overhead: {old_overhead:.1f}% → *{new_overhead:.1f}%* ({arrow}{abs(delta_overhead):.1f}%)\n\n"
            f"_Change is live immediately — /price and /project now use new rates._\n"
            f"_`/taxedit {region_match.lower()} reset` to restore defaults._\n"
            f"_`/taxes {region_match.lower()}` to view full structure._"
        )


    def _build_trade_catalogue(self) -> Dict:
        """
        Build a live-enriched trade catalogue from TRADE_ITEMS.
        Returns dict of slug → item dict with live price, quality, and source added.
        """
        catalogue = {}
        for slug, item in self.TRADE_ITEMS.items():
            entry = dict(item)
            try:
                price, quality, components = self._commodity_adjusted_price(slug)
                entry["live_price_usd"] = price
                entry["data_quality"]   = quality
                entry["price_source"]   = components.get("source", "unknown")
            except Exception:
                entry["live_price_usd"] = item.get("floor_price_usd", 0.0)
                entry["data_quality"]   = "floor_price"
                entry["price_source"]   = "floor"
            catalogue[slug] = entry
        return catalogue

    def _get_freight_rate(self, origin: str, destination: str) -> dict:
        """Return freight rate dict, with oil-price adjustment applied."""
        key = (origin.title(), destination.title())
        rate = dict(self.FREIGHT_RATE_TABLE.get(key, self._FREIGHT_DEFAULT))
        # Adjust freight for oil price: baseline is $80/barrel
        try:
            comms = market_engine.fetch_commodity_prices()
            oil_price = comms.get("OIL_BRENT", comms.get("OIL_WTI", {})).get("price", 80.0)
            oil_factor = oil_price / 80.0          # >1 = expensive oil → higher freight
            rate["sea"] = round(rate["sea"] * oil_factor, 3)
            rate["air"] = round(rate["air"] * oil_factor, 3)
            rate["oil_price"] = oil_price
        except Exception:
            rate["oil_price"] = 80.0
        return rate

    def _get_live_commodities(self) -> Dict[str, float]:
        """Fetch live commodity prices, returning a flat dict of name→price."""
        try:
            comms = market_engine.fetch_commodity_prices()
            return {
                "copper":    comms.get("COPPER",    {}).get("price", self._COMMODITY_BASELINES["copper"]),
                "steel":     comms.get("STEEL",     {}).get("price", self._COMMODITY_BASELINES["steel"]),
                "oil":       comms.get("OIL_BRENT", comms.get("OIL_WTI", {})).get("price", self._COMMODITY_BASELINES["oil"]),
                "aluminum":  comms.get("ALUMINUM",  {}).get("price", self._COMMODITY_BASELINES["aluminum"]),
                "lithium":   comms.get("LITHIUM",   {}).get("price", self._COMMODITY_BASELINES["lithium"]),
                "electronics": 1.0,
            }
        except Exception:
            return dict(self._COMMODITY_BASELINES)

    def _get_live_proxy_price(self, item_key: str) -> Tuple[float, str, str]:
        """
        Fetch the Yahoo Finance proxy price for an item.
        Returns (proxy_price_usd, data_quality, proxy_ticker).
        Falls back gracefully through cache → synthetic.
        """
        item = self.TRADE_ITEMS.get(item_key)
        if not item:
            return 0.0, "error", "N/A"

        ticker = item["yahoo_proxy"]
        scale  = item["proxy_scale"]

        try:
            data = market_engine.fetch_yahoo_finance(ticker)
            if data and data.get("price", 0) > 0:
                raw_price    = data["price"]
                proxy_price  = raw_price * scale
                data_quality = data.get("data_quality", "real-time")
                return round(proxy_price, 4), data_quality, ticker
        except Exception as e:
            logger.warning(f"Proxy fetch failed for {item_key} ({ticker}): {e}")

        # Fallback: use cached if available
        cache_key = f"trade_proxy:{item_key}"
        if cache_key in market_engine.cache:
            cached = market_engine.cache[cache_key]
            return cached.get("price", 0.0), "cached", ticker

        return 0.0, "unavailable", ticker

    def _load_trade_price_sheet(self) -> Dict:
        """Load admin price overrides from disk. Returns {} if none exist."""
        try:
            if os.path.exists(self.TRADE_PRICE_FILE):
                with open(self.TRADE_PRICE_FILE, "r", encoding="utf-8") as f:
                    return json.load(f)
        except Exception as e:
            logger.error(f"Trade price sheet load error: {e}")
        return {}

    def _save_trade_price_sheet(self, sheet: Dict):
        """Persist admin price overrides atomically."""
        tmp = self.TRADE_PRICE_FILE + ".tmp"
        try:
            with open(tmp, "w", encoding="utf-8") as f:
                json.dump(sheet, f, indent=2, default=str)
            os.replace(tmp, self.TRADE_PRICE_FILE)
        except Exception as e:
            logger.error(f"Trade price sheet save error: {e}")
            if os.path.exists(tmp):
                os.remove(tmp)

    def _build_trade_calc(self, direction: str, item_key: str,
                          origin: str, destination: str,
                          qty: float, mode: str = "sea") -> dict:
        """
        Core trade calculation engine.
        direction: 'import' | 'export'
        Returns a dict with full cost breakdown.
        """
        item        = self.TRADE_ITEMS.get(item_key)
        orig_prof   = self.COUNTRY_TRADE_PROFILE.get(origin.title(), self.COUNTRY_TRADE_PROFILE["China"])
        dest_prof   = self.COUNTRY_TRADE_PROFILE.get(destination.title(), self.COUNTRY_TRADE_PROFILE["Nigeria"])

        # ── Live unit price (fully dynamic) ─────────────────────────────
        unit_usd, price_quality, price_components = self._commodity_adjusted_price(item_key)
        cif_usd     = unit_usd * qty                          # cost of goods (USD)

        # Freight
        freight_rates = self._get_freight_rate(origin, destination)
        weight_kg     = item["weight_kg_per_unit"] * qty
        freight_usd   = weight_kg * freight_rates.get(mode, freight_rates["sea"])
        freight_usd   = max(freight_usd, 80.0)               # minimum $80

        # Insurance (0.5% of CIF)
        insurance_usd = cif_usd * 0.005

        # CIF total (Cost + Insurance + Freight)
        cif_total_usd = cif_usd + insurance_usd + freight_usd

        # Import duties & taxes applied at destination
        import_duty_usd  = cif_total_usd * dest_prof["import_duty"]
        levy_usd         = cif_total_usd * dest_prof.get("levy", 0)
        vat_base         = cif_total_usd + import_duty_usd
        vat_usd          = vat_base * dest_prof["vat"]

        # Export clearance at origin (flat)
        export_clearance_usd = orig_prof["export_clearance_usd"]

        # Port handling / miscellaneous (2.5% of CIF)
        port_handling_usd = cif_total_usd * 0.025

        # Total landed cost (USD)
        total_landed_usd = (cif_total_usd + import_duty_usd + levy_usd +
                            vat_usd + export_clearance_usd + port_handling_usd)

        # FX conversion to destination currency
        dest_currency  = dest_prof["currency"]
        dest_symbol    = dest_prof["symbol"]
        fx_ngn_per_usd = (_safe_rate(market_engine.fetch_exchange_rate("USD", "NGN"), {"USD_NGN": 1640}))

        if dest_currency == "NGN":
            fx_rate          = fx_ngn_per_usd
            total_landed_loc = total_landed_usd * fx_rate
            unit_landed_loc  = total_landed_loc / qty
        elif dest_currency == "USD":
            fx_rate          = 1.0
            total_landed_loc = total_landed_usd
            unit_landed_loc  = total_landed_usd / qty
        else:
            fx_rate          = self._resolve_fx(dest_currency) / fx_ngn_per_usd
            total_landed_loc = total_landed_usd * fx_rate
            unit_landed_loc  = total_landed_loc / qty

        # Profit margin suggestion (15–25% over landed cost)
        margin_15 = total_landed_usd * 1.15
        margin_25 = total_landed_usd * 1.25

        return {
            "direction":          direction,
            "slug":               item_key,
            "item_label":         item["label"],
            "item_key":           item_key,
            "hs_code":            item["hs_code"],
            "qty":                qty,
            "unit":               item["unit"],
            "origin":             origin,
            "destination":        destination,
            "mode":               mode,
            # USD breakdown
            "unit_usd":           unit_usd,
            "price_quality":      price_quality,
            "price_source":       price_components.get("source", "unknown"),
            "price_ticker":       price_components.get("ticker", "N/A"),
            "price_components":   price_components,
            "cif_goods_usd":      cif_usd,
            "freight_usd":        round(freight_usd, 2),
            "insurance_usd":      round(insurance_usd, 2),
            "cif_total_usd":      round(cif_total_usd, 2),
            "import_duty_usd":    round(import_duty_usd, 2),
            "levy_usd":           round(levy_usd, 2),
            "vat_usd":            round(vat_usd, 2),
            "export_clearance_usd": round(export_clearance_usd, 2),
            "port_handling_usd":  round(port_handling_usd, 2),
            "total_landed_usd":   round(total_landed_usd, 2),
            # Local currency
            "dest_currency":      dest_currency,
            "dest_symbol":        dest_symbol,
            "fx_rate":            round(fx_rate, 4),
            "fx_ngn_usd":         round(fx_ngn_per_usd, 2),
            "total_landed_loc":   round(total_landed_loc, 2),
            "unit_landed_loc":    round(unit_landed_loc, 2),
            # Margin targets
            "sell_at_15pct_usd":  round(margin_15, 2),
            "sell_at_25pct_usd":  round(margin_25, 2),
            # Logistics meta
            "weight_kg":          round(weight_kg, 1),
            "freight_rate_per_kg": freight_rates.get(mode, 2.5),
            "oil_price":          freight_rates.get("oil_price", 80.0),
            "transit_days":       freight_rates.get(f"days_{mode}", 30),
            "dest_duty_rate":     dest_prof["import_duty"],
            "dest_vat_rate":      dest_prof["vat"],
        }

    def _commodity_adjusted_price(self, item_key: str) -> Tuple[float, str, Dict]:
        """
        Fully dynamic item price engine.

        Priority order:
          1. Admin override in trade_prices.json  (always takes precedence)
          2. Live Yahoo Finance proxy price × commodity adjustment
          3. Commodity-only derivation (no proxy needed)
          4. Floor price from TRADE_ITEMS (absolute last resort)

        Returns (price_usd, data_quality, price_components_dict)
        """
        item = self.TRADE_ITEMS.get(item_key)
        if not item:
            return 0.0, "error", {}

        components = {
            "item_key": item_key,
            "ticker": item.get("yahoo_proxy", "N/A"),
            "proxy_scale": item.get("proxy_scale", 1.0),
        }

        # ── 1. Admin override ────────────────────────────────────────────
        sheet = self._load_trade_price_sheet()
        override = sheet.get(item_key, {})
        if override.get("override_usd") and override["override_usd"] > 0:
            price = float(override["override_usd"])
            components["source"]   = "admin_override"
            components["override"] = price
            components["set_by"]   = override.get("set_by", "admin")
            components["set_at"]   = override.get("set_at", "unknown")
            return price, "admin_override", components

        # ── 2. Live commodities ──────────────────────────────────────────
        live_comms = self._get_live_commodities()
        components["live_commodities"] = {k: round(v, 4) for k, v in live_comms.items()}

        # ── 3. Live Yahoo proxy price ────────────────────────────────────
        proxy_price, proxy_quality, ticker = self._get_live_proxy_price(item_key)
        components["proxy_raw"]     = proxy_price
        components["proxy_quality"] = proxy_quality

        if proxy_price > 0:
            # Apply commodity adjustment on top of proxy price
            # Each commodity factor shifts the proxy proportionally
            factors = item["commodity_factors"]
            adj = 0.0
            for commodity, weight in factors.items():
                live_val    = live_comms.get(commodity, 1.0)
                base_val    = self._COMMODITY_BASELINES.get(commodity, 1.0)
                ratio       = live_val / base_val if base_val > 0 else 1.0
                adj        += weight * ratio

            # Add fixed (electronics/labour) portion unchanged
            fixed_weight = max(0.0, 1.0 - sum(factors.values()))
            adj += fixed_weight

            raw_adjusted = proxy_price * adj
            components["commodity_adj_factor"] = round(adj, 5)
            components["source"] = f"yahoo_proxy:{ticker}"

        else:
            # ── 4. Commodity-only derivation (no proxy) ──────────────────
            # Build price purely from commodity inputs using base ratios
            factors  = item["commodity_factors"]
            base_est = 0.0
            for commodity, weight in factors.items():
                live_val = live_comms.get(commodity, 1.0)
                # Normalise to a $/unit estimate
                if commodity == "copper":
                    base_est += live_val * 2.20462 * item["weight_kg_per_unit"] * weight
                elif commodity == "steel":
                    base_est += (live_val / 1000) * item["weight_kg_per_unit"] * weight
                elif commodity == "oil":
                    base_est += live_val * 0.5 * weight
                elif commodity == "aluminum":
                    base_est += (live_val / 1000) * item["weight_kg_per_unit"] * weight
                else:
                    base_est += live_val * weight

            raw_adjusted = max(base_est, item.get("price_floor_usd", 10.0))
            components["source"] = "commodity_derived"
            proxy_quality = "commodity_derived"

        # ── Clamp to floor / ceiling ─────────────────────────────────────
        floor   = item.get("price_floor_usd", 1.0)
        ceiling = item.get("price_ceil_usd", 999999.0)
        final   = max(floor, min(ceiling, raw_adjusted))

        components["raw_before_clamp"] = round(raw_adjusted, 4)
        components["floor"]   = floor
        components["ceiling"] = ceiling
        components["final_usd"] = round(final, 4)

        return round(final, 2), proxy_quality, components

    def _resolve_fx(self, currency: str) -> float:
        """Return NGN per 1 unit of `currency` (or USD per 1 NGN if dest is not NGN)."""
        if currency == "NGN":
            return 1.0
        if currency == "USD":
            return (_safe_rate(market_engine.fetch_exchange_rate("USD", "NGN"), {"USD_NGN": 1640}))
        # For other currencies get via USD cross
        try:
            usd_ngn = (_safe_rate(market_engine.fetch_exchange_rate("USD", "NGN"), {"USD_NGN": 1640}))
            cur_usd = market_engine.fetch_exchange_rate(currency, "USD")
            # Some engines return cross directly; fall back to REGIONAL_MULTIPLIERS fallbacks
            rate = cur_usd.get("rate", None)
            if rate:
                return usd_ngn / rate  # approx
        except Exception:
            pass
        # Hard fallbacks
        fallbacks = {"GBP": 2050, "EUR": 1750, "CNY": 225, "INR": 18.5,
                     "AED": 422, "GHS": 105, "KES": 12}
        return fallbacks.get(currency, (_safe_rate(market_engine.fetch_exchange_rate("USD", "NGN"), {"USD_NGN": 1640})))

