            f'    &nbsp;&middot;&nbsp; Support: <a href="https://t.me/ivoltadmin" target="_blank">{SUPPORT_HANDLE}</a>',
            f'    &nbsp;&middot;&nbsp; Generated: {now}',
            '  </div>',
