    def _cmd_grouppromo(self, chat_id: int, user_id: int, text: str, is_private: bool):
        """/grouppromo — Send the next (or a specific) promo message to the group now.

        Usage:
          /grouppromo           — send next promo in rotation
          /grouppromo 3         — send promo #3 specifically (1-indexed)
          /grouppromo status    — show last promo sent & next scheduled time
          /grouppromo list      — list all promo previews
        """
        if not admin_manager.is_admin(user_id):
            self.send_message(chat_id, "⛔ Admin only.")
            return

        parts = text.strip().split()
        sub   = parts[1].lower() if len(parts) > 1 else ''

        if sub == 'status':
            state = db.load(GroupMarketingSystem._PROMO_STATE_KEY) or {}
            last_i    = state.get("last_index", -1)
            last_sent = state.get("last_sent", "Never")[:19] if state.get("last_sent") else "Never"
            next_i    = (last_i + 1) % len(_GROUP_PROMOS)
            try:
                if state.get("last_sent"):
                    last_dt = datetime.fromisoformat(state["last_sent"])
                    if last_dt.tzinfo is None:
                        last_dt = WAT.localize(last_dt)
                    next_dt = last_dt + timedelta(hours=PROMO_INTERVAL_HOURS)
                    next_due = next_dt.strftime("%Y-%m-%d %H:%M WAT")
                else:
                    next_due = "Now (no promo sent yet)"
            except Exception:
                next_due = "Unknown"
            self.send_message(chat_id,
                f"*📢 Group Promo Status*\n\n"
                f"Last sent: Promo #{last_i + 1} at `{last_sent}`\n"
                f"Next due: `{next_due}`\n"
                f"Interval: every *{PROMO_INTERVAL_HOURS}h* (set via `PROMO_INTERVAL_HOURS` env)\n"
                f"Total promos in rotation: *{len(_GROUP_PROMOS)}*\n"
                f"Next in rotation: Promo #{next_i + 1}\n\n"
                f"Use `/grouppromo` to send now, or `/grouppromo N` for a specific one."
            )
            return

        if sub == 'list':
            msg = f"*📢 Group Promo Library ({len(_GROUP_PROMOS)} promos)*\n\n"
            for i, p in enumerate(_GROUP_PROMOS):
                preview = p[:80].replace('\n', ' ').replace('*', '').replace('_', '')
                msg += f"*#{i + 1}:* {preview}…\n\n"
            msg += "_Use `/grouppromo N` to send a specific one._"
            self.send_message(chat_id, msg)
            return

        # Send specific or next promo
        index = -1
        if sub.isdigit():
            index = int(sub) - 1  # convert 1-indexed to 0-indexed
            if index < 0 or index >= len(_GROUP_PROMOS):
                self.send_message(chat_id,
                    f"❌ Invalid promo number. Choose 1–{len(_GROUP_PROMOS)}.")
                return

        result = self.group_marketing.send_promo_now(chat_id, index)
        self.send_message(chat_id, result)

