class GroupMarketingSystem:
    """
    Handles all automated group marketing for iVolt Power Solutions.

    Features:
      • Welcome every new member with a full bot showcase
      • Send rotating promotional messages to the group on a schedule
      • Tracks which promo was last sent to avoid repeating immediately
      • Only runs on Bot1 (the group bot) to avoid duplicate messages
    """

    _PROMO_STATE_KEY = "group_promo_state"

    def __init__(self, bot: "TelegramBot"):
        self.bot = bot

    # ── New member welcome ────────────────────────────────────────────────────
    def welcome_new_member(self, chat_id: int, user_id: int, first_name: str):
        """Send a personalised welcome + bot showcase to a new group member."""
        try:
            msg = _group_welcome_message(first_name)
            self.bot.send_message(chat_id, msg)
            # Also register this user so they receive future broadcasts
            try:
                all_users_reg = db.load('all_users') or {}
                all_users_reg[str(user_id)] = datetime.now(WAT).strftime("%Y-%m-%d")
                db.save('all_users', all_users_reg)
            except Exception:
                pass
            logger.info(f"[GroupMarketing] Welcomed new member {user_id} ({first_name}) in chat {chat_id}")
        except Exception as e:
            logger.error(f"[GroupMarketing] welcome_new_member error: {e}")

    # ── Periodic promo ────────────────────────────────────────────────────────
    def send_periodic_promo(self):
        """
        Send the next rotating promo message to the group.
        Called by BackgroundServices on a schedule (every PROMO_INTERVAL_HOURS hours).
        Only fires if Bot1 token is active (group bot).
        """
        try:
            # Load state — which promo index was sent last
            state = db.load(self._PROMO_STATE_KEY) or {}
            last_index    = state.get("last_index", -1)
            last_sent_str = state.get("last_sent", "")

            # Enforce interval — don't spam even if called more frequently
            if last_sent_str:
                try:
                    last_sent_dt = datetime.fromisoformat(last_sent_str)
                    if last_sent_dt.tzinfo is None:
                        last_sent_dt = WAT.localize(last_sent_dt)
                    elapsed_hours = (datetime.now(WAT) - last_sent_dt).total_seconds() / 3600
                    if elapsed_hours < PROMO_INTERVAL_HOURS:
                        return  # Too soon
                except Exception:
                    pass

            # Pick next promo (round-robin)
            next_index = (last_index + 1) % len(_GROUP_PROMOS)
            promo_msg  = _GROUP_PROMOS[next_index]

            result = self.bot.send_message(GROUP_ID, promo_msg)
            if result and result.get('ok'):
                db.save(self._PROMO_STATE_KEY, {
                    "last_index": next_index,
                    "last_sent":  datetime.now(WAT).isoformat(),
                })
                logger.info(f"[GroupMarketing] Sent promo #{next_index + 1}/{len(_GROUP_PROMOS)} to group {GROUP_ID}")
            else:
                logger.warning(f"[GroupMarketing] Promo send failed: {result}")
        except Exception as e:
            logger.error(f"[GroupMarketing] send_periodic_promo error: {e}")

    # ── Manual trigger (admin command) ───────────────────────────────────────
    def send_promo_now(self, chat_id: int, index: int = -1) -> str:
        """
        Admin can call /grouppromo to send the next (or a specific) promo immediately.
        Returns a status string.
        """
        if index < 0 or index >= len(_GROUP_PROMOS):
            state = db.load(self._PROMO_STATE_KEY) or {}
            last_index = state.get("last_index", -1)
            index = (last_index + 1) % len(_GROUP_PROMOS)

        promo_msg = _GROUP_PROMOS[index]
        result = self.bot.send_message(GROUP_ID, promo_msg)
        if result and result.get('ok'):
            db.save(self._PROMO_STATE_KEY, {
                "last_index": index,
                "last_sent":  datetime.now(WAT).isoformat(),
            })
            return f"✅ Promo #{index + 1}/{len(_GROUP_PROMOS)} sent to group."
        return f"❌ Failed to send promo. Check GROUP_ID and Bot1 token."


