# ══════════════════════════════════════════════════════════════════════════════
# TWILIO WHATSAPP BRIDGE
# ══════════════════════════════════════════════════════════════════════════════
# How it works:
#   • A Flask webhook receives inbound WhatsApp messages from Twilio.
#   • The bridge translates each message into a fake Telegram-style update
#     and feeds it straight into the bot's process_update() pipeline.
#   • All commands (/shop, /price, /invoice, /cart etc.) work identically
#     on WhatsApp — no duplication of logic.
#   • Outgoing replies are sent via Twilio's WhatsApp API instead of Telegram.
#
# Setup (3 steps):
#   1. pip install twilio flask
#   2. Set env vars:
#        TWILIO_ACCOUNT_SID   = ACxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx
#        TWILIO_AUTH_TOKEN    = your_auth_token
#        TWILIO_WHATSAPP_FROM = whatsapp:+14155238886  (sandbox)
#                               whatsapp:+234XXXXXXXXXX  (your approved number)
#   3. Run with ENABLE_WHATSAPP=1 (see main() below).
#      Expose port 5001 publicly (e.g. ngrok http 5001) and set your
#      Twilio sandbox webhook to: https://your-ngrok.io/whatsapp
#
# Note: Photo sends (product cards) fall back to a text link on WhatsApp
#       because Twilio MMS delivery varies by region.
# ══════════════════════════════════════════════════════════════════════════════

class TwilioWhatsAppBridge:
    """
    Wraps the iVolt Power Solutions bot so it answers WhatsApp messages via Twilio.
    Drop-in: reuses the same IVoltBot instance — no logic duplication.
    """

    def __init__(self, bot_instance: 'IVoltBot'):
        self.bot = bot_instance
        self._enabled = bool(TWILIO_ACCOUNT_SID and TWILIO_AUTH_TOKEN)
        if self._enabled:
            try:
                from twilio.rest import Client as TwilioClient
                self._client = TwilioClient(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
                logger.info("TwilioWhatsAppBridge: Twilio client initialised ✅")
            except ImportError:
                logger.error("TwilioWhatsAppBridge: 'twilio' package not installed. "
                             "Run: pip install twilio flask")
                self._enabled = False
                self._client  = None
        else:
            self._client = None
            logger.info("TwilioWhatsAppBridge: disabled (TWILIO_ACCOUNT_SID not set)")

    @property
    def enabled(self) -> bool:
        return self._enabled

    def send_whatsapp(self, to: str, body: str) -> bool:
        """Send a WhatsApp text message via Twilio."""
        if not self._client:
            return False
        try:
            # Strip Markdown formatting for WhatsApp (plain text)
            import re
            clean = re.sub(r'\*([^*]+)\*', r'\1', body)   # bold
            clean = re.sub(r'_([^_]+)_',   r'\1', clean)  # italic
            clean = re.sub(r'`([^`]+)`',   r'\1', clean)  # code
            clean = re.sub(r'\[([^\]]+)\]\([^)]+\)', r'\1', clean)  # links
            # Telegram ```code blocks``` → plain
            clean = re.sub(r'```[\s\S]*?```', lambda m:
                           m.group(0).replace('```', '').strip(), clean)

            self._client.messages.create(
                from_=TWILIO_WHATSAPP_FROM,
                to=to,
                body=clean[:1600]   # WhatsApp message limit
            )
            return True
        except Exception as e:
            logger.error(f"send_whatsapp error to {to}: {e}")
            return False

    def handle_inbound(self, form_data: dict) -> str:
        """
        Handle an inbound Twilio webhook POST.
        Returns TwiML <Response/> — all replies are sent via the Twilio API.

        WhatsApp limitations vs Telegram:
          • No inline keyboards — replaced with numbered text menus
          • Photo sending is best-effort (MMS unreliable in Nigeria)
          • No .txt file attachments — invoice text is sent inline
          • No callback_query events — users type commands instead

        Special WhatsApp shortcuts (no / needed):
          shop        → /shop  (full catalogue, text format)
          price       → /price
          cart        → /cart
          invoice     → /invoice (shows help)
          help        → /help
          status      → /status
          menu        → shows quick-start menu
          1-10        → shortcut for /invoice STAB-[SKU] 1  (if in browse mode)
        """
        try:
            wa_from = form_data.get('From', '')
            body    = form_data.get('Body', '').strip()
            media_url = form_data.get('MediaUrl0', '')

            if not wa_from or not body:
                return '<Response/>'

            phone   = wa_from.replace('whatsapp:', '').replace('+', '').replace(' ', '')
            user_id = int(phone) % (10 ** 15)
            chat_id = user_id

            body_lower = body.strip().lower()

            # ── WhatsApp text shortcuts ───────────────────────────────────
            WA_SHORTCUTS = {
                # Greetings / navigation
                'menu':         '/help',
                'help':         '/help',
                'hi':           '/start',
                'hello':        '/start',
                'start':        '/start',
                'status':       '/status',
                # Shop
                'shop':         '/shop',
                'catalogue':    '/shop',
                'catalog':      '/shop',
                'products':     '/shop',
                'items':        '/shop',
                'price':        '/price',
                'prices':       '/price',
                # Order flow
                'cart':         '/cart',
                'invoice':      '/invoice',
                'invoices':     '/invoice list',
                'track':        '/track',
                'orders':       '/track',
                'order':        '/track',
                # Discovery
                'search':       '/search',
                'compare':      '/compare',
                'related':      '/related',
                'similar':      '/related',
                'history':      '/pricehistory',
                'pricehistory': '/pricehistory',
                # Deals
                'flash':        '/flash',
                'sale':         '/flash',
                'sales':        '/flash',
                'deals':        '/flash',
                'bulk':         '/bulk',
                'discount':     '/bulk',
                # Alerts
                'notify':       '/notify',
                'alerts':       '/notify',
                'alert':        '/notify',
                # Delivery
                'zones':        '/shop zones',
                'delivery':     '/shop zones',
                'shipping':     '/shop zones',
                # Schematics (premium)
                'schematic':    '/schematic',
                'wiring':       '/schematic',
                'diagram':      '/schematic',
            }
            if body_lower in WA_SHORTCUTS:
                body = WA_SHORTCUTS[body_lower]
            elif not body.startswith('/'):
                body = '/' + body

            fake_update = {
                'update_id': int(time.time()),
                'message': {
                    'chat': {'id': chat_id, 'type': 'private'},
                    'from': {'id': user_id, 'first_name': phone},
                    'text': body,
                }
            }

            # ── Save originals ────────────────────────────────────────────
            original_send         = self.bot.send_message
            original_photo        = self.bot.send_photo
            original_doc          = self.bot.send_document
            original_photo_kb     = self.bot.send_photo_with_keyboard
            original_answer_cb    = self.bot.answer_callback
            original_edit_msg     = self.bot.edit_message
            bridge_ref            = self

            def _clean_md(text: str) -> str:
                """Strip Telegram Markdown for WhatsApp plain text."""
                import re as _re
                text = _re.sub(r'\*([^*]+)\*',   r'\1',  text)   # bold
                text = _re.sub(r'_([^_]+)_',      r'\1',  text)   # italic
                text = _re.sub(r'`([^`]+)`',       r'\1',  text)   # code
                text = _re.sub(r'\[([^\]]+)\]\([^)]+\)', r'\1 (link)', text)  # links
                text = _re.sub(r'```[\s\S]*?```',  lambda m:
                               m.group(0).replace('```', '').strip(), text)
                return text.strip()

            def wa_send_message(cid, text, **kwargs):
                clean = _clean_md(text)
                # Split into 1600-char chunks (WhatsApp limit)
                for i in range(0, len(clean), 1580):
                    bridge_ref.send_whatsapp(wa_from, clean[i:i+1580])
                return {'ok': True}

            def wa_send_photo(cid, photo_url, caption='', **kwargs):
                """Try to send photo via Twilio MMS; fall back to text + link."""
                if bridge_ref._client and caption:
                    try:
                        bridge_ref._client.messages.create(
                            from_=TWILIO_WHATSAPP_FROM,
                            to=wa_from,
                            body=_clean_md(caption)[:1600],
                            media_url=[photo_url]
                        )
                        return {'ok': True}
                    except Exception:
                        pass
                # Fallback: text + URL
                msg = _clean_md(caption) if caption else ''
                if photo_url:
                    msg += f'\n\nProduct photo: {photo_url}'
                bridge_ref.send_whatsapp(wa_from, msg[:1600])
                return {'ok': True}

            def wa_send_photo_with_keyboard(cid, photo_url, caption, keyboard, **kwargs):
                """Send photo + text menu instead of inline keyboard."""
                wa_send_photo(cid, photo_url, caption)
                # Build a text-based menu from the keyboard
                rows = keyboard.get('inline_keyboard', [])
                if rows:
                    menu = '\n\n*To order, type one of:*\n'
                    for row in rows:
                        for btn in row:
                            label = btn.get('text', '')
                            data  = btn.get('callback_data', '')
                            # Map common callbacks to WhatsApp commands
                            if data.startswith('cart_add|'):
                                parts = data.split('|')
                                sku   = parts[1] if len(parts) > 1 else ''
                                menu += f'  • To add to cart: /cart (then /invoice {sku} 1)\n'
                            elif data.startswith('invoice_now|'):
                                parts = data.split('|')
                                sku   = parts[1] if len(parts) > 1 else ''
                                menu += f'  • Invoice: /invoice {sku} 1\n'
                            elif data == 'cart_view':
                                menu += '  • View cart: /cart\n'
                            elif data.startswith('shop_browse|'):
                                idx = data.split('|')[1]
                                menu += f'  • Browse more: /shop\n'
                            elif data == 'cart_checkout':
                                menu += '  • Checkout: /cart checkout\n'
                    bridge_ref.send_whatsapp(wa_from, _clean_md(menu))
                return {'ok': True}

            def wa_send_document(cid, file_bytes, filename, caption='', **kwargs):
                """Send invoice as inline text on WhatsApp (no file attachment)."""
                try:
                    inv_text = file_bytes.decode('utf-8')
                    header   = f"📄 *{filename}*\n{_clean_md(caption)}\n\n"
                    full     = header + inv_text
                    # Send in chunks
                    for i in range(0, len(full), 1580):
                        bridge_ref.send_whatsapp(wa_from, full[i:i+1580])
                except Exception:
                    bridge_ref.send_whatsapp(wa_from,
                        f"📄 {filename}\n{_clean_md(caption)}\n\n"
                        "(Save this message as your invoice)")
                return {'ok': True}

            def wa_answer_callback(cq_id, text='', **kwargs):
                """No-op — WhatsApp has no callback queries."""
                return {'ok': True}

            def wa_edit_message(cid, message_id, text, **kwargs):
                """WhatsApp can't edit messages — send a new one instead."""
                wa_send_message(cid, text)
                return {'ok': True}

            # ── Patch ─────────────────────────────────────────────────────
            self.bot.send_message            = wa_send_message
            self.bot.send_photo              = wa_send_photo
            self.bot.send_document           = wa_send_document
            self.bot.send_photo_with_keyboard = wa_send_photo_with_keyboard
            self.bot.answer_callback         = wa_answer_callback
            self.bot.edit_message            = wa_edit_message

            try:
                self.bot.process_update(fake_update)
            finally:
                # Always restore — even if bot raises
                self.bot.send_message             = original_send
                self.bot.send_photo               = original_photo
                self.bot.send_document            = original_doc
                self.bot.send_photo_with_keyboard = original_photo_kb
                self.bot.answer_callback          = original_answer_cb
                self.bot.edit_message             = original_edit_msg

        except Exception as e:
            logger.error(f"TwilioWhatsAppBridge.handle_inbound error: {e}", exc_info=True)

        return '<Response/>'


def run_whatsapp_webhook(bridge: TwilioWhatsAppBridge, port: int = 5001):
    """Run the Flask webhook server for Twilio in a background thread."""
    try:
        from flask import Flask, request as flask_request
    except ImportError:
        logger.error("Flask not installed. Run: pip install flask")
        return

    app = Flask(__name__)

    # ── Request rate limiter (simple in-memory) ───────────────────────────
    _req_counts: dict = {}   # {ip: [timestamp, ...]}
    _RATE_LIMIT = 30         # max requests per minute per IP

    def _rate_limited(ip: str) -> bool:
        now = time.time()
        window = _req_counts.setdefault(ip, [])
        # Drop requests older than 60s
        _req_counts[ip] = [t for t in window if now - t < 60]
        if len(_req_counts[ip]) >= _RATE_LIMIT:
            return True
        _req_counts[ip].append(now)
        return False

    @app.route('/whatsapp', methods=['POST'])
    def whatsapp_webhook():
        # ── IP rate limiting ──────────────────────────────────────────────
        client_ip = flask_request.headers.get('X-Forwarded-For',
                    flask_request.remote_addr or 'unknown').split(',')[0].strip()
        if _rate_limited(client_ip):
            logger.warning(f"WhatsApp webhook rate limit hit from {client_ip}")
            return '<Response/>', 429, {'Content-Type': 'text/xml'}

        # ── Twilio signature verification ─────────────────────────────────
        # Verifies the request genuinely came from Twilio, not an attacker.
        # Only active when TWILIO_AUTH_TOKEN is set.
        if TWILIO_AUTH_TOKEN:
            try:
                from twilio.request_validator import RequestValidator as _TwilioValidator
                validator  = _TwilioValidator(TWILIO_AUTH_TOKEN)
                sig        = flask_request.headers.get('X-Twilio-Signature', '')
                url        = flask_request.url
                post_data  = flask_request.form.to_dict()
                if not validator.validate(url, post_data, sig):
                    logger.warning(f"WhatsApp webhook: invalid Twilio signature from {client_ip}")
                    return '<Response/>', 403, {'Content-Type': 'text/xml'}
            except ImportError:
                pass  # twilio package not installed — skip verification
            except Exception as e:
                logger.error(f"Twilio signature check error: {e}")
                # Fail open if verification itself errors — log and continue
                pass

        # ── Process message ───────────────────────────────────────────────
        twiml = bridge.handle_inbound(flask_request.form)
        return twiml, 200, {'Content-Type': 'text/xml'}

    @app.route('/health', methods=['GET'])
    def health():
        return {'status': 'ok', 'whatsapp': bridge.enabled}, 200

    logger.info(f"WhatsApp webhook listening on port {port} — "
                f"set Twilio webhook to https://YOUR_DOMAIN:{port}/whatsapp")
    app.run(host='0.0.0.0', port=port, threaded=True)


def run_all_bots():
    """
    Launch all 4 bots simultaneously in separate threads.
    Each thread runs its own polling loop with its own token and mode.

    Usage:
        BOT_ALL=1 python iVolt.py
    Or call run_all_bots() directly from a deployment script.

    Bot assignment:
        Bot1 (8092657356) — Shop & Group  → BOT_MODE=bot1
        Bot2 (7994232925) — Market/Premium → BOT_MODE=bot2
        Bot3 (8761946412) — Installer      → BOT_MODE=bot3
        Bot4 (8638549552) — Super Admin    → BOT_MODE=bot4
    """
    import threading as _threading

    logger.info("Starting iVolt Power Solutions — All Bots Mode")

    services = BackgroundServices()
    services.start()

    bot_configs = [
        ('bot1', BOT1_TOKEN, 'Shop & Group'),
        ('bot2', BOT2_TOKEN, 'Market Data & Premium'),
        ('bot3', BOT3_TOKEN, 'Installer & Safety Marketplace'),
        ('bot4', BOT4_TOKEN, 'Super Admin'),
        ('bot5', BOT5_TOKEN, 'Used Items Marketplace'),
    ]

    threads = []
    for mode, token, label in bot_configs:
        def _run_bot(m=mode, t=token, lbl=label):
            # Pass mode explicitly — do NOT mutate globals() here.
            # Mutating _BOT_MODE in a thread caused race conditions where bots
            # read each other's mode during TelegramBot.__init__.
            try:
                logger.info(f"[{m.upper()}] Starting {lbl}...")
                b = TelegramBot(t, bot_mode=m)
                b.run()
            except Exception as e:
                logger.error(f"[{m.upper()}] Fatal error: {e}", exc_info=True)

        th = _threading.Thread(target=_run_bot, name=f"iVolt-{mode}", daemon=True)
        threads.append(th)
        th.start()
        logger.info(f"[{mode.upper()}] Thread started — {label}")
        time.sleep(1)  # stagger startup to avoid rate limits

    try:
        # Keep main thread alive
        while all(t.is_alive() for t in threads):
            time.sleep(10)
    except KeyboardInterrupt:
        logger.info("All bots shutting down...")
    finally:
        services.stop()


if __name__ == "__main__":
    if os.getenv("BOT_ALL"):
        run_all_bots()
    else:
        main()


def main_with_whatsapp():
    """
    Alternative entry point that runs both Telegram polling AND
    the Twilio WhatsApp webhook simultaneously.

    Usage:
        ENABLE_WHATSAPP=1 python iVolt.py

    Or call this function directly from your deployment script.
    """
    import os as _os
    if not _os.getenv("ENABLE_WHATSAPP"):
        # Fall back to Telegram-only mode
        main()
        return

    logger.info("Starting iVolt in Telegram + WhatsApp dual mode...")

    # Create the bot
    bot_instance = IVoltBot(TOKEN)
    bridge       = TwilioWhatsAppBridge(bot_instance)

    # Start WhatsApp webhook in background thread
    wa_thread = threading.Thread(
        target=run_whatsapp_webhook,
        args=(bridge, 5001),
        daemon=True,
        name="WhatsAppWebhook"
    )
    wa_thread.start()
    logger.info("WhatsApp webhook thread started on port 5001")

    # Run Telegram bot in the main thread
    try:
        bot_instance.run()
    except KeyboardInterrupt:
        print("\nShutting down dual-mode bot...")
